INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('A_Nurse%27s_Calling', 'killer', 'A Nurse''s Calling', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fe/IconPerks_aNursesCalling.png/revision/latest?cb=20160820090103', 'Unlocks potential in your Aura-reading ability.
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of Survivors who are healing or being healed are revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">24</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">28</span></b> <b>metres</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Still attached to the fragments of her past life, she is drawn to those in need of help."</span></i>
</p>
', 'Unlocks potential in your Aura-reading ability.
The Auras of Survivors who are healing or being healed are revealed to you within 20 / 24 / 28 metres.
"Still attached to the fragments of her past life, she is drawn to those in need of help."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Agitation', 'killer', 'Agitation', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ac/IconPerks_agitation.png/revision/latest?cb=20160605204807', 'You get excited in anticipation of hooking your prey.
<p>When carrying a Survivor, you benefit from the following effects:
</p><ul><li><b>Increases</b> your Movement speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">18</span></b> <b>%</b>.</li>
<li><b>Increases</b> your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">+12 metres</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"At some point, the excitement of hooking one of us becomes more important than the desire to kill us."</span></i>
', 'You get excited in anticipation of hooking your prey.
When carrying a Survivor, you benefit from the following effects:
Increases your Movement speed by 6 / 12 / 18 %.
Increases your Terror Radius by +12 metres .

"At some point, the excitement of hooking one of us becomes more important than the desire to kill us."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Alien_Instinct', 'killer', 'Alien Instinct', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/34/IconPerks_alienInstinct.png/revision/latest?cb=20230808160213', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.2.0</div><div class="dynamicContent ptb">You are so stealthy, sometimes it seems like you appear out of nowhere.
<p>Whenever you hook a Survivor, <i>Alien Instinct</i> activates:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the farthest injured Survivor is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">5 seconds</span></b>.</li>
<li>That Survivor suffers from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" class="mw-redirect" title="Oblivious">Oblivious</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/64?cb=20190903170245"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/96?cb=20190903170245"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/32?cb=20190903170245"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">16</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">18</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Yellow light''s for my eyes only." — Dallas</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.2.0 You are so stealthy, sometimes it seems like you appear out of nowhere.
Whenever you hook a Survivor, Alien Instinct activates:
The Aura of the farthest injured Survivor is revealed to you for 5 seconds .
That Survivor suffers from the Oblivious Status Effect for 16 / 18 / 20 seconds.

"Yellow light''s for my eyes only." — Dallas', 'Xenomorph');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('All-Shaking_Thunder', 'killer', 'All-Shaking Thunder', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6a/IconPerks_allShakingThunder.png/revision/latest?cb=20241107202158', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">Enemies on land and sea learned to tremble before your might.
<p>After falling from a height, <i>All-Shaking Thunder</i> activates for <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>seconds</b>:
</p><ul><li><b>Increases</b> the range of your <i><a href="https://deadbydaylight.fandom.com/wiki/Lunge_Attack" class="mw-redirect" title="Lunge Attack">Lunge Attack</a></i> by <b><span class="luaClr clr clr8" style="color: #d41c1c;">+75&nbsp;%</span></b>.</li></ul>

<i>All-Shaking Thunder</i> has a cool-down of <b><span class="luaClr clr clr4" style="color: #ac3ee3;">5 seconds</span></b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Go on. Run. Tell your friends I''m coming for them." — Portia Maye</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 Enemies on land and sea learned to tremble before your might.
After falling from a height, All-Shaking Thunder activates for 8 / 12 / 16 seconds :
Increases the range of your Lunge Attack by +75 % .

All-Shaking Thunder has a cool-down of 5 seconds .
"Go on. Run. Tell your friends I''m coming for them." — Portia Maye', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Awakened_Awareness', 'killer', 'Awakened Awareness', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/97/IconPerks_awakenedAwareness.png/revision/latest?cb=20220815051648', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.2.0</div><div class="dynamicContent ptb">Your genes have been altered to heighten your senses in intense situations.While carrying a Survivor, you benefit from the following effect:
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">16</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">18</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>metres</b> of your location are revealed to you.</li></ul>
</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.2.0 Your genes have been altered to heighten your senses in intense situations.While carrying a Survivor, you benefit from the following effect:
The Auras of all Survivors within 16 / 18 / 20 metres of your location are revealed to you.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Bamboozle', 'killer', 'Bamboozle', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconPerks_bamboozle.png/revision/latest?cb=20180529205216', 'After vaulting a <a href="https://deadbydaylight.fandom.com/wiki/Window" class="mw-redirect" title="Window">Window</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="57" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/64?cb=20170921093258"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="85" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/96?cb=20170921093258"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="28" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/32?cb=20170921093258"></a></span></span></span>, <i>Bamboozle</i> calls upon The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> to block that Window for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>seconds</b>.
<ul><li>Blocked Windows cannot be vaulted by Survivors.</li>
<li><b>Increases</b> your general Vaulting speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">10</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">15</span></b> <b>%</b>.</li></ul>
<p><i>Bamboozle</i> only blocks one Window at a time and does not apply either of its effects to vaulting <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallets</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span>.
</p>', 'After vaulting a Window , Bamboozle calls upon The Entity to block that Window for the next 8 / 12 / 16 seconds.
Blocked Windows cannot be vaulted by Survivors.
Increases your general Vaulting speed by 5 / 10 / 15 %.
Bamboozle only blocks one Window at a time and does not apply either of its effects to vaulting Pallets .', 'Jeffrey_Hawk');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Barbecue_%26_Chilli', 'killer', 'Barbecue & Chilli', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/51/IconPerks_barbecueAndChilli.png/revision/latest?cb=20170914173637', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">A deep bond with The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> unlocks potential in one''s Aura-reading ability.
<ul><li>After hooking a Survivor, all Survivors who are at least <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>metres</b> away from that Hook have their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">5 seconds</span></b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I just can''t take no pleasure in killing. There''s just some things you gotta do. Don''t mean you have to like it." — Drayton Sawyer</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 A deep bond with The Entity unlocks potential in one''s Aura-reading ability.
After hooking a Survivor, all Survivors who are at least 60 / 50 / 40 metres away from that Hook have their Aura revealed to you for 5 seconds .
"I just can''t take no pleasure in killing. There''s just some things you gotta do. Don''t mean you have to like it." — Drayton Sawyer', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Batteries_Included', 'killer', 'Batteries Included', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_batteriesIncluded.png/revision/latest?cb=20231108172942', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.4.2</div><div class="dynamicContent ptb">Being somewhere between man and machine has its upsides.
<p>Whenever you are within <b><span class="luaClr clr clr2" style="color: #e8c252;">12 metres</span></b> of a completed <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span>, you are granted a <b><span class="luaClr clr clr6" style="color: #ff8800;">+5&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b>.
</p><ul><li>This effect lingers for <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>second(s)</b> after leaving the Generator''s range.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Surprise! Did you miss me, Andy?" — Chucky</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.4.2 Being somewhere between man and machine has its upsides.
Whenever you are within 12 metres of a completed Generator , you are granted a +5 % Haste Status Effect.
This effect lingers for 1 / 3 / 5 second(s) after leaving the Generator''s range.

"Surprise! Did you miss me, Andy?" — Chucky', 'Charles_Lee_Ray');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Beast_of_Prey', 'killer', 'Beast of Prey', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/77/IconPerks_beastOfPrey.png/revision/latest?cb=20170727160820', 'Your lust for a kill is so intense that your connection with The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> is momentarily lost, making you totally unpredictable.<br>
<p>Upon gaining the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Bloodlust" class="mw-redirect" title="Bloodlust">Bloodlust</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodlust" title="Bloodlust"><img alt="IconHelp bloodlust" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp bloodlust.png" data-image-key="IconHelp_bloodlust.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e8/IconHelp_bloodlust.png/revision/latest/scale-to-width-down/64?cb=20170907143915"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodlust" title="Bloodlust"><img alt="IconHelp bloodlust" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp bloodlust.png" data-image-key="IconHelp_bloodlust.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e8/IconHelp_bloodlust.png/revision/latest/scale-to-width-down/96?cb=20170907143915"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodlust" title="Bloodlust"><img alt="IconHelp bloodlust" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp bloodlust.png" data-image-key="IconHelp_bloodlust.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e8/IconHelp_bloodlust.png/revision/latest/scale-to-width-down/32?cb=20170907143915"></a></span></span></span></b></i> <b>Status Effect</b>, <i>Beast of Prey</i> activates:
</p>
<ul><li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" class="mw-redirect" title="Undetectable">Undetectable</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/64?cb=20190903170250"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/96?cb=20190903170250"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/32?cb=20190903170250"></a></span></span></span></b></i> <b>Status Effect</b> for as long as <i><b>Bloodlust</b></i> is active.</li></ul>
<p><i>Beast of Prey</i> grants <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b> bonus <a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints">Bloodpoints</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="58" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/64?cb=20180702212847"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="87" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/96?cb=20180702212847"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="29" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/32?cb=20180702212847"></a></span></span></span> for actions in the <a href="https://deadbydaylight.fandom.com/wiki/Hunter" class="mw-redirect" title="Hunter">Hunter</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hunter" title="Hunter"><img alt="DailyRitualIcon hunter" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="DailyRitualIcon hunter.png" data-image-key="DailyRitualIcon_hunter.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a4/DailyRitualIcon_hunter.png/revision/latest/scale-to-width-down/64?cb=20160607183456"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hunter" title="Hunter"><img alt="DailyRitualIcon hunter" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="DailyRitualIcon hunter.png" data-image-key="DailyRitualIcon_hunter.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a4/DailyRitualIcon_hunter.png/revision/latest/scale-to-width-down/96?cb=20160607183456"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hunter" title="Hunter"><img alt="DailyRitualIcon hunter" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="DailyRitualIcon hunter.png" data-image-key="DailyRitualIcon_hunter.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a4/DailyRitualIcon_hunter.png/revision/latest/scale-to-width-down/32?cb=20160607183456"></a></span></span></span> Category.<br>
<i>The bonus Bloodpoints are only awarded during the Trial.</i><br>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Where did she go?"</span></i>
</p>', 'Your lust for a kill is so intense that your connection with The Entity is momentarily lost, making you totally unpredictable.
Upon gaining the Bloodlust Status Effect, Beast of Prey activates:

Grants the Undetectable Status Effect for as long as Bloodlust is active.
Beast of Prey grants 30 / 40 / 50 % bonus Bloodpoints for actions in the Hunter Category.
The bonus Bloodpoints are only awarded during the Trial.
"Where did she go?"', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Bitter_Murmur', 'killer', 'Bitter Murmur', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconPerks_bitterMurmur.png/revision/latest?cb=20160605204819', 'Unlocks potential in your Aura-reading ability:
<ul><li>Each time a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span>is completed, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">16 metres</span></b> of that Generator are revealed to you for <b><span class="luaClr clr clr6" style="color: #ff8800;">5 seconds</span></b>.</li>
<li>Once the last Generator is completed, the Auras of all Survivors are revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">7</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li></ul>
<p><br>
</p>
', 'Unlocks potential in your Aura-reading ability:
Each time a Generator is completed, the Auras of all Survivors within 16 metres of that Generator are revealed to you for 5 seconds .
Once the last Generator is completed, the Auras of all Survivors are revealed to you for 5 / 7 / 10 seconds.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Blood_Echo', 'killer', 'Blood Echo', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconPerks_bloodEcho.png/revision/latest?cb=20191126213547', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">The agony of one is inflicted onto others.
<ul><li>Whenever you hook a Survivor, all other injured Survivors suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> and <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haemorrhage" class="mw-redirect" title="Haemorrhage">Haemorrhage</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haemorrhage" title="Haemorrhage"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haemorrhage" title="Haemorrhage"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haemorrhage" title="Haemorrhage"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span></b></i> <b>Status Effects</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Attack an enemy with precision and their allies will feel it." — Renjiro''s Doctrine 6:3</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 The agony of one is inflicted onto others.
Whenever you hook a Survivor, all other injured Survivors suffer from the Exhausted and Haemorrhage Status Effects for 20 / 25 / 30 seconds.
"Attack an enemy with precision and their allies will feel it." — Renjiro''s Doctrine 6:3', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Blood_Warden', 'killer', 'Blood Warden', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/eb/IconPerks_bloodWarden.png/revision/latest?cb=20171026225711', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 1.8.0</div><div class="dynamicContent ptb">As soon as one <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gate</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> is opened, <i>Blood Warden</i> activates.
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivors</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> standing within the Exit-Gate area are revealed to you.</li></ul>
<p>Once per Trial, hooking a Survivor while <i>Blood Warden</i> is active calls upon The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> to block the exits for all Survivors for <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.<br>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"This is my world. And you can''t ever leave." — Freddy Krueger</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 1.8.0 As soon as one Exit Gate is opened, Blood Warden activates.
The Auras of Survivors standing within the Exit-Gate area are revealed to you.
Once per Trial, hooking a Survivor while Blood Warden is active calls upon The Entity to block the exits for all Survivors for 40 / 50 / 60 seconds.
"This is my world. And you can''t ever leave." — Freddy Krueger', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Bloodhound', 'killer', 'Bloodhound', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconPerks_bloodhound.png/revision/latest?cb=20160605204825', 'Like a hunting scent hound, you smell traces of blood at a great distance.
<ul><li><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood">Pools of Blood</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span> are shown in <b><span class="luaClr clr clr19" style="color: #ff0000;">bright red</span></b> and can be tracked for <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>seconds</b> longer than normal.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Pebbles shimmering in the moonlight; my life drips down in a trail so easy to follow."</span></i>
</p>', 'Like a hunting scent hound, you smell traces of blood at a great distance.
Pools of Blood are shown in bright red and can be tracked for 2 / 3 / 4 seconds longer than normal.
"Pebbles shimmering in the moonlight; my life drips down in a trail so easy to follow."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Brutal_Strength', 'killer', 'Brutal Strength', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3d/IconPerks_brutalStrength.png/revision/latest?cb=20160605204842', 'Your great strength allows you to shred through your prey''s defences.
<ul><li><b>Increases</b> the Action speeds for breaking <a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" class="mw-redirect" title="Breakable Wall">Breakable Walls</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/64?cb=20220910215339"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/96?cb=20220910215339"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/32?cb=20220910215339"></a></span></span></span> and dropped <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallets</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span>, and damaging <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">15</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>%</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"It is more than muscles. A dark power motivates the beast."</span></i>
</p>
', 'Your great strength allows you to shred through your prey''s defences.
Increases the Action speeds for breaking Breakable Walls and dropped Pallets , and damaging Generators by 10 / 15 / 20 %.
"It is more than muscles. A dark power motivates the beast."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Call_of_Brine', 'killer', 'Call of Brine', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3b/IconPerks_callOfBrine.png/revision/latest?cb=20220216115938', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.7.0</div><div class="dynamicContent ptb">Your psychic abilities influence technology in devastating ways.<br>
<p>After performing the <i>Damage Generator</i> action on a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span>, <i>Call of Brine</i> activates for <b><span class="luaClr clr clr2" style="color: #e8c252;">60 seconds</span></b>.
</p>
<ul><li>The damaged Generator regresses at <b><span class="luaClr clr clr2" style="color: #e8c252;">115</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">120</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">125</span></b> <b>%</b> of the normal Regression speed and its <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is highlighted to you in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.</li>
<li>Receive a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> each time a Survivor hits a <a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" class="mw-redirect" title="Good Skill Check">Good Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" title="Good Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" title="Good Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" title="Good Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> on the affected Generator.</li></ul>
</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.7.0 Your psychic abilities influence technology in devastating ways.
After performing the Damage Generator action on a Generator , Call of Brine activates for 60 seconds .

The damaged Generator regresses at 115 / 120 / 125 % of the normal Regression speed and its Aura is highlighted to you in yellow .
Receive a Loud Noise Notification each time a Survivor hits a Good Skill Check on the affected Generator.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Corrupt_Intervention', 'killer', 'Corrupt Intervention', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/10/IconPerks_corruptIntervention.png/revision/latest?cb=20190306195826', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">Your prayers invoke a dark power that meddles with the Survivors'' chances of survival.
<ul><li>At the start of the Trial, the <b><span class="luaClr clr clr2" style="color: #e8c252;">3 Generators</span></b> located farthest from you are blocked by The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">80</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">100</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">120</span></b> <b>seconds</b>.</li></ul>
<p><i>Corrupt Intervention</i> deactivates prematurely once the first Survivor is put into the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"It shall be known across the land that the Gods curse the unfaithful." — (The Tablet of Adiris, 3.7)</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 Your prayers invoke a dark power that meddles with the Survivors'' chances of survival.
At the start of the Trial, the 3 Generators located farthest from you are blocked by The Entity for 80 / 100 / 120 seconds.
Corrupt Intervention deactivates prematurely once the first Survivor is put into the Dying State .
"It shall be known across the land that the Gods curse the unfaithful." — (The Tablet of Adiris, 3.7)', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Coulrophobia', 'killer', 'Coulrophobia', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/45/IconPerks_coulrophobia.png/revision/latest?cb=20180529205206', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">Even those without a fear of clowns know to be terrified of you.
<p>For all Survivors within your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span>, the following effects apply:
</p><ul><li><b>Reduces</b> their Healing speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b>.</li>
<li><b>Increases</b> the Rotation speed of Healing <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">+50&nbsp;%</span></b>.</li></ul></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 Even those without a fear of clowns know to be terrified of you.
For all Survivors within your Terror Radius , the following effects apply:
Reduces their Healing speed by 30 / 40 / 50 %.
Increases the Rotation speed of Healing Skill Checks by +50 % .', 'Jeffrey_Hawk');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Coup_de_Gr%C3%A2ce', 'killer', 'Coup de Grâce', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/bd/IconPerks_coupDeGr%C3%A2ce.png/revision/latest?cb=20201112095015', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">As the end nears, you go in for the kill.
<p>Whenever a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> is completed, <i>Coup de Grâce</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">+2 Tokens</span></b>, up to a maximum of <b><span class="luaClr clr clr6" style="color: #ff8800;">10 Tokens</span></b> per Trial:
</p><ul><li><b>Increases</b> the range of your next <i><a href="https://deadbydaylight.fandom.com/wiki/Lunge_Attack" class="mw-redirect" title="Lunge Attack">Lunge Attack</a></i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">70</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">75</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">80</span></b> <b>%</b>, while consuming <b><span class="luaClr clr clr8" style="color: #d41c1c;">-1 Token</span></b>.</li></ul>

<i>Coup de Grâce</i> can only hold a maximum of <b><span class="luaClr clr clr4" style="color: #ac3ee3;">5 Tokens</span></b> at a time.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 As the end nears, you go in for the kill.
Whenever a Generator is completed, Coup de Grâce gains +2 Tokens , up to a maximum of 10 Tokens per Trial:
Increases the range of your next Lunge Attack by 70 / 75 / 80 %, while consuming -1 Token .

Coup de Grâce can only hold a maximum of 5 Tokens at a time.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Cruel_Limits', 'killer', 'Cruel Limits', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c6/IconPerks_cruelLimits.png/revision/latest?cb=20190903175111', 'Your ties to the otherworldly manifest when your prey attempts to get away.
<p>Whenever a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> is completed, <i>Cruel Limits</i> activates:
</p><ul><li><b>Blocks</b> every Vault location on the Map for all Survivors for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.</li>
<li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the blocked Vault locations are highlighted to you in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"The specimen seems to be able to affect the state of nearby objects, as if they existed in some other form within a dimension alternate to our own." — Hawkins National Laboratory</span></i>
', 'Your ties to the otherworldly manifest when your prey attempts to get away.
Whenever a Generator is completed, Cruel Limits activates:
Blocks every Vault location on the Map for all Survivors for the next 20 / 25 / 30 seconds.
The Auras of the blocked Vault locations are highlighted to you in yellow .

"The specimen seems to be able to affect the state of nearby objects, as if they existed in some other form within a dimension alternate to our own." — Hawkins National Laboratory', 'Demogorgon');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dark_Arrogance', 'killer', 'Dark Arrogance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b1/IconPerks_darkArrogance.png/revision/latest?cb=20240514174200', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">When everything is going right, you are an inescapable inevitability.
<p>Increases your Vaulting speed in exchange for increased vulnerability to being blinded and stunned:
</p><ul><li><b>Permanently increases</b> the duration of <i>Killer Blinds</i> by any means and the duration of <i>Pallet Stuns</i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">+25&nbsp;%</span></b>.</li>
<li><b>Permanently increases</b> your Vaulting speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">15</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">20</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">25</span></b> <b>%</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Run all you want. I will not be denied." — Vecna</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 When everything is going right, you are an inescapable inevitability.
Increases your Vaulting speed in exchange for increased vulnerability to being blinded and stunned:
Permanently increases the duration of Killer Blinds by any means and the duration of Pallet Stuns by +25 % .
Permanently increases your Vaulting speed by 15 / 20 / 25 %.

"Run all you want. I will not be denied." — Vecna', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dark_Devotion', 'killer', 'Dark Devotion', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconPerks_darkDevotion.png/revision/latest?cb=20190306195813', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">The display of your Powers creates a whirlwind of panic that spreads throughout the land.
<p>Whenever the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i> loses a <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span> by any means and thus enters the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>, <i>Dark Devotion</i> activates:
</p><ul><li>Your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span> transfers to the <i><b>Obsession</b></i> for <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>, and its radius is set to <b><span class="luaClr clr clr2" style="color: #e8c252;">32 metres</span></b>.</li>
<li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" class="mw-redirect" title="Undetectable">Undetectable</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/64?cb=20190903170250"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/96?cb=20190903170250"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/32?cb=20190903170250"></a></span></span></span></b></i> <b>Status Effect</b> for the same duration.</li></ul>
<p>The <i><b>Obsession</b></i> with your transferred Terror Radius is also considered to be ''inside the Terror Radius'' for other purposes.
</p><p><i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"And terror shall take hold of a defiant non-believer, who shall falsely announce my arrival." — (The Tablet of Adiris, 48.9)</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 The display of your Powers creates a whirlwind of panic that spreads throughout the land.
Whenever the Obsession loses a Health State by any means and thus enters the Injured State , Dark Devotion activates:
Your Terror Radius transfers to the Obsession for 20 / 25 / 30 seconds, and its radius is set to 32 metres .
Grants the Undetectable Status Effect for the same duration.
The Obsession with your transferred Terror Radius is also considered to be ''inside the Terror Radius'' for other purposes.
You can only be obsessed with one Survivor at a time.
"And terror shall take hold of a defiant non-believer, who shall falsely announce my arrival." — (The Tablet of Adiris, 48.9)', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Darkness_Revealed', 'killer', 'Darkness Revealed', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ed/IconPerks_darknessRevealed.png/revision/latest?cb=20220518112818', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">In your presence, places once thought to be safe are perhaps the most dangerous.
<p>Searching a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span> has the following effect:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">8 metres</span></b> of any <b>Locker</b> are revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">7</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>seconds</b>.</li></ul>

<i>Darkness Revealed</i> has a cool-down of <b><span class="luaClr clr clr6" style="color: #ff8800;">30 seconds</span></b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Stay in the light, my children. In darkness, your fear will expose you." — Otto Stamper</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 In your presence, places once thought to be safe are perhaps the most dangerous.
Searching a Locker has the following effect:
The Auras of Survivors within 8 metres of any Locker are revealed to you for 6 / 7 / 8 seconds.

Darkness Revealed has a cool-down of 30 seconds .
"Stay in the light, my children. In darkness, your fear will expose you." — Otto Stamper', 'Dredge');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dead_Man%27s_Switch', 'killer', 'Dead Man''s Switch', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconPerks_deadMansSwitch.png/revision/latest?cb=20200218172942', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">After hooking a Survivor, <i>Dead Man''s Switch</i> activates:
<ul><li><b>Blocks</b> the first <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> any Survivor stops repairing for <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">45</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>seconds</b>.</li>
<li>The <i>Blocked Generator</i> is highlighted to you in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li></ul>
<p><i>Dead Man''s Switch</i> cannot activate if its effect is still active from a previous activation.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I''ve seen the look on a man''s face when he realises he''s going to die." — Caleb Quinn</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 After hooking a Survivor, Dead Man''s Switch activates:
Blocks the first Generator any Survivor stops repairing for 40 / 45 / 50 seconds.
The Blocked Generator is highlighted to you in white .
Dead Man''s Switch cannot activate if its effect is still active from a previous activation.

"I''ve seen the look on a man''s face when he realises he''s going to die." — Caleb Quinn', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Deathbound', 'killer', 'Deathbound', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconPerks_deathbound.png/revision/latest?cb=20200526201504', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">Those whose lives are intertwined in darkness are destined to suffer together.
<p>Whenever a Survivor finishes healing another Survivor for the equivalent of <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b> <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span>, <i>Deathbound</i> activates:
</p><ul><li>Causes the Healer to scream and reveal their location.</li>
<li>Causes the Healer to suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" class="mw-redirect" title="Oblivious">Oblivious</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/64?cb=20190903170245"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/96?cb=20190903170245"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/32?cb=20190903170245"></a></span></span></span></b></i> <b>Status Effect</b> whenever they are farther than <b><span class="luaClr clr clr2" style="color: #e8c252;">16</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>metres</b> from the other Survivor.</li></ul>

<i>Deathbound</i> deactivates after the Healer loses a Health State.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 Those whose lives are intertwined in darkness are destined to suffer together.
Whenever a Survivor finishes healing another Survivor for the equivalent of 1 Health State , Deathbound activates:
Causes the Healer to scream and reveal their location.
Causes the Healer to suffer from the Oblivious Status Effect whenever they are farther than 16 / 12 / 8 metres from the other Survivor.

Deathbound deactivates after the Healer loses a Health State.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Deerstalker', 'killer', 'Deerstalker', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/01/IconPerks_deerstalker.png/revision/latest?cb=20160605204859', 'Unlocks potential in your Aura-reading ability:
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivors</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> in the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> within <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">28</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">36</span></b> <b>metres</b> of your location are revealed to you.</li></ul>
<p><br>
</p>
', 'Unlocks potential in your Aura-reading ability:
The Auras of all Survivors in the Dying State within 20 / 28 / 36 metres of your location are revealed to you.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Discordance', 'killer', 'Discordance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/82/IconPerks_discordance.png/revision/latest?cb=20181128100920', 'Any <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> within a range of <b><span class="luaClr clr clr2" style="color: #e8c252;">64</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">96</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">128</span></b> <b>metres</b> that is being repaired by <b><span class="luaClr clr clr2" style="color: #e8c252;">2 or more Survivors</span></b> is marked by a <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b> <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span>.
<ul><li>When the Generator is first highlighted, <i>Discordance</i> triggers a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> on the Generator.</li>
<li>After the Generator is no longer within range or is being repaired by just <b><span class="luaClr clr clr6" style="color: #ff8800;">1 Survivor</span></b>, the highlighted Aura will linger for another <b><span class="luaClr clr clr8" style="color: #d41c1c;">4 seconds</span></b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Smartasses get killed. We always see to that." — The Legion</span></i>
</p>', 'Any Generator within a range of 64 / 96 / 128 metres that is being repaired by 2 or more Survivors is marked by a yellow Aura .
When the Generator is first highlighted, Discordance triggers a Loud Noise Notification on the Generator.
After the Generator is no longer within range or is being repaired by just 1 Survivor , the highlighted Aura will linger for another 4 seconds .
"Smartasses get killed. We always see to that." — The Legion', 'Frank,_Julie,_Susie,_Joey');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dissolution', 'killer', 'Dissolution', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconPerks_dissolution.png/revision/latest?cb=20220518112819', 'Everything turns to dust. It is as inescapable as the coming of the night.
<p>After <b><span class="luaClr clr clr2" style="color: #e8c252;">3 seconds</span></b> of injuring a Survivor by any means, <i>Dissolution</i> activates for <b><span class="luaClr clr clr2" style="color: #e8c252;">12</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">16</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>:
</p><ul><li><b>Instantly breaks</b> the next <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallet</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span> that Survivor performs a <i>Fast Vault</i> across while inside your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"The Garden shall be a place of perfect Joy; through Joy, nothing shall stand in our way." — Otto Stamper</span></i>
', 'Everything turns to dust. It is as inescapable as the coming of the night.
After 3 seconds of injuring a Survivor by any means, Dissolution activates for 12 / 16 / 20 seconds :
Instantly breaks the next Pallet that Survivor performs a Fast Vault across while inside your Terror Radius .

"The Garden shall be a place of perfect Joy; through Joy, nothing shall stand in our way." — Otto Stamper', 'Dredge');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Distressing', 'killer', 'Distressing', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/94/IconPerks_distressing.png/revision/latest?cb=20160605204911', 'Your horrifying emanation strikes at a supernaturally long distance.
<ul><li><b>Increases</b> your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">22</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">24</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">26</span></b> <b>%</b></li>
<li>Grants <b><span class="luaClr clr clr2" style="color: #e8c252;">100&nbsp;%</span></b> bonus <a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints">Bloodpoints</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="58" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/64?cb=20180702212847"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="87" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/96?cb=20180702212847"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="29" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/32?cb=20180702212847"></a></span></span></span> for all actions in the <a href="https://deadbydaylight.fandom.com/wiki/Deviousness" class="mw-redirect" title="Deviousness">Deviousness</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deviousness" title="Deviousness"><img alt="DailyRitualIcon deviousness" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="DailyRitualIcon deviousness.png" data-image-key="DailyRitualIcon_deviousness.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/DailyRitualIcon_deviousness.png/revision/latest/scale-to-width-down/64?cb=20160607183430"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deviousness" title="Deviousness"><img alt="DailyRitualIcon deviousness" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="DailyRitualIcon deviousness.png" data-image-key="DailyRitualIcon_deviousness.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/DailyRitualIcon_deviousness.png/revision/latest/scale-to-width-down/96?cb=20160607183430"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deviousness" title="Deviousness"><img alt="DailyRitualIcon deviousness" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="DailyRitualIcon deviousness.png" data-image-key="DailyRitualIcon_deviousness.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/DailyRitualIcon_deviousness.png/revision/latest/scale-to-width-down/32?cb=20160607183430"></a></span></span></span> Category.</li></ul>
<p><br>
</p>
', 'Your horrifying emanation strikes at a supernaturally long distance.
Increases your Terror Radius by 22 / 24 / 26 %
Grants 100 % bonus Bloodpoints for all actions in the Deviousness Category.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dominance', 'killer', 'Dominance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/8d/IconPerks_Dominance.png/revision/latest?cb=20240806171415', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">The power you wield over the land strikes terror in the hearts of all who cross your path.
<p>The first time each <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chest</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> and each <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> are interacted with by a Survivor, <i>Dominance</i> triggers its effect:
</p><ul><li>Calls upon The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> to block it for <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>seconds</b>.</li>
<li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the blocked Prop is revealed to you in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Tragic, is it not? How powerless you must feel." — Dracula</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 The power you wield over the land strikes terror in the hearts of all who cross your path.
The first time each Chest and each Totem are interacted with by a Survivor, Dominance triggers its effect:
Calls upon The Entity to block it for 8 / 12 / 16 seconds.
The Aura of the blocked Prop is revealed to you in white .

"Tragic, is it not? How powerless you must feel." — Dracula', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dragon%27s_Grip', 'killer', 'Dragon''s Grip', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/IconPerks_dragonsGrip.png/revision/latest?cb=20200819113412', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">Performing the <i>Damage Generator</i> action on a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> activates <i>Dragon''s Grip</i> for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">30 seconds</span></b>:
<ul><li>The first Survivor interacting with the damaged <b>Generator</b> will scream, revealing their location for <b><span class="luaClr clr clr6" style="color: #ff8800;">4 seconds</span></b>, and suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">60 seconds</span></b>.</li></ul>
<p><i>Dragon''s Grip</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Such potential in this compound... even the slightest trace causes unnatural effects." — Journal of Talbot Grimes</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 Performing the Damage Generator action on a Generator activates Dragon''s Grip for the next 30 seconds :
The first Survivor interacting with the damaged Generator will scream, revealing their location for 4 seconds , and suffer from the Exposed Status Effect for 60 seconds .
Dragon''s Grip has a cool-down of 60 / 50 / 40 seconds.

"Such potential in this compound... even the slightest trace causes unnatural effects." — Journal of Talbot Grimes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dying_Light', 'killer', 'Dying Light', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/48/IconPerks_dyingLight.png/revision/latest?cb=20161023113257', 'Each time you hook a Survivor other than your <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i>, you gain <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b>:
<ul><li>For as long as the <i><b>Obsession</b></i> is alive, all other Survivors suffer from a stack-able <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">2.5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b> <b>%</b> per Token Action Speed penalty to Repairing, Healing, and Sabotaging, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">22</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">27.5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">33</span></b> <b>%</b> or <b><span class="luaClr clr clr6" style="color: #ff8800;">11 Tokens</span></b>.</li>
<li>The <i><b>Obsession</b></i> is unaffected by this penalty and instead granted a permanent <b><span class="luaClr clr clr8" style="color: #d41c1c;">+33&nbsp;%</span></b> Action Speed bonus to Unhooking and Healing other Survivors.</li></ul>
<p><i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"This isn''t a man..." — Dr Sam Loomis</span></i>
</p>', 'Each time you hook a Survivor other than your Obsession , you gain +1 Token :
For as long as the Obsession is alive, all other Survivors suffer from a stack-able 2 / 2.5 / 3 % per Token Action Speed penalty to Repairing, Healing, and Sabotaging, up to a maximum of 22 / 27.5 / 33 % or 11 Tokens .
The Obsession is unaffected by this penalty and instead granted a permanent +33 % Action Speed bonus to Unhooking and Healing other Survivors.
You can only be obsessed with one Survivor at a time.

"This isn''t a man..." — Dr Sam Loomis', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Enduring', 'killer', 'Enduring', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/94/IconPerks_enduring.png/revision/latest?cb=20160605204922', 'You are resilient to pain.
<ul><li><b>Reduces</b> the duration of <i>Pallet Stuns</i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">45</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b>.</li></ul>
<p><i>Enduring</i> has no effect while carrying a Survivor.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"He stops at nothing."</span></i>
</p>', 'You are resilient to pain.
Reduces the duration of Pallet Stuns by 40 / 45 / 50 %.
Enduring has no effect while carrying a Survivor.

"He stops at nothing."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Eruption', 'killer', 'Eruption', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/dd/IconPerks_eruption.png/revision/latest?cb=20210526102859', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.6.0</div><div class="dynamicContent ptb">The NE-α parasite provides you with the intelligence and awareness needed to set a trap.
<p>Performing the <i>Damage Generator</i> action on a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> applies <i>Eruption</i>:
</p><ul><li>All affected Generators are highlighted to you in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.</li>
<li>The next time any <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivor</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> enters the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> by any means, all affected Generators explode and immediately start regressing, which removes the highlighted Aura.</li>
<li><b>Instantly regresses</b> the Generator by <b><span class="luaClr clr clr2" style="color: #e8c252;">-10&nbsp;%</span></b> of its maximum possible Progression.</li>
<li>Causes all Survivors repairing the afflicted Generators to scream and reveal their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">10</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">12</span></b> <b>seconds</b>.</li></ul>

<i>Eruption</i> has a cool-down of <b><span class="luaClr clr clr6" style="color: #ff8800;">30 seconds</span></b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"It can use weapons?" — Jill Valentine</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.6.0 The NE-α parasite provides you with the intelligence and awareness needed to set a trap.
Performing the Damage Generator action on a Generator applies Eruption :
All affected Generators are highlighted to you in yellow .
The next time any Survivor enters the Dying State by any means, all affected Generators explode and immediately start regressing, which removes the highlighted Aura.
Instantly regresses the Generator by -10 % of its maximum possible Progression.
Causes all Survivors repairing the afflicted Generators to scream and reveal their Aura to you for 8 / 10 / 12 seconds.

Eruption has a cool-down of 30 seconds .
"It can use weapons?" — Jill Valentine', 'Nemesis_T-Type');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Fire_Up', 'killer', 'Fire Up', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5c/IconPerks_fireUp.png/revision/latest?cb=20171026225645', 'The increased pressure of losing your preys fills you with anger and gives you unsuspected motivation.
<p>Each time a Generator is completed, <i>Fire Up</i> grows in power and gains <b><span class="luaClr clr clr2" style="color: #e8c252;">1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr6" style="color: #ff8800;">5 Tokens</span></b>.<br>
Each Token applies a stack-able buff of <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3.5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>%</b> per Token, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">15</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">17.5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>%</b>, to the following Action speeds:
</p><ul><li>Picking up and dropping Survivors.</li>
<li>Breaking <a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" class="mw-redirect" title="Breakable Wall">Breakable Walls</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/64?cb=20220910215339"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/96?cb=20220910215339"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/32?cb=20220910215339"></a></span></span></span> and <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallets</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span>, and damaging <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span>.</li>
<li>Vaulting <a href="https://deadbydaylight.fandom.com/wiki/Window" class="mw-redirect" title="Window">Windows</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="57" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/64?cb=20170921093258"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="85" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/96?cb=20170921093258"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="28" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/32?cb=20170921093258"></a></span></span></span>.</li></ul>


<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Now why don''t you just fucking die?" — Freddy Krueger</span></i>
</p>', 'The increased pressure of losing your preys fills you with anger and gives you unsuspected motivation.
Each time a Generator is completed, Fire Up grows in power and gains 1 Token , up to a maximum of 5 Tokens .
Each Token applies a stack-able buff of 3 / 3.5 / 4 % per Token, up to a maximum of 15 / 17.5 / 20 %, to the following Action speeds:
Picking up and dropping Survivors.
Breaking Breakable Walls and Pallets , and damaging Generators .
Vaulting Windows .

"Now why don''t you just fucking die?" — Freddy Krueger', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Forced_Hesitation', 'killer', 'Forced Hesitation', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4c/IconPerks_forcedHesitation.png/revision/latest?cb=20230524214839', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.0.0</div><div class="dynamicContent ptb">You have learnt the emotional weaknesses of the organics, and how to exploit them.
<ul><li>Whenever a Survivor is put into the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> by any means, all other Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">16 metres</span></b> of them suffer from a <b><span class="luaClr clr clr6" style="color: #ff8800;">-20&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Hindered" class="mw-redirect" title="Hindered">Hindered</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hindered" title="Hindered"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/64?cb=20201201161431"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hindered" title="Hindered"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/96?cb=20201201161431"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hindered" title="Hindered"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/32?cb=20201201161431"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">10 seconds</span></b>.</li></ul>
<p><i>Forced Hesitation</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">35</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"THE ORGANIC MIND''S CAPACITY FOR EMPATHY GOES BEYOND HINDRANCE!" — HUX-A7-13</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.0.0 You have learnt the emotional weaknesses of the organics, and how to exploit them.
Whenever a Survivor is put into the Dying State by any means, all other Survivors within 16 metres of them suffer from a -20 % Hindered Status Effect for 10 seconds .
Forced Hesitation has a cool-down of 40 / 35 / 30 seconds.
"THE ORGANIC MIND''S CAPACITY FOR EMPATHY GOES BEYOND HINDRANCE!" — HUX-A7-13', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Forced_Penance', 'killer', 'Forced Penance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconPerks_forcedPenance.png/revision/latest?cb=20200526201518', 'Those who stand in the way of duty will suffer harsh judgement.<br>
<p>Survivors who take a <i><a href="https://deadbydaylight.fandom.com/wiki/Protection_Hit" class="mw-redirect" title="Protection Hit">Protection Hit</a></i> suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/64?cb=20180829073317"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/32?cb=20180829073317"></a></span></span></span></b></i> <b>Status Effect</b> for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">70</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">80</span></b> <b>seconds</b>.
</p>
', 'Those who stand in the way of duty will suffer harsh judgement.
Survivors who take a Protection Hit suffer from the Broken Status Effect for the next 60 / 70 / 80 seconds.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Forever_Entwined', 'killer', 'Forever Entwined', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6d/IconPerks_foreverEntwined.png/revision/latest?cb=20250616212701', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.6.0</div><div class="dynamicContent ptb">Unable to retrieve the Perk description or unable to display it. It can be added to the <a href="https://deadbydaylight.fandom.com/wiki/Module:Datatable/Loadout/Descriptions" title="Module:Datatable/Loadout/Descriptions">Datatable/Loadout</a>. Otherwise  Please contact <a href="https://deadbydaylight.fandom.com/wiki/User:Jouki" class="gamepedia_pro_user" title="User:Jouki">Jouki</a></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.6.0 Unable to retrieve the Perk description or unable to display it. It can be added to the Datatable/Loadout. Otherwise  Please contact Jouki', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Franklin%27s_Demise', 'killer', 'Franklin''s Demise', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b2/IconPerks_franklinsDemise.png/revision/latest?cb=20170914173626', 'Your vicious <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attacks" class="mw-redirect" title="Basic Attacks">Basic Attacks</a></i> make Survivors drop their <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Items</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span> on impact:
<ul><li>Causes dropped <b>Items</b> to slowly lose their Charges over <b><span class="luaClr clr clr2" style="color: #e8c252;">150</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">120</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">90</span></b> <b>seconds</b>.</li>
<li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of dropped <b>Items</b> are revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">32 metres</span></b>.
<ul><li>The level of depletion is indicated by the colour of the Aura, ranging from <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b> to <b><span class="luaClr clr clr19" style="color: #ff0000;">red</span></b> as the timer elapses.</li></ul></li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Sally, I hear something. Stop! Stop!" — Franklin Hardesty</span></i>
</p>
', 'Your vicious Basic Attacks make Survivors drop their Items on impact:
Causes dropped Items to slowly lose their Charges over 150 / 120 / 90 seconds.
The Auras of dropped Items are revealed to you within 32 metres .
The level of depletion is indicated by the colour of the Aura, ranging from white to red as the timer elapses.
"Sally, I hear something. Stop! Stop!" — Franklin Hardesty', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Friends_%27til_the_End', 'killer', 'Friends ''til the End', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconPerks_friendsTilTheEnd.png/revision/latest?cb=20231108172943', 'You will kill anyone who gets between you and your target.
<p>When you hook any Survivors that is not the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i>, the following effects apply to the <i><b>Obsession</b></i>:
</p><ul><li>Their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is revealed for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li>
<li>They suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">20 seconds</span></b>.</li></ul>

When you hook the <i><b>Obsession</b></i>, the following effects apply to a random Survivor:
<ul><li>Causes the Survivor to scream and reveal their location to the Killer.</li>
<li>They become the new <i><b>Obsession</b></i>.</li></ul>

<i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I got some fresh meat lined up, and I''m not gonna let you spoil it, not this time!" — Chucky</span></i>
</p>', 'You will kill anyone who gets between you and your target.
When you hook any Survivors that is not the Obsession , the following effects apply to the Obsession :
Their Aura is revealed for 6 / 8 / 10 seconds.
They suffer from the Exposed Status Effect for 20 seconds .

When you hook the Obsession , the following effects apply to a random Survivor:
Causes the Survivor to scream and reveal their location to the Killer.
They become the new Obsession .

You can only be obsessed with one Survivor at a time.
"I got some fresh meat lined up, and I''m not gonna let you spoil it, not this time!" — Chucky', 'Charles_Lee_Ray');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Furtive_Chase', 'killer', 'Furtive Chase', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/94/IconPerks_furtiveChase.png/revision/latest?cb=20190606094409', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.3.0</div><div class="dynamicContent ptb">You lurk in the shadows, eliminating your victims one by one.
<p>Each time you hook your <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i>, you benefit from the following effects for <b><span class="luaClr clr clr2" style="color: #e8c252;">14</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">16</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">18</span></b> <b>seconds</b>:
</p><ul><li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" class="mw-redirect" title="Undetectable">Undetectable</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/64?cb=20190903170250"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/96?cb=20190903170250"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/32?cb=20190903170250"></a></span></span></span></b></i> <b>Status Effect</b>.</li>
<li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">+5&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b>.</li></ul>


<p>Whenever the <i><b>Obsession</b></i> is rescued from a Hook, their rescuer will become the new <i><b>Obsession</b></i>.
</p><p><i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You have no idea what I have planned for you. It''ll be in the news for weeks. I''ll make sure of that." — The Ghost Face</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.3.0 You lurk in the shadows, eliminating your victims one by one.
Each time you hook your Obsession , you benefit from the following effects for 14 / 16 / 18 seconds :
Grants the Undetectable Status Effect.
Grants a +5 % Haste Status Effect.

Whenever the Obsession is rescued from a Hook, their rescuer will become the new Obsession .
You can only be obsessed with one Survivor at a time.
"You have no idea what I have planned for you. It''ll be in the news for weeks. I''ll make sure of that." — The Ghost Face', 'Danny_Johnson');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Game_Afoot', 'killer', 'Game Afoot', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/53/IconPerks_gameAfoot.png/revision/latest?cb=20230218135317', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.6.0</div><div class="dynamicContent ptb">First you pick your prey, then you pick it apart.
<ul><li>Whenever you hit the Survivor with the highest cumulative Chase time, with a <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attack" class="mw-redirect" title="Basic Attack">Basic Attack</a></i>, they become the <i><b>Obsession</b></i>.</li></ul>
<p>While you are chasing your <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i>, <i>Game Afoot</i> activates its secondary effect:
</p><ul><li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">5&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">9</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b> after damaging a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> or breaking a <a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" class="mw-redirect" title="Breakable Wall">Breakable Wall</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/64?cb=20220910215339"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/96?cb=20220910215339"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/32?cb=20220910215339"></a></span></span></span> or <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallet</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span></li></ul>
<p><i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"This one might actually be a challenge..." — Sonhadores Sombrios, Issue #3</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.6.0 First you pick your prey, then you pick it apart.
Whenever you hit the Survivor with the highest cumulative Chase time, with a Basic Attack , they become the Obsession .
While you are chasing your Obsession , Game Afoot activates its secondary effect:
Grants a 5 % Haste Status Effect for 8 / 9 / 10 seconds after damaging a Generator or breaking a Breakable Wall or Pallet
You can only be obsessed with one Survivor at a time.
"This one might actually be a challenge..." — Sonhadores Sombrios, Issue #3', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Gearhead', 'killer', 'Gearhead', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fd/IconPerks_gearhead.png/revision/latest?cb=20200218172900', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.7.0</div><div class="dynamicContent ptb">You have got an ear for well-oiled gears.
<p>After a Survivor loses a <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span>, <i>Gearhead</i> activates for <b><span class="luaClr clr clr2" style="color: #e8c252;">30 seconds</span></b>:
</p><ul><li>While <i>Gearhead</i> is active, a <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivor</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> succeeding a <a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" class="mw-redirect" title="Good Skill Check">Good Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" title="Good Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" title="Good Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" title="Good Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> while repairing reveals their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">7</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>seconds</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Sometimes a man''s best work is what puts him in the grave." — The Prison Warden</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.7.0 You have got an ear for well-oiled gears.
After a Survivor loses a Health State , Gearhead activates for 30 seconds :
While Gearhead is active, a Survivor succeeding a Good Skill Check while repairing reveals their Aura to you for 6 / 7 / 8 seconds.
"Sometimes a man''s best work is what puts him in the grave." — The Prison Warden', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Genetic_Limits', 'killer', 'Genetic Limits', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6d/IconPerks_geneticLimits.png/revision/latest?cb=20230524214956', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">Around you, the limits of human life become readily apparent.
<ul><li>Whenever a Survivor loses a Health State, they suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">7</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>seconds</b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"THE ORGANIC BODY IS SO LIMITED!" — HUX-A7-13</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 Around you, the limits of human life become readily apparent.
Whenever a Survivor loses a Health State, they suffer from the Exhausted Status Effect for 6 / 7 / 8 seconds.
"THE ORGANIC BODY IS SO LIMITED!" — HUX-A7-13', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Grim_Embrace', 'killer', 'Grim Embrace', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_grimEmbrace.png/revision/latest?cb=20211109180734', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">Your act of servitude to The Entity has not gone unnoticed.
<p>Each time a Survivor is hooked for the first time, <i>Grim Embrace</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b> and activates once you are at least <b><span class="luaClr clr clr6" style="color: #ff8800;">16 metres</span></b> away from the <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hook</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span>:
</p><ul><li><b><span class="luaClr clr clr13" style="color: #418284;">1-3 Tokens</span></b>: <b>Blocks</b> all <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">4 Tokens</span></b>: <b>Blocks</b> all <b>Generators</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">40 seconds</span></b> and the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i> is revealed to you for <b><span class="luaClr clr clr4" style="color: #ac3ee3;">6 seconds</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Are we nothing but prisoners to our sorrow?" — Carmina Mora</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 Your act of servitude to The Entity has not gone unnoticed.
Each time a Survivor is hooked for the first time, Grim Embrace gains +1 Token and activates once you are at least 16 metres away from the Hook :
1-3 Tokens : Blocks all Generators for 6 / 8 / 10 seconds.
4 Tokens : Blocks all Generators for 40 seconds and the Aura of the Obsession is revealed to you for 6 seconds .

"Are we nothing but prisoners to our sorrow?" — Carmina Mora', NULL);
