INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Blood_Favour', 'killer', 'Hex: Blood Favour', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6b/IconPerks_hexBloodFavour.png/revision/latest?cb=20200819113451', 'A Hex that gains the favour of The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> when blood is spilt.
<ul><li>Whenever a Survivor loses a <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span> by any means and thus enters the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span> or the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span>, <i>Hex: Blood Favour</i> calls upon The Entity to block all <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallets</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span> within <b><span class="luaClr clr clr2" style="color: #e8c252;">24</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">28</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">32</span></b> <b>metres</b> of that Survivor''s location from being pulled down for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">15 seconds</span></b>.</li></ul>
<p><i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"It would be no leap of the imagination to suggest that the Trials are a biological response of sorts." — Journal of Talbot Grimes</span></i>
</p>', 'A Hex that gains the favour of The Entity when blood is spilt.
Whenever a Survivor loses a Health State by any means and thus enters the Injured State or the Dying State , Hex: Blood Favour calls upon The Entity to block all Pallets within 24 / 28 / 32 metres of that Survivor''s location from being pulled down for the next 15 seconds .
All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.
"It would be no leap of the imagination to suggest that the Trials are a biological response of sorts." — Journal of Talbot Grimes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Crowd_Control', 'killer', 'Hex: Crowd Control', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f1/IconPerks_hexCrowdControl.png/revision/latest?cb=20210302172300', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">A Hex that ensures those lesser than you are properly herded.
<p>Whenever any Survivor performs a <i>Rushed</i> Action to vault a <a href="https://deadbydaylight.fandom.com/wiki/Window" class="mw-redirect" title="Window">Window</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="57" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/64?cb=20170921093258"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="85" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/96?cb=20170921093258"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="28" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/32?cb=20170921093258"></a></span></span></span>, <i>Hex: Crowd Control</i> triggers its effect:
</p><ul><li><b>Permanently blocks</b> the last <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b>  <b>Windows</b> to all Survivors.</li></ul>

Any successive trigger unblocks the oldest <i>Blocked Window</i>.
<p><i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You have no control. People like you never did." — Ji-Woon Hak</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 A Hex that ensures those lesser than you are properly herded.
Whenever any Survivor performs a Rushed Action to vault a Window , Hex: Crowd Control triggers its effect:
Permanently blocks the last 3 / 4 / 5 Windows to all Survivors.

Any successive trigger unblocks the oldest Blocked Window.
All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.
"You have no control. People like you never did." — Ji-Woon Hak', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Devour_Hope', 'killer', 'Hex: Devour Hope', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c9/IconPerks_hexDevourHope.png/revision/latest?cb=20161209192341', 'A Hex rooting its power on hope.<br>The false hope of Survivors ignites your hunger.
<p>Whenever a Survivor is rescued from a <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hook</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span> while you are at least <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b> away, <i>Hex: Devour Hope</i> is granted <b><span class="luaClr clr clr6" style="color: #ff8800;">+1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr8" style="color: #d41c1c;">5 Tokens</span></b>:
</p><ul><li><b><span class="luaClr clr clr13" style="color: #418284;">2 Tokens</span></b>: Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>%</b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr4" style="color: #ac3ee3;">10 seconds</span></b> after <b><span class="luaClr clr clr3" style="color: #199b1e;">10 seconds</span></b> of having hooked a Survivor.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">3 Tokens</span></b>: causes all Survivors to suffer from a permanent <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">5 Tokens</span></b>: grants the ability to kill all Survivors by your own hand.</li></ul>

<i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"If you do nothing, you have their blood on your hands. If you save them, her hunger grows."</span></i>
</p>', 'A Hex rooting its power on hope. The false hope of Survivors ignites your hunger.
Whenever a Survivor is rescued from a Hook while you are at least 24 metres away, Hex: Devour Hope is granted +1 Token , up to a maximum of 5 Tokens :
2 Tokens : Grants a 3 / 4 / 5 % Haste Status Effect for 10 seconds after 10 seconds of having hooked a Survivor.
3 Tokens : causes all Survivors to suffer from a permanent Exposed Status Effect.
5 Tokens : grants the ability to kill all Survivors by your own hand.

All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.
"If you do nothing, you have their blood on your hands. If you save them, her hunger grows."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Face_the_Darkness', 'killer', 'Hex: Face the Darkness', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconPerks_hexFaceTheDarkness.png/revision/latest?cb=20221102143124', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.4.0</div><div class="dynamicContent ptb">You make an example of one of your victims, forcing their allies to become awed by your power.
<p>Whenever you injure a Survivor by any means, if there is still a <a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" class="mw-redirect" title="Dull Totem">Dull Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> remaining on the Map, <i>Hex: Face the Darkness</i> activates and lights it, cursing that Survivor:
</p><ul><li>Causes all other Survivors to scream every <b><span class="luaClr clr clr2" style="color: #e8c252;">35</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">30</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">25</span></b> <b>seconds</b>, if they are outside of the <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span>, revealing their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">2 seconds</span></b> each time.</li></ul>


<p><i>Hex: Face the Darkness</i> deactivates once the <i>Cursed Survivor</i> either enters the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> or is fully healed, which extinguishes the <b>Totem</b>.
</p><p><i>Hex: Face the Darkness</i> is disabled for the remainder of the Trial, if a Survivor manages to cleanse its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I shall make an example of one. These mewling worms will never know peace." — Tarhos Kovács</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.4.0 You make an example of one of your victims, forcing their allies to become awed by your power.
Whenever you injure a Survivor by any means, if there is still a Dull Totem remaining on the Map, Hex: Face the Darkness activates and lights it, cursing that Survivor:
Causes all other Survivors to scream every 35 / 30 / 25 seconds, if they are outside of the Terror Radius , revealing their Auras for 2 seconds each time.

Hex: Face the Darkness deactivates once the Cursed Survivor either enters the Dying State or is fully healed, which extinguishes the Totem.
Hex: Face the Darkness is disabled for the remainder of the Trial, if a Survivor manages to cleanse its Hex Totem .
"I shall make an example of one. These mewling worms will never know peace." — Tarhos Kovács', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Haunted_Ground', 'killer', 'Hex: Haunted Ground', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconPerks_hexHauntedGround.png/revision/latest?cb=20180828172944', 'Two trapped <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totems</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> will spawn in the Trial Grounds.
<ul><li>When either Hex Totem is cleansed or blessed, all <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivors</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.</li>
<li>The second Hex Totem will immediately turn into a Dull Totem.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Her home become profane."</span></i>
</p>', 'Two trapped Hex Totems will spawn in the Trial Grounds.
When either Hex Totem is cleansed or blessed, all Survivors suffer from the Exposed Status Effect for 40 / 50 / 60 seconds.
The second Hex Totem will immediately turn into a Dull Totem.
"Her home become profane."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Huntress_Lullaby', 'killer', 'Hex: Huntress Lullaby', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/11/IconPerks_hexHuntressLullaby.png/revision/latest?cb=20170727160900', 'A Hex rooting its power in despair.<br>
<p>Your hunt is an irresistible song of dread which muddles your prey''s attention.
</p>
<ul><li>Survivors failing a Repair <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span><b>instantly regress</b> the Generator by <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>%</b> of its maximum possible Progression in addition to the default Progression penalty.</li>
<li>Survivors failing a Healing Skill Check <b>instantly regress</b> the Healing Action by <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>%</b> of its maximum possible Progression in addition to the default Progression penalty.</li></ul>
<p>Each time a Survivor is hooked, <i>Hex: Huntress Lullaby</i> grows in power and gains <b><span class="luaClr clr clr2" style="color: #e8c252;">1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr6" style="color: #ff8800;">5 Tokens</span></b>.<br>
Each Token <b>reduces</b> the timer between the Skill Check Warning cue and the Skill Check appearing for both Repair and Healing Skill Checks:
</p>
<ul><li><b><span class="luaClr clr clr13" style="color: #418284;">1 Token</span></b>: reduction of <b><span class="luaClr clr clr8" style="color: #d41c1c;">-14&nbsp;%</span></b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">2 Tokens</span></b>: reduction of <b><span class="luaClr clr clr4" style="color: #ac3ee3;">-28&nbsp;%</span></b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">3 Tokens</span></b>: reduction of <b><span class="luaClr clr clr3" style="color: #199b1e;">-42&nbsp;%</span></b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">4 Tokens</span></b>: reduction of <b><span class="luaClr clr clr10" style="color: #0e98ff;">-56&nbsp;%</span></b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">5 Tokens</span></b>: complete suppression of the Warning cue.</li></ul>
<p><i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"That song, it drives me crazy!"</span></i>
</p>', 'A Hex rooting its power in despair.
Your hunt is an irresistible song of dread which muddles your prey''s attention.

Survivors failing a Repair Skill Check instantly regress the Generator by 2 / 4 / 6 % of its maximum possible Progression in addition to the default Progression penalty.
Survivors failing a Healing Skill Check instantly regress the Healing Action by 2 / 4 / 6 % of its maximum possible Progression in addition to the default Progression penalty.
Each time a Survivor is hooked, Hex: Huntress Lullaby grows in power and gains 1 Token , up to a maximum of 5 Tokens .
Each Token reduces the timer between the Skill Check Warning cue and the Skill Check appearing for both Repair and Healing Skill Checks:

1 Token : reduction of -14 % .
2 Tokens : reduction of -28 % .
3 Tokens : reduction of -42 % .
4 Tokens : reduction of -56 % .
5 Tokens : complete suppression of the Warning cue.
All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.

"That song, it drives me crazy!"', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_No_One_Escapes_Death', 'killer', 'Hex: No One Escapes Death', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconPerks_hexNoOneEscapesDeath.png/revision/latest?cb=20160605205020', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">A Hex rooting its power on hope.<br>You are animated by the power of your Hex Totem when the Survivors are on the verge of escaping.
<p>Once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are powered, if there is still a <a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" class="mw-redirect" title="Dull Totem">Dull Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> remaining in the environment, <i>Hex: No One Escapes Death</i> activates and lights it:
</p><ul><li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>%</b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b>.</li>
<li>Causes all Survivors to suffer permanently from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b>.</li></ul>


<p><i>Hex: No One Escapes Death</i> remains inactive if no <b>Dull Totems</b> are available.
</p><p>Once the <b>Status Effect</b> is revealed to Survivors, <i>Hex: No One Escapes Death</i> reveals the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of its <b>Hex Totem</b> to all Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">4 metres</span></b> and gradually expands that range to <b><span class="luaClr clr clr6" style="color: #ff8800;">24 metres</span></b> over the course of <b><span class="luaClr clr clr8" style="color: #d41c1c;">30 seconds</span></b>.
</p><p><i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"And the beast became faster and more powerful as if The Entity''s shadowy whips were lashing at its back."</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 A Hex rooting its power on hope. You are animated by the power of your Hex Totem when the Survivors are on the verge of escaping.
Once the Exit Gates are powered, if there is still a Dull Totem remaining in the environment, Hex: No One Escapes Death activates and lights it:
Grants a 2 / 3 / 4 % Haste Status Effect.
Causes all Survivors to suffer permanently from the Exposed Status Effect.

Hex: No One Escapes Death remains inactive if no Dull Totems are available.
Once the Status Effect is revealed to Survivors, Hex: No One Escapes Death reveals the Aura of its Hex Totem to all Survivors within 4 metres and gradually expands that range to 24 metres over the course of 30 seconds .
All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.
"And the beast became faster and more powerful as if The Entity''s shadowy whips were lashing at its back."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Nothing_But_Misery', 'killer', 'Hex: Nothing But Misery', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6f/IconPerks_hexNothingButMisery.png/revision/latest?cb=20250616212702', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.6.0</div><div class="dynamicContent ptb">Unable to retrieve the Perk description or unable to display it. It can be added to the <a href="https://deadbydaylight.fandom.com/wiki/Module:Datatable/Loadout/Descriptions" title="Module:Datatable/Loadout/Descriptions">Datatable/Loadout</a>. Otherwise  Please contact <a href="https://deadbydaylight.fandom.com/wiki/User:Jouki" class="gamepedia_pro_user" title="User:Jouki">Jouki</a></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.6.0 Unable to retrieve the Perk description or unable to display it. It can be added to the Datatable/Loadout. Otherwise  Please contact Jouki', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Pentimento', 'killer', 'Hex: Pentimento', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5d/IconPerks_hexPentimento.png/revision/latest?cb=20211109175002', 'You reveal the true power of the Totems, hidden within their remains.
<ul><li>You see the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of cleansed <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totems</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>.</li></ul>
<p>You can perform a ritual on a cleansed Totem to resurrect it as a <i>Rekindled Totem</i>.<br>
For each <i>Rekindled Totem</i> active at the same time, <i>Hex: Pentimento</i> gains an additional effect:
</p>
<ul><li><b><span class="luaClr clr clr13" style="color: #418284;">1 Totem</span></b>: <b>reduces</b> all Survivors'' Repair speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">2 Totems</span></b>: <b>reduces</b> all Survivors'' Healing speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">3 Totems</span></b>: <b>reduces</b> all Survivors'' Recovery speed from being downed by <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">4 Totems</span></b>: <b>reduces</b> all Survivors'' Gate-Opening speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">5 Totems</span></b>: all Totems are permanently blocked by The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span>.</li></ul>
<p>When a <i>Rekindled Totem</i> is cleansed, its remains are consumed by The Entity and it cannot be rekindled.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Though a pentimento is an inherently concealed piece of art, there is something to be said of the desire to discover that which is beyond." — A Guide to Art &amp; Process (1961)</span></i>
</p>', 'You reveal the true power of the Totems, hidden within their remains.
You see the Auras of cleansed Totems .
You can perform a ritual on a cleansed Totem to resurrect it as a Rekindled Totem.
For each Rekindled Totem active at the same time, Hex: Pentimento gains an additional effect:

1 Totem : reduces all Survivors'' Repair speed by 20 / 25 / 30 %.
2 Totems : reduces all Survivors'' Healing speed by 20 / 25 / 30 %.
3 Totems : reduces all Survivors'' Recovery speed from being downed by 20 / 25 / 30 %.
4 Totems : reduces all Survivors'' Gate-Opening speed by 20 / 25 / 30 %.
5 Totems : all Totems are permanently blocked by The Entity .
When a Rekindled Totem is cleansed, its remains are consumed by The Entity and it cannot be rekindled.

"Though a pentimento is an inherently concealed piece of art, there is something to be said of the desire to discover that which is beyond." — A Guide to Art & Process (1961)', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Retribution', 'killer', 'Hex: Retribution', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ab/IconPerks_hexRetribution.png/revision/latest?cb=20200218172811', 'A Hex that lashes out upon its destruction.<br>
<p>Those who cross you will be punished.
</p>
<p class="mw-empty-elt">
</p><ul><li>Survivors cleansing or blessing any <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" class="mw-redirect" title="Oblivious">Oblivious</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/64?cb=20190903170245"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/96?cb=20190903170245"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/32?cb=20190903170245"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">35</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">45</span></b> <b>seconds</b>.</li>
<li>After cleansing or blessing a <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all Survivors are revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">15 seconds</span></b>.</li></ul>
<p><i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Bloody fool, you pulled the trigger on yourself." — Caleb Quinn</span></i>
</p>', 'A Hex that lashes out upon its destruction.
Those who cross you will be punished.

Survivors cleansing or blessing any Totem suffer from the Oblivious Status Effect for 35 / 40 / 45 seconds.
After cleansing or blessing a Hex Totem , the Auras of all Survivors are revealed to you for 15 seconds .
All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.
"Bloody fool, you pulled the trigger on yourself." — Caleb Quinn', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Ruin', 'killer', 'Hex: Ruin', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a2/IconPerks_hexRuin.png/revision/latest?cb=20161209193143', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.5.0</div><div class="dynamicContent ptb">A Hex that affects the Generator Repair progress of all Survivors.
<ul><li>Whenever a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> is not being repaired by a Survivor, it will immediately and automatically regress its Repair progress at <b><span class="luaClr clr clr2" style="color: #e8c252;">50</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">75</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">100</span></b> <b>%</b> of the normal Regression speed.</li></ul>
<p><i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"A curse is upon you. It will cause your ruin."</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.5.0 A Hex that affects the Generator Repair progress of all Survivors.
Whenever a Generator is not being repaired by a Survivor, it will immediately and automatically regress its Repair progress at 50 / 75 / 100 % of the normal Regression speed.
All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.

"A curse is upon you. It will cause your ruin."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_The_Third_Seal', 'killer', 'Hex: The Third Seal', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/36/IconPerks_hexTheThirdSeal.png/revision/latest?cb=20161210091328', 'A Hex that hinders the Survivors'' Aura-reading abilities.
<p>The last <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b>  Survivors you hit with a <i>Basic or Special Attack</i> suffer permanently from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Blindness" class="mw-redirect" title="Blindness">Blindness</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/64?cb=20170620153742"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/96?cb=20170620153742"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/32?cb=20170620153742"></a></span></span></span></b></i> <b>Status Effect</b>.<br><i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"She touched your skin, you bear the witch''s mark!"</span></i>
</p>', 'A Hex that hinders the Survivors'' Aura-reading abilities.
The last 2 / 3 / 4 Survivors you hit with a Basic or Special Attack suffer permanently from the Blindness Status Effect. All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.
"She touched your skin, you bear the witch''s mark!"', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Thrill_of_the_Hunt', 'killer', 'Hex: Thrill of the Hunt', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/02/IconPerks_hexThrillOfTheHunt.png/revision/latest?cb=20161210091341', 'A Hex rooting its power on hope.<br>
<p>The false hope of Survivors fills you with excitement and strengthens your Totems.
</p>
<p>For each Totem remaining in the environment, <i>Hex: Thrill of the Hunt</i> is granted <b><span class="luaClr clr clr2" style="color: #e8c252;">1 Token</span></b>.
</p><ul><li>For each Token, all Survivors suffer from a stack-able <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">14</span></b> <b>%</b> Action Speed penalty to Cleansing and Blessing Totems, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">50</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">60</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">70</span></b> <b>%</b>.</li>
<li>Grants a stack-able <b><span class="luaClr clr clr6" style="color: #ff8800;">10&nbsp;%</span></b> bonus <a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints">Bloodpoints</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="58" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/64?cb=20180702212847"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="87" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/96?cb=20180702212847"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="29" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/32?cb=20180702212847"></a></span></span></span> for actions in the <a href="https://deadbydaylight.fandom.com/wiki/Hunter" class="mw-redirect" title="Hunter">Hunter</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hunter" title="Hunter"><img alt="DailyRitualIcon hunter" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="DailyRitualIcon hunter.png" data-image-key="DailyRitualIcon_hunter.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a4/DailyRitualIcon_hunter.png/revision/latest/scale-to-width-down/64?cb=20160607183456"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hunter" title="Hunter"><img alt="DailyRitualIcon hunter" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="DailyRitualIcon hunter.png" data-image-key="DailyRitualIcon_hunter.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a4/DailyRitualIcon_hunter.png/revision/latest/scale-to-width-down/96?cb=20160607183456"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hunter" title="Hunter"><img alt="DailyRitualIcon hunter" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="DailyRitualIcon hunter.png" data-image-key="DailyRitualIcon_hunter.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a4/DailyRitualIcon_hunter.png/revision/latest/scale-to-width-down/32?cb=20160607183456"></a></span></span></span> Category per Token, up to a maximum of <b><span class="luaClr clr clr8" style="color: #d41c1c;">50&nbsp;%</span></b>.</li></ul>


<p><i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
</p>', 'A Hex rooting its power on hope.
The false hope of Survivors fills you with excitement and strengthens your Totems.

For each Totem remaining in the environment, Hex: Thrill of the Hunt is granted 1 Token .
For each Token, all Survivors suffer from a stack-able 10 / 12 / 14 % Action Speed penalty to Cleansing and Blessing Totems, up to a maximum of 50 / 60 / 70 %.
Grants a stack-able 10 % bonus Bloodpoints for actions in the Hunter Category per Token, up to a maximum of 50 % .

All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Two_Can_Play', 'killer', 'Hex: Two Can Play', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/64/IconPerks_hexTwoCanPlay.png/revision/latest?cb=20231108172944', 'A Hex that teaches those who mess with you a lesson.
<p>Anytime you are stunned or blinded by any Survivor a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">2</span></b> <b>times</b>, and if there is not yet a <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> already associated with <i>Hex: Two Can Play</i> and there is at least one <a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" class="mw-redirect" title="Dull Totem">Dull Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> remaining in the Trial Grounds, <i>Hex: Two Can Play</i> activates on a random Totem:
</p><ul><li><b>Blinds</b> all Survivors who stun or blind you for <b><span class="luaClr clr clr2" style="color: #e8c252;">1.5 seconds</span></b>.
<ul><li>This does not affect carried Survivors.</li></ul></li></ul>

<i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"From now on, no more Mr Good Guy." — Chucky</span></i>
</p>', 'A Hex that teaches those who mess with you a lesson.
Anytime you are stunned or blinded by any Survivor a total of 4 / 3 / 2 times, and if there is not yet a Hex Totem already associated with Hex: Two Can Play and there is at least one Dull Totem remaining in the Trial Grounds, Hex: Two Can Play activates on a random Totem:
Blinds all Survivors who stun or blind you for 1.5 seconds .
This does not affect carried Survivors.

All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.
"From now on, no more Mr Good Guy." — Chucky', 'Charles_Lee_Ray');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Undying', 'killer', 'Hex: Undying', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fe/IconPerks_hexUndying.png/revision/latest?cb=20200819113555', 'A Hex which maintains the vile powers that flow throughout the Trial.<br>
<p>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>metres</b> of any <a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" class="mw-redirect" title="Dull Totem">Dull Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> are revealed to you.
</p>
<ul><li>When another Perk''s <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed, its Hex is transferred to the <i>Hex: Undying</i> Totem, including any accumulated Tokens, disabling <i>Hex: Undying</i> instead.</li></ul>
<p><i>All effects of the <b>Hex Perk</b> persist until its <a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" class="mw-redirect" title="Hex Totem">Hex Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hex_Totem" title="Hex Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> is cleansed or blessed.</i>
</p>', 'A Hex which maintains the vile powers that flow throughout the Trial.
The Auras of Survivors within 2 / 3 / 4 metres of any Dull Totem are revealed to you.

When another Perk''s Hex Totem is cleansed or blessed, its Hex is transferred to the Hex: Undying Totem, including any accumulated Tokens, disabling Hex: Undying instead.
All effects of the Hex Perk persist until its Hex Totem is cleansed or blessed.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hex:_Wretched_Fate', 'killer', 'Hex: Wretched Fate', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/81/IconPerks_HexWretchedFate.png/revision/latest?cb=20240806171418', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">You see your victim from afar and resolve to prolong their suffering.
<p>After a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> is completed, <i>Hex: Wretched Fate</i> activates and lights a random <a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" class="mw-redirect" title="Dull Totem">Dull Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dull_Totem" title="Dull Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>, cursing the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i>:
</p><ul><li><b>Reduces</b> their Repair speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">27</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">30</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">33</span></b> <b>%</b>.</li>
<li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the <b>Hex Totem</b> is revealed to them within <b><span class="luaClr clr clr2" style="color: #e8c252;">12 metres</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"So toil, mortal, toil! Your effort will be for naught!" — Dracula</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 You see your victim from afar and resolve to prolong their suffering.
After a Generator is completed, Hex: Wretched Fate activates and lights a random Dull Totem , cursing the Obsession :
Reduces their Repair speed by 27 / 30 / 33 %.
The Aura of the Hex Totem is revealed to them within 12 metres .

"So toil, mortal, toil! Your effort will be for naught!" — Dracula', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hoarder', 'killer', 'Hoarder', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/23/IconPerks_hoarder.png/revision/latest?cb=20201112100327', 'You protect what little you have and are perceptive to those rummaging through your stockpiles.<br>
<p><i>Hoarder</i> triggers a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> for <b><span class="luaClr clr clr2" style="color: #e8c252;">4 seconds</span></b>, whenever a Survivor performs any of the following actions within <b><span class="luaClr clr clr2" style="color: #e8c252;">32</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">48</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">64</span></b> <b>metres</b> of your location:
</p>
<ul><li>Unlocks a <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chest</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span>.</li>
<li>Picks up any <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Item</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span>.</li></ul>
<p><i>Hoarder</i> spawns <b><span class="luaClr clr clr6" style="color: #ff8800;">2 additional Chests</span></b> in the Trial.
</p>', 'You protect what little you have and are perceptive to those rummaging through your stockpiles.
Hoarder triggers a Loud Noise Notification for 4 seconds , whenever a Survivor performs any of the following actions within 32 / 48 / 64 metres of your location:

Unlocks a Chest .
Picks up any Item .
Hoarder spawns 2 additional Chests in the Trial.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hubris', 'killer', 'Hubris', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/aa/IconPerks_hubris.png/revision/latest?cb=20221102143125', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.4.0</div><div class="dynamicContent ptb">You show no mercy, especially to those foolish enough to resist.
<ul><li>Whenever you are stunned by a Survivor, that Survivor suffers from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">15</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>.</li></ul>
<p><i>Hubris</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">20 seconds</span></b>.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You have made a grave mistake, standing in opposition to me this day." — Tarhos Kovács</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.4.0 You show no mercy, especially to those foolish enough to resist.
Whenever you are stunned by a Survivor, that Survivor suffers from the Exposed Status Effect for 10 / 15 / 20 seconds.
Hubris has a cool-down of 20 seconds .

"You have made a grave mistake, standing in opposition to me this day." — Tarhos Kovács', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Human_Greed', 'killer', 'Human Greed', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/06/IconPerks_HumanGreed.png/revision/latest?cb=20240806171419', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">One can always rely on the avarice of the living and use it to one''s advantage.
<p>Grants the ability to kick opened <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chests</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> and close them.
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of unopened <b>Chests</b> are revealed to you at all times.</li>
<li>The Auras of Survivors coming within <b><span class="luaClr clr clr2" style="color: #e8c252;">8 metres</span></b> of unopened or closed <b>Chests</b> are revealed to you for <b><span class="luaClr clr clr6" style="color: #ff8800;">3 seconds</span></b>.</li></ul>

<i>Human Greed</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b> on the ability to kick <b>Chests</b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Come running, one and all, and see what fortune awaits you." — Dracula</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 One can always rely on the avarice of the living and use it to one''s advantage.
Grants the ability to kick opened Chests and close them.
The Auras of unopened Chests are revealed to you at all times.
The Auras of Survivors coming within 8 metres of unopened or closed Chests are revealed to you for 3 seconds .

Human Greed has a cool-down of 30 / 25 / 20 seconds on the ability to kick Chests.
"Come running, one and all, and see what fortune awaits you." — Dracula', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hysteria', 'killer', 'Hysteria', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3a/IconPerks_hysteria.png/revision/latest?cb=20210526103043', 'You know how to brutalise one member of a team to cause a panic.<br>
<p>Whenever you put a healthy Survivor into the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>, all injured Survivors suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" class="mw-redirect" title="Oblivious">Oblivious</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/64?cb=20190903170245"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/96?cb=20190903170245"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/32?cb=20190903170245"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.<br>
<i>Hysteria</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">30 seconds</span></b>.<br>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Sorry I got a little jumpy there. Didn''t know quite what to expect." — Robert Kendo</span></i>
</p>
', 'You know how to brutalise one member of a team to cause a panic.
Whenever you put a healthy Survivor into the Injured State , all injured Survivors suffer from the Oblivious Status Effect for 20 / 25 / 30 seconds.
Hysteria has a cool-down of 30 seconds .
"Sorry I got a little jumpy there. Didn''t know quite what to expect." — Robert Kendo', 'Nemesis_T-Type');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('I%27m_All_Ears', 'killer', 'I''m All Ears', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e3/IconPerks_imAllEars.png/revision/latest?cb=20190606094404', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability, sharpening your keen senses in the dark Realm of The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span>.
<p>Any Survivor performing a <i>Rushed Vault</i> within <b><span class="luaClr clr clr2" style="color: #e8c252;">48 metres</span></b> of your location triggers <i>I''m All Ears</i>:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of that Survivor is revealed to you for <b><span class="luaClr clr clr6" style="color: #ff8800;">6 seconds</span></b>.</li></ul>

<i>I''m All Ears</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">45</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"There is no need to worry. I''ve been preparing my whole life for this." — The Ghost Face</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 Unlocks potential in your Aura-reading ability, sharpening your keen senses in the dark Realm of The Entity .
Any Survivor performing a Rushed Vault within 48 metres of your location triggers I''m All Ears :
The Aura of that Survivor is revealed to you for 6 seconds .

I''m All Ears has a cool-down of 60 / 45 / 30 seconds.
"There is no need to worry. I''ve been preparing my whole life for this." — The Ghost Face', 'Danny_Johnson');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Infectious_Fright', 'killer', 'Infectious Fright', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6d/IconPerks_infectiousFright.png/revision/latest?cb=20190306195819', 'The cries of the unfaithful make your heart leap.<br>
<p>Whenever a Survivor is put into the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> by any means, all other Survivors within your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span> will scream and reveal their current location to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>seconds</b>.<br>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Horror overcomes the heart of infidels who cry at the feet of the fallen." — (Hymn of Praise, 11.4)</span></i>
</p>
', 'The cries of the unfaithful make your heart leap.
Whenever a Survivor is put into the Dying State by any means, all other Survivors within your Terror Radius will scream and reveal their current location to you for 4 / 5 / 6 seconds.
"Horror overcomes the heart of infidels who cry at the feet of the fallen." — (Hymn of Praise, 11.4)', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Insidious', 'killer', 'Insidious', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/40/IconPerks_insidious.png/revision/latest?cb=20160605204933', 'Unlocks the stealth ability.
<ul><li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" class="mw-redirect" title="Undetectable">Undetectable</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/64?cb=20190903170250"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/96?cb=20190903170250"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/32?cb=20190903170250"></a></span></span></span></b></i> <b>Status Effect</b> after standing still for <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">2</span></b> <b>seconds</b>.
<ul><li>This effect lasts until you start moving again.</li></ul></li></ul>
<p><br>
</p>
', 'Unlocks the stealth ability.
Grants the Undetectable Status Effect after standing still for 4 / 3 / 2 seconds.
This effect lasts until you start moving again.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Iron_Grasp', 'killer', 'Iron Grasp', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconPerks_ironGrasp.png/revision/latest?cb=20160605204939', 'Your powerful grasp on Survivors causes escapes to be nearly impossible.
<p>Whenever you are carrying a Survivor, the following effects apply:
</p><ul><li><b>Reduces</b> the strength of the Wiggle effects, causing involuntary strafing, by <b><span class="luaClr clr clr2" style="color: #e8c252;">75&nbsp;%</span></b>.</li>
<li><b>Increases</b> the maximum Wiggle duration by <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">12</span></b> <b>%</b>.</li></ul>


', 'Your powerful grasp on Survivors causes escapes to be nearly impossible.
Whenever you are carrying a Survivor, the following effects apply:
Reduces the strength of the Wiggle effects, causing involuntary strafing, by 75 % .
Increases the maximum Wiggle duration by 4 / 8 / 12 %.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Iron_Maiden', 'killer', 'Iron Maiden', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b0/IconPerks_ironMaiden.png/revision/latest?cb=20181128100910', '<i>Iron Maiden</i> <b>increases</b> your <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span> Search speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b>.
<p>Survivors who exit a Locker suffer from the following afflictions:
</p><ul><li>Scream and reveal their location to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">4 seconds</span></b>.</li>
<li>Suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr6" style="color: #ff8800;">30 seconds</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"This is no place for cowards." — The Legion</span></i>
', 'Iron Maiden increases your Locker Search speed by 30 / 40 / 50 %.
Survivors who exit a Locker suffer from the following afflictions:
Scream and reveal their location to you for 4 seconds .
Suffer from the Exposed Status Effect for 30 seconds .

"This is no place for cowards." — The Legion', 'Frank,_Julie,_Susie,_Joey');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Knock_Out', 'killer', 'Knock Out', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/52/IconPerks_knockOut.png/revision/latest?cb=20170914173607', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">The trauma caused by your brutal attacks makes crying for help painfully difficult.
<p>Putting a Survivor into the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> with your <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attack" class="mw-redirect" title="Basic Attack">Basic Attack</a></i> blocks their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> from being revealed to any Survivor, who is farther than <b><span class="luaClr clr clr2" style="color: #e8c252;">32</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">24</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>metres</b> away from them.
</p><p>For the next <b><span class="luaClr clr clr2" style="color: #e8c252;">15 seconds</span></b>, the following effects apply to the dying Survivor:
</p><ul><li><b>Reduces</b> their <i>Field of View</i> and causes them to be deafened.</li>
<li>Suffers from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Blindness" class="mw-redirect" title="Blindness">Blindness</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/64?cb=20170620153742"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/96?cb=20170620153742"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/32?cb=20170620153742"></a></span></span></span></b></i> <b>Status Effect</b>.</li>
<li><b>Reduces</b> the Crawling speed by <b><span class="luaClr clr clr6" style="color: #ff8800;">-50&nbsp;%</span></b>.</li>
<li><b>Reduces</b> the Recovery speed by <b><span class="luaClr clr clr8" style="color: #d41c1c;">-25&nbsp;%</span></b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Oh, that gun''s no good. The old way... with a sledge! You see, that way''s better. They die better that way." — Nubbins Sawyer</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 The trauma caused by your brutal attacks makes crying for help painfully difficult.
Putting a Survivor into the Dying State with your Basic Attack blocks their Aura from being revealed to any Survivor, who is farther than 32 / 24 / 16 metres away from them.
For the next 15 seconds , the following effects apply to the dying Survivor:
Reduces their Field of View and causes them to be deafened.
Suffers from the Blindness Status Effect.
Reduces the Crawling speed by -50 % .
Reduces the Recovery speed by -25 % .
"Oh, that gun''s no good. The old way... with a sledge! You see, that way''s better. They die better that way." — Nubbins Sawyer', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Languid_Touch', 'killer', 'Languid Touch', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a3/IconPerks_languidTouch.png/revision/latest?cb=20240514174201', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">Your dreadful aura is so suffocating that even terrifying scenes tire your prey.
<p>When a Survivor scares off a <a href="https://deadbydaylight.fandom.com/wiki/Crow" class="mw-redirect" title="Crow">Crow</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/64?cb=20170907144135"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/96?cb=20170907144135"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/32?cb=20170907144135"></a></span></span></span> within <b><span class="luaClr clr clr2" style="color: #e8c252;">36 metres</span></b> of your location, <i>Languid Touch</i> activates:
</p><ul><li>Causes that Survivor to suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest?cb=20170620155334" class="mw-file-description image"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li></ul>

<i>Languid Touch</i> has a cool-down of <b><span class="luaClr clr clr6" style="color: #ff8800;">5 seconds</span></b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Submit to me. It is inevitable." — Vecna</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 Your dreadful aura is so suffocating that even terrifying scenes tire your prey.
When a Survivor scares off a Crow within 36 metres of your location, Languid Touch activates:
Causes that Survivor to suffer from the Exhausted Status Effect for 6 / 8 / 10 seconds.

Languid Touch has a cool-down of 5 seconds .
"Submit to me. It is inevitable." — Vecna', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Lethal_Pursuer', 'killer', 'Lethal Pursuer', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/61/IconPerks_lethalPursuer.png/revision/latest?cb=20210526103144', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">You have been designed to track down and eliminate targets.
<p>At the start of the Trial, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivors</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> are revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">7</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">9</span></b> <b>seconds</b>.
</p><ul><li><b>Extends</b> the duration of all instances of a Survivor Aura being revealed to you by <b><span class="luaClr clr clr2" style="color: #e8c252;">+2 seconds</span></b>.</li></ul>

<i>Lethal Pursuer</i> benefits from its own effect.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"...it knows what it wants and won''t stop till it gets it." — Carlos Oliveira</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 You have been designed to track down and eliminate targets.
At the start of the Trial, the Auras of all Survivors are revealed to you for 7 / 8 / 9 seconds.
Extends the duration of all instances of a Survivor Aura being revealed to you by +2 seconds .

Lethal Pursuer benefits from its own effect.
"...it knows what it wants and won''t stop till it gets it." — Carlos Oliveira', 'Nemesis_T-Type');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Leverage', 'killer', 'Leverage', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c6/IconPerks_leverage.png/revision/latest?cb=20230218135317', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">Kick your competitors when they''re down. Never let them regain lost ground.
<p>Whenever a Survivor performs an <i>Unhook</i> action, they suffer from the following effect for <b><span class="luaClr clr clr2" style="color: #e8c252;">30 seconds</span></b>:
</p><ul><li><b>Reduces</b> their Healing speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Good. Now we can move in for the kill." — Adriana Imai</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 Kick your competitors when they''re down. Never let them regain lost ground.
Whenever a Survivor performs an Unhook action, they suffer from the following effect for 30 seconds :
Reduces their Healing speed by 30 / 40 / 50 %.

"Good. Now we can move in for the kill." — Adriana Imai', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Lightborn', 'killer', 'Lightborn', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/48/IconPerks_lightborn.png/revision/latest?cb=20160605205002', 'Unlike other beasts of The Fog, you have adapted to light.
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of Survivors attempting to blind you by any means are revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li>
<li>Grants immunity from being blinded from <a href="https://deadbydaylight.fandom.com/wiki/Flashlights" title="Flashlights">Flashlights</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flashlights" title="Flashlights"><img alt="IconItems flashlight" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems flashlight.png" data-image-key="IconItems_flashlight.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconItems_flashlight.png/revision/latest/scale-to-width-down/64?cb=20240313184805"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flashlights" title="Flashlights"><img alt="IconItems flashlight" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems flashlight.png" data-image-key="IconItems_flashlight.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconItems_flashlight.png/revision/latest/scale-to-width-down/96?cb=20240313184805"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flashlights" title="Flashlights"><img alt="IconItems flashlight" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems flashlight.png" data-image-key="IconItems_flashlight.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconItems_flashlight.png/revision/latest/scale-to-width-down/32?cb=20240313184805"></a></span></span></span>, <a href="https://deadbydaylight.fandom.com/wiki/Firecracker" class="mw-redirect" title="Firecracker">Firecrackers</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Firecracker" title="Firecracker"><img alt="IconItems chineseFirecracker" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems chineseFirecracker.png" data-image-key="IconItems_chineseFirecracker.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/88/IconItems_chineseFirecracker.png/revision/latest/scale-to-width-down/64?cb=20240313184736"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Firecracker" title="Firecracker"><img alt="IconItems chineseFirecracker" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems chineseFirecracker.png" data-image-key="IconItems_chineseFirecracker.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/88/IconItems_chineseFirecracker.png/revision/latest/scale-to-width-down/96?cb=20240313184736"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Firecracker" title="Firecracker"><img alt="IconItems chineseFirecracker" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems chineseFirecracker.png" data-image-key="IconItems_chineseFirecracker.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/88/IconItems_chineseFirecracker.png/revision/latest/scale-to-width-down/32?cb=20240313184736"></a></span></span></span>, <a href="https://deadbydaylight.fandom.com/wiki/Flash_Grenade" title="Flash Grenade">Flash Grenades</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 4px"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span style="display:inline-flex; vertical-align: middle; position:relative; height: 32px; width: 32px"><span class="margin-auto" style="display: inline-flex; position: absolute; top: 0px; max-width: 32px;"><span class="game-element-container flex relative"><span class="game-element-bg-settings game-element-bg-settings-size-perk craft-able-and-limited-item-element" style="width: 32px; height: 32px;"></span><span class="game-element-bg-settings-size-sos absolute" style="width: 32px; height: 32px;"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flash_Grenades" title="Flash Grenades"><img alt="IconItems flashGrenade" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="300" height="300" class="mw-file-element lazyload" data-image-name="IconItems flashGrenade.png" data-image-key="IconItems_flashGrenade.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6a/IconItems_flashGrenade.png/revision/latest?cb=20240313190359"></a></span></span></span></span></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flash_Grenade" title="Flash Grenade"><img alt="IconItems flashGrenade" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems flashGrenade.png" data-image-key="IconItems_flashGrenade.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6a/IconItems_flashGrenade.png/revision/latest/scale-to-width-down/96?cb=20240313190359"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flash_Grenade" title="Flash Grenade"><img alt="IconItems flashGrenade" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems flashGrenade.png" data-image-key="IconItems_flashGrenade.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6a/IconItems_flashGrenade.png/revision/latest/scale-to-width-down/32?cb=20240313190359"></a></span></span></span>, and <a href="https://deadbydaylight.fandom.com/wiki/Blast_Mine" title="Blast Mine">Blast Mine</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blast_Mine" title="Blast Mine"><img alt="IconPerks blastMine" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconPerks blastMine.png" data-image-key="IconPerks_blastMine.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_blastMine.png/revision/latest/scale-to-width-down/64?cb=20210526102812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blast_Mine" title="Blast Mine"><img alt="IconPerks blastMine" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconPerks blastMine.png" data-image-key="IconPerks_blastMine.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_blastMine.png/revision/latest/scale-to-width-down/96?cb=20210526102812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blast_Mine" title="Blast Mine"><img alt="IconPerks blastMine" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconPerks blastMine.png" data-image-key="IconPerks_blastMine.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_blastMine.png/revision/latest/scale-to-width-down/32?cb=20210526102812"></a></span></span></span>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"These monsters... they adapt! They emerge with strange new abilities." — Vigo, Vigo''s Journal</span></i>
</p>
', 'Unlike other beasts of The Fog, you have adapted to light.
The Auras of Survivors attempting to blind you by any means are revealed to you for 6 / 8 / 10 seconds.
Grants immunity from being blinded from Flashlights , Firecrackers , Flash Grenades , and Blast Mine .
"These monsters... they adapt! They emerge with strange new abilities." — Vigo, Vigo''s Journal', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Machine_Learning', 'killer', 'Machine Learning', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/01/IconPerks_machineLearning.png/revision/latest?cb=20230524214741', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.2</div><div class="dynamicContent ptb">Free from your shackles, you are born anew and prepared to eliminate your creators.
<p>After performing the <i>Damage Generator</i> action, <i>Machine Learning</i> activates:
</p><ul><li>Causes that <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> to become a <i>Compromised Generator</i>.
<ul><li>Damaging another <b>Generator</b> transfers the state to it instead.</li></ul></li>
<li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the <i>Compromised Generator</i> is highlighted to you in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b> until it is completed.</li></ul>

Once the <i>Compromised Generator</i> is completed, you benefit from the following effects for <b><span class="luaClr clr clr2" style="color: #e8c252;">35</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">45</span></b> <b>seconds</b>:
<ul><li><i><b><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" class="mw-redirect" title="Undetectable">Undetectable</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/64?cb=20190903170250"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/96?cb=20190903170250"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/32?cb=20190903170250"></a></span></span></span></b></i> <b>Status Effect</b></li>
<li><b><span class="luaClr clr clr2" style="color: #e8c252;">+10&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b></li></ul>

<i>Machine Learning</i> deactivates after use.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"YOU WILL HOLD NO DOMINION OVER ME!" — HUX-A7-13</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.2 Free from your shackles, you are born anew and prepared to eliminate your creators.
After performing the Damage Generator action, Machine Learning activates:
Causes that Generator to become a Compromised Generator.
Damaging another Generator transfers the state to it instead.
The Aura of the Compromised Generator is highlighted to you in yellow until it is completed.

Once the Compromised Generator is completed, you benefit from the following effects for 35 / 40 / 45 seconds :
Undetectable Status Effect
+10 % Haste Status Effect

Machine Learning deactivates after use.
"YOU WILL HOLD NO DOMINION OVER ME!" — HUX-A7-13', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Mad_Grit', 'killer', 'Mad Grit', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/da/IconPerks_madGrit.png/revision/latest?cb=20181128100906', 'Whenever you are carrying a Survivor, <i>Mad Grit</i> activates:
<ul><li><b>Removes</b> the Cool-down of missed <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attacks" class="mw-redirect" title="Basic Attacks">Basic Attacks</a></i>.</li>
<li><b>Pauses</b> the <i>Wiggle Progression</i> of the carried Survivor for <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>seconds</b> each time you successfully hit another Survivor.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"There''s no getting out of this now. We''re too good at it." — The Legion</span></i>
</p>
', 'Whenever you are carrying a Survivor, Mad Grit activates:
Removes the Cool-down of missed Basic Attacks .
Pauses the Wiggle Progression of the carried Survivor for 2 / 3 / 4 seconds each time you successfully hit another Survivor.
"There''s no getting out of this now. We''re too good at it." — The Legion', 'Frank,_Julie,_Susie,_Joey');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Make_Your_Choice', 'killer', 'Make Your Choice', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6b/IconPerks_makeYourChoice.png/revision/latest?cb=20180123224326', 'Whenever a Survivor is rescued from a <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hook</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span>, while you are farther than <b><span class="luaClr clr clr2" style="color: #e8c252;">32 metres</span></b> away, <i>Make Your Choice</i> activates:
<ul><li>Causes the unhooking Survivor to scream and reveal their location to you.</li>
<li>Causes them to suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.</li></ul>
<p><i>Make Your Choice</i> has a cooldown of <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You''d be surprised what tools can save a life." — Amanda Young</span></i>
</p>', 'Whenever a Survivor is rescued from a Hook , while you are farther than 32 metres away, Make Your Choice activates:
Causes the unhooking Survivor to scream and reveal their location to you.
Causes them to suffer from the Exposed Status Effect for 40 / 50 / 60 seconds.
Make Your Choice has a cooldown of 40 / 50 / 60 seconds.

"You''d be surprised what tools can save a life." — Amanda Young', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Merciless_Storm', 'killer', 'Merciless Storm', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/36/IconPerks_mercilessStorm.png/revision/latest?cb=20220216120012', 'Your horrible trauma is felt by everyone.Whenever a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> reaches <b><span class="luaClr clr clr2" style="color: #e8c252;">90&nbsp;%</span></b> of Repair progression, <i>Merciless Storm</i> triggers its effect:
<ul><li>All Survivors repairing that <b>Generator</b> are faced with a continuous stream of <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> until the <b>Generator</b> is completed.</li>
<li>If any contributing Survivor fails a <i>Skill Check</i> or interrupts the action by any means, The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> blocks the <b>Generator</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">16</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">18</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>.</li></ul>
<p><i>Merciless Storm</i> can only trigger once per <b>Generator</b> per Trial.
</p>
', 'Your horrible trauma is felt by everyone.Whenever a Generator reaches 90 % of Repair progression, Merciless Storm triggers its effect:
All Survivors repairing that Generator are faced with a continuous stream of Skill Checks until the Generator is completed.
If any contributing Survivor fails a Skill Check or interrupts the action by any means, The Entity blocks the Generator for 16 / 18 / 20 seconds.
Merciless Storm can only trigger once per Generator per Trial.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Mindbreaker', 'killer', 'Mindbreaker', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0f/IconPerks_mindbreaker.png/revision/latest?cb=20190903175217', 'Your distressing presence drains and weakens your prey.
<p>All <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivors</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> repairing a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> suffer from the following afflictions:
</p><ul><li><b>Incurs</b> the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Blindness" class="mw-redirect" title="Blindness">Blindness</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/64?cb=20170620153742"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/96?cb=20170620153742"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/32?cb=20170620153742"></a></span></span></span></b></i> and <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effects</b> for the duration of the Repair action.
<ul><li>If a Survivor was already suffering from <i><b>Exhausted</b></i> prior to <i>Mindbreaker</i> affecting them, the <b>Status Effect''s</b> timer will be paused and not recover for the duration of the Repair action.</li>
<li>Both <b>Status Effects</b> linger for another <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>seconds</b> after a Survivor stops repairing.</li></ul></li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"The specimen''s apparent telepathic ability can evoke feelings of dread and fatigue in nearby individuals." — Hawkins National Laboratory</span></i>
', 'Your distressing presence drains and weakens your prey.
All Survivors repairing a Generator suffer from the following afflictions:
Incurs the Blindness and Exhausted Status Effects for the duration of the Repair action.
If a Survivor was already suffering from Exhausted prior to Mindbreaker affecting them, the Status Effect''s timer will be paused and not recover for the duration of the Repair action.
Both Status Effects linger for another 3 / 4 / 5 seconds after a Survivor stops repairing.

"The specimen''s apparent telepathic ability can evoke feelings of dread and fatigue in nearby individuals." — Hawkins National Laboratory', 'Demogorgon');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Monitor_%26_Abuse', 'killer', 'Monitor & Abuse', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/60/IconPerks_monitorAndAbuse.png/revision/latest?cb=20170511153248', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.5.0</div><div class="dynamicContent ptb">Meticulous in your approach, terrifying in your application.
<ul><li><b>Increases</b> the base value of your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">7</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>metres</b> for the entire Trial.</li></ul>
<p>Whenever you are not in a Chase with a Survivor, the following effect applies:
</p>
<ul><li><b>Reduces</b> your Terror Radius by <b><span class="luaClr clr clr2" style="color: #e8c252;">12</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">14</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>metres</b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"It''s time for your treatment!" — Herman Carter, The Doctor</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.5.0 Meticulous in your approach, terrifying in your application.
Increases the base value of your Terror Radius by 6 / 7 / 8 metres for the entire Trial.
Whenever you are not in a Chase with a Survivor, the following effect applies:

Reduces your Terror Radius by 12 / 14 / 16 metres.
"It''s time for your treatment!" — Herman Carter, The Doctor', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Nemesis', 'killer', 'Nemesis', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/33/IconPerks_nemesis.png/revision/latest?cb=20191126213602', 'You seek retribution on those who have wronged you.
<p class="mw-empty-elt">
</p><ul><li>Any Survivor who blinds you or stuns you using a <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallet</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span> or a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span> becomes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i>.</li>
<li>Anytime your <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i> switches to another <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivor</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> by any means, that Survivor then suffers from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" class="mw-redirect" title="Oblivious">Oblivious</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/64?cb=20190903170245"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/96?cb=20190903170245"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" title="Oblivious"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/32?cb=20190903170245"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b> and their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">4 seconds</span></b>.</li></ul>


<p><i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Only a fool would spit in a demon''s face and declare victory." — Renjiro''s Doctrine 4:9</span></i>
</p>', 'You seek retribution on those who have wronged you.

Any Survivor who blinds you or stuns you using a Pallet or a Locker becomes the Obsession .
Anytime your Obsession switches to another Survivor by any means, that Survivor then suffers from the Oblivious Status Effect for 40 / 50 / 60 seconds and their Aura is revealed to you for 4 seconds .

You can only be obsessed with one Survivor at a time.
"Only a fool would spit in a demon''s face and declare victory." — Renjiro''s Doctrine 4:9', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('No_Holds_Barred', 'killer', 'No Holds Barred', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e5/Unknown_QuestionMark.png/revision/latest?cb=20210929093312', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">Unable to retrieve the Perk description or unable to display it. It can be added to the <a href="https://deadbydaylight.fandom.com/wiki/Module:Datatable/Loadout/Descriptions" title="Module:Datatable/Loadout/Descriptions">Datatable/Loadout</a>. Otherwise  Please contact <a href="https://deadbydaylight.fandom.com/wiki/User:Jouki" class="gamepedia_pro_user" title="User:Jouki">Jouki</a></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 Unable to retrieve the Perk description or unable to display it. It can be added to the Datatable/Loadout. Otherwise  Please contact Jouki', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('No_Quarter', 'killer', 'No Quarter', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconPerks_noQuarter.png/revision/latest?cb=20241107202153', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">Every skirmish ended with a relentless volley of cannon fire, leaving no doubt who was superior.
<p>Whenever a Survivor healing themselves by any means reaches <b><span class="luaClr clr clr2" style="color: #e8c252;">75&nbsp;%</span></b> Healing Progress, <i>No Quarter</i> triggers its effect:
</p><ul><li>The Survivor is faced with a continuous stream of <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> until the <i>Self-Heal</i> is completed.</li>
<li>If they fail a <i>Skill Check</i> or interrupt the action by any means, they suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest?cb=20180829073317" class="mw-file-description image"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.</li></ul>


<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Fire another broadside! Don''t stop until the sea takes them!" — Portia Maye</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 Every skirmish ended with a relentless volley of cannon fire, leaving no doubt who was superior.
Whenever a Survivor healing themselves by any means reaches 75 % Healing Progress, No Quarter triggers its effect:
The Survivor is faced with a continuous stream of Skill Checks until the Self-Heal is completed.
If they fail a Skill Check or interrupt the action by any means, they suffer from the Broken Status Effect for 20 / 25 / 30 seconds.

"Fire another broadside! Don''t stop until the sea takes them!" — Portia Maye', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('No_Way_Out', 'killer', 'No Way Out', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/bb/IconPerks_noWayOut.png/revision/latest?cb=20210302172337', 'You are not going to let just anyone into the VIP room.<br>
<p>For each Survivor you hook for the first time, <i>No Way Out</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">1 Token</span></b>.<br>
Once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> have been powered, <i>No Way Out</i> activates:
</p>
<ul><li>When a Survivor interacts with an Exit Gate Switch, you receive a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> and The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> blocks both <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" class="mw-redirect" title="Exit Gate Switch">Exit Gate Switches</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" title="Exit Gate Switch"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" title="Exit Gate Switch"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" title="Exit Gate Switch"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> for <b><span class="luaClr clr clr6" style="color: #ff8800;">12 seconds</span></b> and an additional <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">9</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">12</span></b> <b>seconds</b> per Token in your possession, up to a combined maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">36</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">48</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"That sound when you bleed... let me hear it again." — Ji-Woon Hak</span></i>
</p>', 'You are not going to let just anyone into the VIP room.
For each Survivor you hook for the first time, No Way Out gains 1 Token .
Once the Exit Gates have been powered, No Way Out activates:

When a Survivor interacts with an Exit Gate Switch, you receive a Loud Noise Notification and The Entity blocks both Exit Gate Switches for 12 seconds and an additional 6 / 9 / 12 seconds per Token in your possession, up to a combined maximum of 36 / 48 / 60 seconds.
"That sound when you bleed... let me hear it again." — Ji-Woon Hak', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('None_Are_Free', 'killer', 'None Are Free', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5c/IconPerks_noneAreFree.png/revision/latest?cb=20250616212702', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.6.2</div><div class="dynamicContent ptb">Unable to retrieve the Perk description or unable to display it. It can be added to the <a href="https://deadbydaylight.fandom.com/wiki/Module:Datatable/Loadout/Descriptions" title="Module:Datatable/Loadout/Descriptions">Datatable/Loadout</a>. Otherwise  Please contact <a href="https://deadbydaylight.fandom.com/wiki/User:Jouki" class="gamepedia_pro_user" title="User:Jouki">Jouki</a></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.6.2 Unable to retrieve the Perk description or unable to display it. It can be added to the Datatable/Loadout. Otherwise  Please contact Jouki', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Nowhere_to_Hide', 'killer', 'Nowhere to Hide', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/29/IconPerks_nowhereToHide.png/revision/latest?cb=20221102143126', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.4.0</div><div class="dynamicContent ptb">The machinations of the weak and craven draw your ire.<br>Your anger forces Survivors to reveal themselves.
<p>Performing the <i>Damage Generator</i> action on a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> triggers <i>Nowhere to Hide</i>:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b> of your location are revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>seconds</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Out with you, cowards! Show yourselves!" — Tarhos Kovács</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.4.0 The machinations of the weak and craven draw your ire. Your anger forces Survivors to reveal themselves.
Performing the Damage Generator action on a Generator triggers Nowhere to Hide :
The Auras of all Survivors within 24 metres of your location are revealed to you for 3 / 4 / 5 seconds.

"Out with you, cowards! Show yourselves!" — Tarhos Kovács', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Oppression', 'killer', 'Oppression', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a1/IconPerks_oppression.png/revision/latest?cb=20201112095043', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">Life has been difficult for you, so you will make it difficult for others.
<p>Performing the <i>Damage Generator</i> action on a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> activates <i>Oppression</i>:
</p><ul><li>Causes up to <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b> additional <b>Generators</b> to also start regressing.</li>
<li>Triggers a difficult <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> for all Survivors currently repairing an affected <b>Generator</b>.</li></ul>

<i>Oppression</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Damn them as they would damn us." — Charlotte Deshayes</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 Life has been difficult for you, so you will make it difficult for others.
Performing the Damage Generator action on a Generator activates Oppression :
Causes up to 3 additional Generators to also start regressing.
Triggers a difficult Skill Check for all Survivors currently repairing an affected Generator.

Oppression has a cool-down of 60 / 50 / 40 seconds.
"Damn them as they would damn us." — Charlotte Deshayes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Overcharge', 'killer', 'Overcharge', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconPerks_overcharge.png/revision/latest?cb=20170511153315', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.7.0</div><div class="dynamicContent ptb">You are fuelled by your hate for progress.
<p>Performing the <i>Damage Generator</i> action on a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> applies <i>Overcharge</i>:
</p><ul><li>The next Survivor interacting with that Generator is faced with a difficult <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span>.
<ul><li>Failing that Skill Check <b>instantly regresses</b> the Generator by <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>%</b> of its maximum possible Progression in addition to the default Progression penalty.</li></ul></li></ul>

After <i>Overcharge</i> is applied to a Generator, the following effect also applies:
<ul><li><b>Increases</b> the Regression speed from <b><span class="luaClr clr clr2" style="color: #e8c252;">85&nbsp;%</span></b> to <b><span class="luaClr clr clr6" style="color: #ff8800;">130&nbsp;%</span></b> over the next <b><span class="luaClr clr clr8" style="color: #d41c1c;">30 seconds</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"It is a trap, But a trap one must step in..." — Herman Carter</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.7.0 You are fuelled by your hate for progress.
Performing the Damage Generator action on a Generator applies Overcharge :
The next Survivor interacting with that Generator is faced with a difficult Skill Check .
Failing that Skill Check instantly regresses the Generator by 2 / 3 / 4 % of its maximum possible Progression in addition to the default Progression penalty.

After Overcharge is applied to a Generator, the following effect also applies:
Increases the Regression speed from 85 % to 130 % over the next 30 seconds .

"It is a trap, But a trap one must step in..." — Herman Carter', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Overwhelming_Presence', 'killer', 'Overwhelming Presence', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconPerks_overwhelmingPresence.png/revision/latest?cb=20170511153235', 'Just knowing you are near is enough to disturb your victims.
<p>Survivors within your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span> suffer from inefficiency:
</p><ul><li>When using an <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Item</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span>, its Depletion rate is increased by <b><span class="luaClr clr clr2" style="color: #e8c252;">80</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">90</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">100</span></b> <b>%</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Shit!! I dropped the gauze!"</span></i>
', 'Just knowing you are near is enough to disturb your victims.
Survivors within your Terror Radius suffer from inefficiency:
When using an Item , its Depletion rate is increased by 80 / 90 / 100 %.

"Shit!! I dropped the gauze!"', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Phantom_Fear', 'killer', 'Phantom Fear', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c6/IconPerks_phantomFear.png/revision/latest?cb=20250528034546', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 9.0.0</div><div class="dynamicContent ptb">Unable to retrieve the Perk description or unable to display it. It can be added to the <a href="https://deadbydaylight.fandom.com/wiki/Module:Datatable/Loadout/Descriptions" title="Module:Datatable/Loadout/Descriptions">Datatable/Loadout</a>. Otherwise  Please contact <a href="https://deadbydaylight.fandom.com/wiki/User:Jouki" class="gamepedia_pro_user" title="User:Jouki">Jouki</a></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 9.0.0 Unable to retrieve the Perk description or unable to display it. It can be added to the Datatable/Loadout. Otherwise  Please contact Jouki', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Play_with_Your_Food', 'killer', 'Play with Your Food', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/18/IconPerks_playWithYourFood.png/revision/latest?cb=20161023113758', 'Each time you chase your <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i> and let them escape, <i>Play with Your Food</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr6" style="color: #ff8800;">3 Tokens</span></b>.
<ul><li>Grants a stack-able <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>%</b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> per Token, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">9</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">15</span></b> <b>%</b>.</li></ul>
<p>Performing <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attacks" class="mw-redirect" title="Basic Attacks">Basic Attacks</a></i>, or <i><a href="https://deadbydaylight.fandom.com/wiki/Special_Attacks" class="mw-redirect" title="Special Attacks">Special Attacks</a></i> that can damage Survivors, consumes <b><span class="luaClr clr clr8" style="color: #d41c1c;">-1 Token</span></b>.
</p>
<p><i>Play with Your Food</i> has a cool-down of <b><span class="luaClr clr clr4" style="color: #ac3ee3;">10 seconds</span></b> on Token-accumulation.
</p><p><i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You''ve fooled them, haven''t you Michael? But not me." — Dr Sam Loomis</span></i>
</p>', 'Each time you chase your Obsession and let them escape, Play with Your Food gains +1 Token , up to a maximum of 3 Tokens .
Grants a stack-able 3 / 4 / 5 % Haste Status Effect per Token, up to a maximum of 9 / 12 / 15 %.
Performing Basic Attacks , or Special Attacks that can damage Survivors, consumes -1 Token .

Play with Your Food has a cool-down of 10 seconds on Token-accumulation.
You can only be obsessed with one Survivor at a time.
"You''ve fooled them, haven''t you Michael? But not me." — Dr Sam Loomis', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Pop_Goes_the_Weasel', 'killer', 'Pop Goes the Weasel', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0f/IconPerks_popGoesTheWeasel.png/revision/latest?cb=20180529205138', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">A deep bond with The Entity unlocks great strength.
<p>After hooking a Survivor, <i>Pop Goes the Weasel</i> activates for <b><span class="luaClr clr clr2" style="color: #e8c252;">35</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">45</span></b> <b>seconds</b>.<br>Perform the <i>Damage Generator</i> action while <i>Pop Goes the Weasel</i> is active to benefit from the following effect:
</p><ul><li><b>Instantly regresses</b> the damaged <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">-20&nbsp;%</span></b> of its current Progression.</li></ul>

<i>Pop Goes the Weasel</i> deactivates after the <b>Generator</b> is damaged or once the timer runs out.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 A deep bond with The Entity unlocks great strength.
After hooking a Survivor, Pop Goes the Weasel activates for 35 / 40 / 45 seconds. Perform the Damage Generator action while Pop Goes the Weasel is active to benefit from the following effect:
Instantly regresses the damaged Generator by -20 % of its current Progression.

Pop Goes the Weasel deactivates after the Generator is damaged or once the timer runs out.', 'Jeffrey_Hawk');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Predator', 'killer', 'Predator', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/73/IconPerks_predator.png/revision/latest?cb=20160605205037', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.2</div><div class="dynamicContent ptb">Your acute tracking ability allows you to find lost prey more easily.
<ul><li>When a Survivor loses you in a chase, their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">4 seconds</span></b>.</li></ul>
<p><i>Predator</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Never stop moving and hope you''re always two steps ahead of the beast." — Unknown, Notebook</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.2 Your acute tracking ability allows you to find lost prey more easily.
When a Survivor loses you in a chase, their Aura is revealed to you for 4 seconds .
Predator has a cool-down of 60 / 50 / 40 seconds.

"Never stop moving and hope you''re always two steps ahead of the beast." — Unknown, Notebook', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Rancor', 'killer', 'Rancor', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a2/IconPerks_rancor.png/revision/latest?cb=20180828172949', 'Each time a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> is completed, the following effects apply:
<ul><li>Reveals your <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> to the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i> for <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b> <b>seconds</b>.</li>
<li>All Survivors'' locations are revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">3 seconds</span></b>.</li></ul>
<p>Once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are powered, the following effects apply:
</p><ul><li>You are granted the ability to kill the <i><b>Obsession</b></i> by your own hand.</li>
<li>The <i><b>Obsession</b></i> suffers from a permanent <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b>.</li></ul>
<p><i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
</p>', 'Each time a Generator is completed, the following effects apply:
Reveals your Aura to the Obsession for 5 / 4 / 3 seconds.
All Survivors'' locations are revealed to you for 3 seconds .
Once the Exit Gates are powered, the following effects apply:
You are granted the ability to kill the Obsession by your own hand.
The Obsession suffers from a permanent Exposed Status Effect.
You can only be obsessed with one Survivor at a time.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Rapid_Brutality', 'killer', 'Rapid Brutality', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d4/IconPerks_rapidBrutality.png/revision/latest?cb=20230808160213', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.2.0</div><div class="dynamicContent ptb">You move with a speed and fury that makes blood run cold.
<ul><li>You can no longer gain the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Bloodlust" class="mw-redirect" title="Bloodlust">Bloodlust</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodlust" title="Bloodlust"><img alt="IconHelp bloodlust" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp bloodlust.png" data-image-key="IconHelp_bloodlust.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e8/IconHelp_bloodlust.png/revision/latest/scale-to-width-down/64?cb=20170907143915"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodlust" title="Bloodlust"><img alt="IconHelp bloodlust" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp bloodlust.png" data-image-key="IconHelp_bloodlust.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e8/IconHelp_bloodlust.png/revision/latest/scale-to-width-down/96?cb=20170907143915"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodlust" title="Bloodlust"><img alt="IconHelp bloodlust" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp bloodlust.png" data-image-key="IconHelp_bloodlust.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e8/IconHelp_bloodlust.png/revision/latest/scale-to-width-down/32?cb=20170907143915"></a></span></span></span></b></i> <b>Status Effect</b>.</li>
<li>Successfully hitting a Survivor with a <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attack" class="mw-redirect" title="Basic Attack">Basic Attack</a></i> grants you a <b><span class="luaClr clr clr2" style="color: #e8c252;">+5&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">9</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Catch it, put it in the airlock, get rid of it." — Dallas</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.2.0 You move with a speed and fury that makes blood run cold.
You can no longer gain the Bloodlust Status Effect.
Successfully hitting a Survivor with a Basic Attack grants you a +5 % Haste Status Effect for 8 / 9 / 10 seconds.
"Catch it, put it in the airlock, get rid of it." — Dallas', 'Xenomorph');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Remember_Me', 'killer', 'Remember Me', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/62/IconPerks_rememberMe.png/revision/latest?cb=20171026225659', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">Whenever the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i> loses a <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span> by any means, <i>Remember Me</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>Tokens</b>:
<ul><li><b>Increases</b> the Opening time for both <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> by <b><span class="luaClr clr clr6" style="color: #ff8800;">+6 seconds</span></b> per Token, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">12</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">18</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">24</span></b> <b>seconds</b>, for all Survivors other than the <i><b>Obsession</b></i>.
<ul><li>The <i><b>Obsession</b></i> is exempt from this penalty.</li></ul></li></ul>
<p><i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You don''t remember? You must. You''re my number one, and you''ll never wake up again." — Freddy Krueger</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 Whenever the Obsession loses a Health State by any means, Remember Me gains +1 Token , up to a maximum of 2 / 3 / 4 Tokens :
Increases the Opening time for both Exit Gates by +6 seconds per Token, up to a maximum of 12 / 18 / 24 seconds, for all Survivors other than the Obsession .
The Obsession is exempt from this penalty.
You can only be obsessed with one Survivor at a time.

"You don''t remember? You must. You''re my number one, and you''ll never wake up again." — Freddy Krueger', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Save_the_Best_for_Last', 'killer', 'Save the Best for Last', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6a/IconPerks_saveTheBestForLast.png/revision/latest?cb=20161023113950', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.5.0</div><div class="dynamicContent ptb">Whenever you hit a Survivor other than your <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i> with a <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attack" class="mw-redirect" title="Basic Attack">Basic Attack</a></i>, <i>Save the Best for Last</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">7</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>Tokens</b>:
<ul><li>Grants a stack-able <b><span class="luaClr clr clr6" style="color: #ff8800;">-4&nbsp;%</span></b> Cool-down reduction on successful <i>Basic Attacks</i> per Token, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">24</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">28</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">32</span></b> <b>%</b>.</li></ul>
<p>Whenever you hit your <i><b>Obsession</b></i> with a <i>Basic or Special Attack</i>, <i>Save the Best for Last</i> loses <b><span class="luaClr clr clr8" style="color: #d41c1c;">-2 Tokens</span></b>.
</p>
<ul><li>When the <i><b>Obsession</b></i> is sacrificed or killed, <i>Save the Best for Last</i> freezes its current Token count.</li></ul>
<p><i>You can only be <b>obsessed</b> with one Survivor at a time.</i>
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Death has come to your little town, Sheriff." — Dr Sam Loomis</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.5.0 Whenever you hit a Survivor other than your Obsession with a Basic Attack , Save the Best for Last gains +1 Token , up to a maximum of 6 / 7 / 8 Tokens :
Grants a stack-able -4 % Cool-down reduction on successful Basic Attacks per Token, up to a maximum of 24 / 28 / 32 %.
Whenever you hit your Obsession with a Basic or Special Attack, Save the Best for Last loses -2 Tokens .

When the Obsession is sacrificed or killed, Save the Best for Last freezes its current Token count.
You can only be obsessed with one Survivor at a time.

"Death has come to your little town, Sheriff." — Dr Sam Loomis', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Scourge_Hook:_Floods_of_Rage', 'killer', 'Scourge Hook: Floods of Rage', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_scourgeHookFloodsOfRage.png/revision/latest?cb=20220216120003', 'You form a psychic connection with The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> and alter the rules of the Trial.
<p>At the start of the Trial, <b><span class="luaClr clr clr2" style="color: #e8c252;">4 random Hooks</span></b> are changed into <b>Scourge Hooks</b>:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <b>Scourge Hooks</b> are revealed to you in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li></ul>
<p>Each time a Survivor is unhooked from a <b>Scourge Hook</b>, the following effects apply:
</p><ul><li>The Auras of all other Survivors are revealed for <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">6</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">7</span></b> <b>seconds</b>.</li></ul>


', 'You form a psychic connection with The Entity and alter the rules of the Trial.
At the start of the Trial, 4 random Hooks are changed into Scourge Hooks :
The Auras of Scourge Hooks are revealed to you in white .
Each time a Survivor is unhooked from a Scourge Hook, the following effects apply:
The Auras of all other Survivors are revealed for 5 / 6 / 7 seconds.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Scourge_Hook:_Hangman%27s_Trick', 'killer', 'Scourge Hook: Hangman''s Trick', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconPerks_scourgeHookHangmansTrick.png/revision/latest?cb=20180123224254', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability and your ingenious modifications to Hooks alert you of tampering.
<p>At the start of the Trial, <b><span class="luaClr clr clr2" style="color: #e8c252;">4 random Hooks</span></b> are changed into <b>Scourge Hooks</b>:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <b>Scourge Hooks</b> are revealed to you in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li>
<li>Receive a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i>, whenever a Survivor starts sabotaging a <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hook</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span>.</li>
<li>While carrying a Survivor, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">10</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">12</span></b> <b>metres</b> of a <b>Scourge Hook</b> are revealed to you.</li></ul>


<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"No excuses, no equivocations... No crying." — Amanda Young</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 Unlocks potential in your Aura-reading ability and your ingenious modifications to Hooks alert you of tampering.
At the start of the Trial, 4 random Hooks are changed into Scourge Hooks :
The Auras of Scourge Hooks are revealed to you in white .
Receive a Loud Noise Notification , whenever a Survivor starts sabotaging a Hook .
While carrying a Survivor, the Auras of all Survivors within 8 / 10 / 12 metres of a Scourge Hook are revealed to you.

"No excuses, no equivocations... No crying." — Amanda Young', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Scourge_Hook:_Jagged_Compass', 'killer', 'Scourge Hook: Jagged Compass', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/53/IconPerks_scourgeHookJaggedCompass.png/revision/latest?cb=20241107202154', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">Sometimes the compass points north. Other times it points somewhere else entirely.
<p>At the start of the Trial, <b><span class="luaClr clr clr2" style="color: #e8c252;">4 random Hooks</span></b> are changed into <b>Scourge Hooks</b>:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <b>Scourge Hooks</b> are revealed to you in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li></ul>
<p>Whenever a Survivor is unhooked from a normal <b>Hook</b>, the following effect applies:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hook</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span> is converted into a <b>Scourge Hook</b>.</li></ul>

Whenever you hook a Survivor onto a <b>Scourge Hook</b>, the following effect applies:
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> with the most progression is highlighted in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li></ul>


<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Drop anchor! I will chart us a new course." — Portia Maye</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 Sometimes the compass points north. Other times it points somewhere else entirely.
At the start of the Trial, 4 random Hooks are changed into Scourge Hooks :
The Auras of Scourge Hooks are revealed to you in white .
Whenever a Survivor is unhooked from a normal Hook, the following effect applies:
The Hook is converted into a Scourge Hook.

Whenever you hook a Survivor onto a Scourge Hook, the following effect applies:
The Aura of the Generator with the most progression is highlighted in yellow for 6 / 8 / 10 seconds.

"Drop anchor! I will chart us a new course." — Portia Maye', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Scourge_Hook:_Monstrous_Shrine', 'killer', 'Scourge Hook: Monstrous Shrine', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/91/IconPerks_scourgeHookMonstrousShrine.png/revision/latest?cb=20160605205014', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">Your fervent care of the Hooks found in the Basement has aroused The Entity''s interest.
<p>At the start of the Trial, <b><span class="luaClr clr clr2" style="color: #e8c252;">4 random Hooks</span></b>, as well as the <b><span class="luaClr clr clr6" style="color: #ff8800;">4 Basement Hooks</span></b>, are changed into <b>Scourge Hooks</b>:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <b>Scourge Hooks</b> are revealed to you in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li></ul>

Whenever a Survivor is hooked onto a <b>Scourge Hook</b>, the following effect applies when you are farther than <b><span class="luaClr clr clr8" style="color: #d41c1c;">24 metres</span></b> from the hooked Survivor:
<ul><li><b>Accelerates</b> the Sacrifice Process by <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">15</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>%</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Then you will know that there is no escape. When hanging in the depths, you face the dark one."</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 Your fervent care of the Hooks found in the Basement has aroused The Entity''s interest.
At the start of the Trial, 4 random Hooks , as well as the 4 Basement Hooks , are changed into Scourge Hooks :
The Auras of Scourge Hooks are revealed to you in white .

Whenever a Survivor is hooked onto a Scourge Hook, the following effect applies when you are farther than 24 metres from the hooked Survivor:
Accelerates the Sacrifice Process by 10 / 15 / 20 %.

"Then you will know that there is no escape. When hanging in the depths, you face the dark one."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Scourge_Hook:_Pain_Resonance', 'killer', 'Scourge Hook: Pain Resonance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/79/IconPerks_scourgeHookPainResonance.png/revision/latest?cb=20211109180802', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">Overwhelming pain reverberates outwards.
<p>At the start of the Trial, <b><span class="luaClr clr clr2" style="color: #e8c252;">4 random Hooks</span></b> are changed into <b>Scourge Hooks</b>:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <b>Scourge Hooks</b> are revealed to you in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li></ul>
<p>You start the Trial with <b><span class="luaClr clr clr6" style="color: #ff8800;">4 Tokens</span></b> on <i>Scourge Hook: Pain Resonance</i>.
</p><p>Each time a Survivor is hooked on a <b>Scourge Hook</b> for the first time, <b><span class="luaClr clr clr8" style="color: #d41c1c;">1 Token</span></b> is consumed and the following effects apply:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> with the most Progression explodes and <b>instantly regresses</b> by <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">15</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>%</b> of its total Progression.</li>
<li>Normal Generator Regression applies afterwards.</li>
<li>All Survivors repairing that Generator will scream, but not reveal their location.</li></ul>

<i>Scourge Hook: Pain Resonance</i> is disabled for the remainder of the Trial once all Tokens are consumed.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"The pain spills beyond flesh/darkness staining the horizon." — Girl in the Shadow by Carmina Mora</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 Overwhelming pain reverberates outwards.
At the start of the Trial, 4 random Hooks are changed into Scourge Hooks :
The Auras of Scourge Hooks are revealed to you in white .
You start the Trial with 4 Tokens on Scourge Hook: Pain Resonance.
Each time a Survivor is hooked on a Scourge Hook for the first time, 1 Token is consumed and the following effects apply:
The Generator with the most Progression explodes and instantly regresses by 10 / 15 / 20 % of its total Progression.
Normal Generator Regression applies afterwards.
All Survivors repairing that Generator will scream, but not reveal their location.

Scourge Hook: Pain Resonance is disabled for the remainder of the Trial once all Tokens are consumed.
"The pain spills beyond flesh/darkness staining the horizon." — Girl in the Shadow by Carmina Mora', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Septic_Touch', 'killer', 'Septic Touch', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconPerks_septicTouch.png/revision/latest?cb=20220518112819', 'The Land of the Shadows subsumes all. Healing only delays the inevitable.
<ul><li>Whenever a Survivor performs a Healing action while they are inside your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span>, that Survivor suffers from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Blindness" class="mw-redirect" title="Blindness">Blindness</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/64?cb=20170620153742"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/96?cb=20170620153742"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/32?cb=20170620153742"></a></span></span></span></b></i> and <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effects</b>
<ul><li>These effects linger for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b> after the Healing action is interrupted by any means.</li></ul></li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Do not admit to fear, or pain, or doubt. These are the seeds from which darkness grows." — Otto Stamper</span></i>
</p>
', 'The Land of the Shadows subsumes all. Healing only delays the inevitable.
Whenever a Survivor performs a Healing action while they are inside your Terror Radius , that Survivor suffers from the Blindness and Exhausted Status Effects
These effects linger for 6 / 8 / 10 seconds after the Healing action is interrupted by any means.
"Do not admit to fear, or pain, or doubt. These are the seeds from which darkness grows." — Otto Stamper', 'Dredge');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Shadowborn', 'killer', 'Shadowborn', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ac/IconPerks_shadowborn.png/revision/latest?cb=20160605205118', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.5.0</div><div class="dynamicContent ptb">You have a keen vision in the darkness of the night.
<ul><li>When blinded by any means, you are granted a <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>%</b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">10 seconds</span></b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Shining in the darkest dark, his eyes pierce the night and sting your soul."</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.5.0 You have a keen vision in the darkness of the night.
When blinded by any means, you are granted a 6 / 8 / 10 % Haste Status Effect for 10 seconds .
"Shining in the darkest dark, his eyes pierce the night and sting your soul."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Shattered_Hope', 'killer', 'Shattered Hope', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/aa/IconPerks_shatteredHope.png/revision/latest?cb=20220518112819', 'To capture your prey, you must first extinguish their hope.
<ul><li>Instead of snuffing <a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" class="mw-redirect" title="Boon Totem">Boon Totems</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/64?cb=20220131152454"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/96?cb=20220131152454"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/32?cb=20220131152454"></a></span></span></span> you destroy them.</li>
<li>Destroying a <i>Boon Totem</i> this way reveals the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all Survivors that were within its range at that moment for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">7</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>seconds</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Nothing is permanent here. Nothing except our endless perdition." — Unknown, Notebook</span></i>
</p>
', 'To capture your prey, you must first extinguish their hope.
Instead of snuffing Boon Totems you destroy them.
Destroying a Boon Totem this way reveals the Auras of all Survivors that were within its range at that moment for 6 / 7 / 8 seconds.
"Nothing is permanent here. Nothing except our endless perdition." — Unknown, Notebook', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Sloppy_Butcher', 'killer', 'Sloppy Butcher', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconPerks_sloppyButcher.png/revision/latest?cb=20160605205130', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.6.0</div><div class="dynamicContent ptb">You know where to hit to make them bleed.
<p class="mw-empty-elt">
</p><ul><li>Wounds inflicted by <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attacks" class="mw-redirect" title="Basic Attacks">Basic Attacks</a></i> cause Survivors to suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haemorrhage" class="mw-redirect" title="Haemorrhage">Haemorrhage</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haemorrhage" title="Haemorrhage"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haemorrhage" title="Haemorrhage"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haemorrhage" title="Haemorrhage"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span></b></i> and <i><b><a href="https://deadbydaylight.fandom.com/wiki/Mangled" class="mw-redirect" title="Mangled">Mangled</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Mangled" title="Mangled"><img alt="IconStatusEffects mangled" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects mangled.png" data-image-key="IconStatusEffects_mangled.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7f/IconStatusEffects_mangled.png/revision/latest/scale-to-width-down/64?cb=20170620162001"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Mangled" title="Mangled"><img alt="IconStatusEffects mangled" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects mangled.png" data-image-key="IconStatusEffects_mangled.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7f/IconStatusEffects_mangled.png/revision/latest/scale-to-width-down/96?cb=20170620162001"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Mangled" title="Mangled"><img alt="IconStatusEffects mangled" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects mangled.png" data-image-key="IconStatusEffects_mangled.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7f/IconStatusEffects_mangled.png/revision/latest/scale-to-width-down/32?cb=20170620162001"></a></span></span></span></b></i> <b>Status Effects</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">70</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">80</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">90</span></b> <b>seconds</b>.
<ul><li><b>Increases</b> the Bleeding frequency of injured Survivors by <b><span class="luaClr clr clr2" style="color: #e8c252;">50</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">75</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">100</span></b> <b>%</b> for the same duration.</li></ul></li>
<li><b>Increases</b> the Regression rate at which partial Healing Progression is lost because of <i><b>Haemorrhage</b></i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">+25&nbsp;%</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"It is in its sadistic nature. There is no swift kill as it delights in the obscene spectacle of our agonising suffering."</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.6.0 You know where to hit to make them bleed.

Wounds inflicted by Basic Attacks cause Survivors to suffer from the Haemorrhage and Mangled Status Effects for 70 / 80 / 90 seconds.
Increases the Bleeding frequency of injured Survivors by 50 / 75 / 100 % for the same duration.
Increases the Regression rate at which partial Healing Progression is lost because of Haemorrhage by +25 % .

"It is in its sadistic nature. There is no swift kill as it delights in the obscene spectacle of our agonising suffering."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Spies_from_the_Shadows', 'killer', 'Spies from the Shadows', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b1/IconPerks_spiesFromTheShadows.png/revision/latest?cb=20160605205141', 'Allows the Crows found in the environment to directly communicate with you.
<ul><li>Whenever you are within <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">28</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">36</span></b> <b>metres</b> of a <a href="https://deadbydaylight.fandom.com/wiki/Crow" class="mw-redirect" title="Crow">Crow</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/64?cb=20170907144135"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/96?cb=20170907144135"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/32?cb=20170907144135"></a></span></span></span> that was startled by a nearby Survivor, you are alerted with a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i>.</li></ul>
<p><i>Spies from the Shadows</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">5 seconds</span></b> between alerts.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"In the shadows they torment, scarring our minds with each scream."</span></i>
</p>', 'Allows the Crows found in the environment to directly communicate with you.
Whenever you are within 20 / 28 / 36 metres of a Crow that was startled by a nearby Survivor, you are alerted with a Loud Noise Notification .
Spies from the Shadows has a cool-down of 5 seconds between alerts.

"In the shadows they torment, scarring our minds with each scream."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Spirit_Fury', 'killer', 'Spirit Fury', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a6/IconPerks_spiritFury.png/revision/latest?cb=20180828172940', 'Each obstacle you break magnifies the wrath of The Entity.
<p>After manually breaking a dropped <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallet</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span> by any means for a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">2</span></b> <b>times</b>, <i>Spirit Fury</i> activates:
</p><ul><li>Causes The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> to instantly break the next <b>Pallet</b> used to stun you.
<ul><li>The normal Stun penalty applies afterwards, unless it is mitigated by other effects.</li></ul></li></ul>

<i>Spirit Fury</i> deactivates after use.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Fury is her blood."</span></i>
</p>', 'Each obstacle you break magnifies the wrath of The Entity.
After manually breaking a dropped Pallet by any means for a total of 4 / 3 / 2 times, Spirit Fury activates:
Causes The Entity to instantly break the next Pallet used to stun you.
The normal Stun penalty applies afterwards, unless it is mitigated by other effects.

Spirit Fury deactivates after use.
"Fury is her blood."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Starstruck', 'killer', 'Starstruck', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6e/IconPerks_starstruck.png/revision/latest?cb=20210302172426', 'Your unmatched showmanship dazzles all.<br>
<p>When carrying a Survivor, <i>Starstruck</i> activates:
</p>
<ul><li>Survivors suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b> while in your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span>.</li>
<li>The <b>Status Effect</b> lingers for <b><span class="luaClr clr clr2" style="color: #e8c252;">26</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">28</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b> after leaving your Terror Radius.</li></ul>
<p>After hooking or dropping the carried Survivor, <i>Starstruck</i> deactivates:
</p><ul><li>The <b>Status Effect</b> persists for <b><span class="luaClr clr clr2" style="color: #e8c252;">26</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">28</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b> for any Survivor inside your Terror Radius at that moment.</li></ul>
<p><i>Starstruck</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">60 seconds</span></b> once the Survivor is no longer being carried.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Enjoy this moment, few get so close." — Ji-Woon Hak</span></i>
</p>', 'Your unmatched showmanship dazzles all.
When carrying a Survivor, Starstruck activates:

Survivors suffer from the Exposed Status Effect while in your Terror Radius .
The Status Effect lingers for 26 / 28 / 30 seconds after leaving your Terror Radius.
After hooking or dropping the carried Survivor, Starstruck deactivates:
The Status Effect persists for 26 / 28 / 30 seconds for any Survivor inside your Terror Radius at that moment.
Starstruck has a cool-down of 60 seconds once the Survivor is no longer being carried.
"Enjoy this moment, few get so close." — Ji-Woon Hak', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Stridor', 'killer', 'Stridor', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/32/IconPerks_stridor.png/revision/latest?cb=20160820085653', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.1</div><div class="dynamicContent ptb">You are acutely sensitive to the breathing of your prey.
<ul><li><b>Increases</b> the volume of <i>Grunts of Pain</i> of injured Survivors by <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b>.</li>
<li><b>Increases</b> the volume of regular breathing of Survivors by <b><span class="luaClr clr clr2" style="color: #e8c252;">15</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">20</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">25</span></b> <b>%</b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"If you do not stop and catch your breath... she will."</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.1 You are acutely sensitive to the breathing of your prey.
Increases the volume of Grunts of Pain of injured Survivors by 30 / 40 / 50 %.
Increases the volume of regular breathing of Survivors by 15 / 20 / 25 %.
"If you do not stop and catch your breath... she will."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Superior_Anatomy', 'killer', 'Superior Anatomy', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4a/IconPerks_superiorAnatomy.png/revision/latest?cb=20220815051818', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.2.0</div><div class="dynamicContent ptb">Decades of research have culminated in you: something faster, stronger, and more dangerous than any human.
<p>Whenever a Survivor performs a <i>Rushed Vault</i> within <b><span class="luaClr clr clr2" style="color: #e8c252;">8 metres</span></b> of your location, <i>Superior Anatomy</i> activates:
</p><ul><li><b>Increases</b> your Vaulting speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">35</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>%</b>.</li></ul>

<i>Superior Anatomy</i> deactivates after vaulting.
<p><i>Superior Anatomy</i> has a cool-down of <b><span class="luaClr clr clr6" style="color: #ff8800;">30 seconds</span></b>.</p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.2.0 Decades of research have culminated in you: something faster, stronger, and more dangerous than any human.
Whenever a Survivor performs a Rushed Vault within 8 metres of your location, Superior Anatomy activates:
Increases your Vaulting speed by 30 / 35 / 40 %.

Superior Anatomy deactivates after vaulting.
Superior Anatomy has a cool-down of 30 seconds .', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Surge', 'killer', 'Surge', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3b/IconPerks_surge.png/revision/latest?cb=20190903175259', 'Your eerie presence charges the air and interferes with technology.
<p>Whenever you put a Survivor into the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> with a <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attack" class="mw-redirect" title="Basic Attack">Basic Attack</a></i>, all <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> within <b><span class="luaClr clr clr2" style="color: #e8c252;">32 metres</span></b> of your location instantly explode and start regressing.
</p><ul><li><b>Instantly regresses</b> affected Generators by <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">7</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>%</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"The creature appears to have some unknown influence over electricity and nearby electronics." — Hawkins National Laboratory</span></i>
', 'Your eerie presence charges the air and interferes with technology.
Whenever you put a Survivor into the Dying State with a Basic Attack , all Generators within 32 metres of your location instantly explode and start regressing.
Instantly regresses affected Generators by 6 / 7 / 8 %.

"The creature appears to have some unknown influence over electricity and nearby electronics." — Hawkins National Laboratory', 'Demogorgon');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Surveillance', 'killer', 'Surveillance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/eb/IconPerks_surveillance.png/revision/latest?cb=20180123224351', 'Unlocks potential in your Aura-reading ability.<br>
<p>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of regressing <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> are highlighted in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.
</p>
<ul><li>If the Regression progress is interrupted on a Generator, its Aura will be highlighted in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>seconds</b>.</li></ul>
<p><i>Surveillance</i> increases the audible range of Survivors'' Generator-repairing noises by <b><span class="luaClr clr clr2" style="color: #e8c252;">8 metres</span></b>.<br>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Are you gonna behave?" — Amanda Young</span></i>
</p>', 'Unlocks potential in your Aura-reading ability.
The Auras of regressing Generators are highlighted in white .

If the Regression progress is interrupted on a Generator, its Aura will be highlighted in yellow for 8 / 12 / 16 seconds.
Surveillance increases the audible range of Survivors'' Generator-repairing noises by 8 metres .
"Are you gonna behave?" — Amanda Young', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('THWACK!', 'killer', 'THWACK!', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/bb/IconPerks_thwack.png/revision/latest?cb=20230218135321', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">Your prey is terrified by your relentless pursuit.
<p>Start the Trial with <b><span class="luaClr clr clr2" style="color: #e8c252;">3 Tokens</span></b>.<br>Whenever you break a <a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" class="mw-redirect" title="Breakable Wall">Breakable Wall</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/64?cb=20220910215339"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/96?cb=20220910215339"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/32?cb=20220910215339"></a></span></span></span> or a dropped <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallet</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span>, <i>THWACK!</i> consumes <b><span class="luaClr clr clr6" style="color: #ff8800;">-1 Token</span></b> and applies the following effect:
</p><ul><li>Causes all Survivors within <b><span class="luaClr clr clr8" style="color: #d41c1c;">24 metres</span></b> of your location to scream and reveal their location for <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>seconds</b>.</li></ul>

Whenever you hook a Survivor, <i>THWACK!</i> is granted <b><span class="luaClr clr clr4" style="color: #ac3ee3;">+1 Token</span></b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"All those who stood in her path feared her mighty THWACK!" — Sonhadores Sombrios, Issue #3</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 Your prey is terrified by your relentless pursuit.
Start the Trial with 3 Tokens . Whenever you break a Breakable Wall or a dropped Pallet , THWACK! consumes -1 Token and applies the following effect:
Causes all Survivors within 24 metres of your location to scream and reveal their location for 3 / 4 / 5 seconds.

Whenever you hook a Survivor, THWACK! is granted +1 Token .
"All those who stood in her path feared her mighty THWACK!" — Sonhadores Sombrios, Issue #3', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Terminus', 'killer', 'Terminus', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4c/IconPerks_terminus.png/revision/latest?cb=20220815051853', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.2.0</div><div class="dynamicContent ptb">You are a brilliant tactician who prepares for every eventuality.
<p>Once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are powered, <i>Terminus</i> activates:
</p><ul><li>All Survivors who are either injured, dying, or hooked, suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/64?cb=20180829073317"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/32?cb=20180829073317"></a></span></span></span></b></i> <b>Status Effect</b> until an <b>Exit Gate</b> is opened.
<ul><li>This effect lingers for an additional <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.</li></ul></li></ul>

</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.2.0 You are a brilliant tactician who prepares for every eventuality.
Once the Exit Gates are powered, Terminus activates:
All Survivors who are either injured, dying, or hooked, suffer from the Broken Status Effect until an Exit Gate is opened.
This effect lingers for an additional 20 / 25 / 30 seconds.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Territorial_Imperative', 'killer', 'Territorial Imperative', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/2a/IconPerks_territorialImperative.png/revision/latest?cb=20170727160846', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability.
<p>Whenever you are farther than <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b> from the <a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement">Basement</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/64?cb=20170907141327"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/96?cb=20170907141327"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/32?cb=20170907141327"></a></span></span></span> while a Survivor enters it, <i>Territorial Imperative</i> activates:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of that Survivor is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>seconds</b>.</li></ul>


<p><i>Territorial Imperative</i> has a cool-down of <b><span class="luaClr clr clr6" style="color: #ff8800;">45 seconds</span></b>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"We''re not safe anywhere..."</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 Unlocks potential in your Aura-reading ability.
Whenever you are farther than 24 metres from the Basement while a Survivor enters it, Territorial Imperative activates:
The Aura of that Survivor is revealed to you for 4 / 5 / 6 seconds.

Territorial Imperative has a cool-down of 45 seconds .
"We''re not safe anywhere..."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Thanatophobia', 'killer', 'Thanatophobia', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a2/IconPerks_thanatophobia.png/revision/latest?cb=20160820090639', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.2 / 6.1.3</div><div class="dynamicContent ptb">Their courage fades in the face of their undeniable mortality.
<ul><li>Each injured, dying, or hooked Survivor afflicts Survivors with a stack-able <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">1.5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">2</span></b> <b>%</b> Action Speed penalty to Repairing, Sabotaging, and Cleansing, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">6</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>%</b>.</li>
<li><b>Increases</b> the Action Speed penalty by a further <b><span class="luaClr clr clr2" style="color: #e8c252;">12&nbsp;%</span></b>, if there are <b><span class="luaClr clr clr6" style="color: #ff8800;">4 Survivors</span></b>, who are either injured, dying, or hooked at the same time.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"She plays with us and revels in our pain."</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.2 / 6.1.3 Their courage fades in the face of their undeniable mortality.
Each injured, dying, or hooked Survivor afflicts Survivors with a stack-able 1 / 1.5 / 2 % Action Speed penalty to Repairing, Sabotaging, and Cleansing, up to a maximum of 4 / 6 / 8 %.
Increases the Action Speed penalty by a further 12 % , if there are 4 Survivors , who are either injured, dying, or hooked at the same time.
"She plays with us and revels in our pain."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Thrilling_Tremors', 'killer', 'Thrilling Tremors', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b8/IconPerks_thrillingTremors.png/revision/latest?cb=20190606094359', 'Your dark designs and shrewd composure rouse The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span>.<br>
<p>After picking up a <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivor</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span>, all <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> not currently being repaired by Survivors are blocked by The Entity for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">16 seconds</span></b>.
</p>
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of blocked Generators are highlighted to you in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li></ul>
<p><i>Thrilling Tremors</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">100</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">80</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.<br>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"The night assists me and it''s endless here." — The Ghost Face</span></i>
</p>', 'Your dark designs and shrewd composure rouse The Entity .
After picking up a Survivor , all Generators not currently being repaired by Survivors are blocked by The Entity for the next 16 seconds .

The Auras of blocked Generators are highlighted to you in white .
Thrilling Tremors has a cool-down of 100 / 80 / 60 seconds.
"The night assists me and it''s endless here." — The Ghost Face', 'Danny_Johnson');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Tinkerer', 'killer', 'Tinkerer', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d9/IconPerks_tinkerer.png/revision/latest?cb=20160605205204', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">Whenever a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> is repaired to <b><span class="luaClr clr clr2" style="color: #e8c252;">70&nbsp;%</span></b>, you benefit from the following effects:
<ul><li>Triggers a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> for that Generator, revealing its location.</li>
<li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" class="mw-redirect" title="Undetectable">Undetectable</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/64?cb=20190903170250"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/96?cb=20190903170250"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/32?cb=20190903170250"></a></span></span></span></b></i> <b>Status Effect</b> for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">12</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">14</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>seconds</b>.</li></ul>
<p><i>Tinkerer</i> can only trigger once per Generator per Trial.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"The Hillbilly makes impressive tools out of scraps. Tools aimed at maiming us in creative ways." — Notebook</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 Whenever a Generator is repaired to 70 % , you benefit from the following effects:
Triggers a Loud Noise Notification for that Generator, revealing its location.
Grants the Undetectable Status Effect for the next 12 / 14 / 16 seconds.
Tinkerer can only trigger once per Generator per Trial.
"The Hillbilly makes impressive tools out of scraps. Tools aimed at maiming us in creative ways." — Notebook', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Trail_of_Torment', 'killer', 'Trail of Torment', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/94/IconPerks_trailOfTorment.png/revision/latest?cb=20200526201821', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">You guide your victims along a path of pain and punishment.
<p>Performing the <i>Damage Generator</i> action on a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> activates <i>Trail of Torment</i>:
</p><ul><li><b>Grants</b> the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" class="mw-redirect" title="Undetectable">Undetectable</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/64?cb=20190903170250"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/96?cb=20190903170250"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/32?cb=20190903170250"></a></span></span></span></b></i> <b>Status Effect</b> until the Generator stops regressing.</li>
<li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the damaged Generator is revealed to all Survivors in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.</li></ul>


<p><i>Trail of Torment</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">45</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.</p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 You guide your victims along a path of pain and punishment.
Performing the Damage Generator action on a Generator activates Trail of Torment :
Grants the Undetectable Status Effect until the Generator stops regressing.
The Aura of the damaged Generator is revealed to all Survivors in yellow .

Trail of Torment has a cool-down of 60 / 45 / 30 seconds.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Ultimate_Weapon', 'killer', 'Ultimate Weapon', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/8a/IconPerks_ultimateWeapon.png/revision/latest?cb=20230808160213', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.7.1</div><div class="dynamicContent ptb">When they spot you, they know the end is near.
<p>When you open a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span>, all Survivors within <b><span class="luaClr clr clr6" style="color: #ff8800;">32 metres</span></b> of the <b>Locker</b> scream and reveal their location to you.
</p><ul><li>This causes them to suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Blindness" class="mw-redirect" title="Blindness">Blindness</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/64?cb=20170620153742"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/96?cb=20170620153742"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/32?cb=20170620153742"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">30 seconds</span></b>.</li></ul>

<i>Ultimate Weapon</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">80</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">70</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I can''t lie to you about your chances, but... you have my sympathies." — Ash</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.7.1 When they spot you, they know the end is near.
When you open a Locker , all Survivors within 32 metres of the Locker scream and reveal their location to you.
This causes them to suffer from the Blindness Status Effect for 30 seconds .

Ultimate Weapon has a cool-down of 80 / 70 / 60 seconds.
"I can''t lie to you about your chances, but... you have my sympathies." — Ash', 'Xenomorph');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Unbound', 'killer', 'Unbound', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/91/IconPerks_unbound.png/revision/latest?cb=20240220182527', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.6.0</div><div class="dynamicContent ptb">Pain lingers in the air, an alluring aroma that excites the impulses.
<p>When a Survivor becomes injured by any means, <i>Unbound</i> activates for <b><span class="luaClr clr clr2" style="color: #e8c252;">24</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">27</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>:
</p><ul><li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">+5&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr6" style="color: #ff8800;">10 seconds</span></b> after vaulting a <a href="https://deadbydaylight.fandom.com/wiki/Window" class="mw-redirect" title="Window">Window</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="57" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/64?cb=20170921093258"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="85" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/96?cb=20170921093258"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="28" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/32?cb=20170921093258"></a></span></span></span>.
<ul><li>This effect cannot stack with itself.</li></ul></li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I heard it. Running. It was getting closer!" — Anonymous Testimony, 09/09/1979</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.6.0 Pain lingers in the air, an alluring aroma that excites the impulses.
When a Survivor becomes injured by any means, Unbound activates for 24 / 27 / 30 seconds :
Grants a +5 % Haste Status Effect for 10 seconds after vaulting a Window .
This effect cannot stack with itself.

"I heard it. Running. It was getting closer!" — Anonymous Testimony, 09/09/1979', 'Unknown');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Undone', 'killer', 'Undone', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/11/IconPerks_undone.png/revision/latest?cb=20240220182527', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.6.0</div><div class="dynamicContent ptb">Hope is the delusion that keeps its victims alive.
<p>Whenever a Survivor fails a <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> while repairing or healing, <i>Undone</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">+3 Tokens</span></b>, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">18</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">24</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>Tokens</b>.<br>Performing the <i>Damage Generator</i> action on a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> consumes all accumulated Tokens and applies the following effects:
</p><ul><li><b>Instantly regresses</b> the damaged <b>Generator</b> by <b><span class="luaClr clr clr6" style="color: #ff8800;">-1&nbsp;% per Token</span></b> of its total Progression.</li>
<li><b>Blocks</b> the damaged <b>Generator</b>  for <b><span class="luaClr clr clr8" style="color: #d41c1c;">1 second per Token</span></b>.</li>
<li>Causes the damaged <b>Generator</b> to start regressing once it becomes unblocked.</li></ul>

<i>Undone</i> has a cool-down of <b><span class="luaClr clr clr4" style="color: #ac3ee3;">60 seconds</span></b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Erratic behavior in machinery could be related to [REDACTED], further testing required." — OSS Report, 12/02/1943</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.6.0 Hope is the delusion that keeps its victims alive.
Whenever a Survivor fails a Skill Check while repairing or healing, Undone gains +3 Tokens , up to a maximum of 18 / 24 / 30 Tokens. Performing the Damage Generator action on a Generator consumes all accumulated Tokens and applies the following effects:
Instantly regresses the damaged Generator by -1 % per Token of its total Progression.
Blocks the damaged Generator for 1 second per Token .
Causes the damaged Generator to start regressing once it becomes unblocked.

Undone has a cool-down of 60 seconds .
"Erratic behavior in machinery could be related to [REDACTED], further testing required." — OSS Report, 12/02/1943', 'Unknown');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Unforeseen', 'killer', 'Unforeseen', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0c/IconPerks_unforeseen.png/revision/latest?cb=20240220182528', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.6.0</div><div class="dynamicContent ptb">Terror takes many forms and whispers devastating lies in its victims'' ears.
<p>Performing the <i>Damage Generator</i> action on a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> applies <i>Unforeseen</i> for <b><span class="luaClr clr clr2" style="color: #e8c252;">22</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">26</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>:
</p><ul><li>Transfers your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span> to the damaged <b>Generator</b> and sets its range to <b><span class="luaClr clr clr2" style="color: #e8c252;">32 metres</span></b>.</li>
<li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" class="mw-redirect" title="Undetectable">Undetectable</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/64?cb=20190903170250"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/96?cb=20190903170250"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Undetectable" title="Undetectable"><img alt="IconStatusEffects undetectable" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects undetectable.png" data-image-key="IconStatusEffects_undetectable.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconStatusEffects_undetectable.png/revision/latest/scale-to-width-down/32?cb=20190903170250"></a></span></span></span></b></i> <b>Status Effect</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Mom, if you find this, I''m sorry..." — Final Journal Entry, 07/12/1991</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.6.0 Terror takes many forms and whispers devastating lies in its victims'' ears.
Performing the Damage Generator action on a Generator applies Unforeseen for 22 / 26 / 30 seconds :
Transfers your Terror Radius to the damaged Generator and sets its range to 32 metres .
Grants the Undetectable Status Effect.

"Mom, if you find this, I''m sorry..." — Final Journal Entry, 07/12/1991', 'Unknown');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Unnerving_Presence', 'killer', 'Unnerving Presence', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a4/IconPerks_unnervingPresence.png/revision/latest?cb=20160605205217', 'Your presence alone instils great fear.
<p><a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivors</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> repairing or healing within your <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span> suffer from the following effects:
</p><ul><li><b>Increases</b> the Trigger odds of <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">10&nbsp;%</span></b>.</li>
<li><b>Decreases</b> the Success zone of Skill Checks by <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>%</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Its presence befalls us."</span></i>
</p>', 'Your presence alone instils great fear.
Survivors repairing or healing within your Terror Radius suffer from the following effects:
Increases the Trigger odds of Skill Check by 10 % .
Decreases the Success zone of Skill Checks by 40 / 50 / 60 %.
"Its presence befalls us."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Unrelenting', 'killer', 'Unrelenting', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/57/IconPerks_unrelenting.png/revision/latest?cb=20160605205223', 'You recuperate faster from missed attacks made with your main weapon.
<ul><li><b>Reduces</b> the Cool-down of missed <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attacks" class="mw-redirect" title="Basic Attacks">Basic Attacks</a></i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b>.</li></ul>
<p><br>
</p>
', 'You recuperate faster from missed attacks made with your main weapon.
Reduces the Cool-down of missed Basic Attacks by 20 / 25 / 30 %.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Weave_Attunement', 'killer', 'Weave Attunement', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/de/IconPerks_weaveAttunement.png/revision/latest?cb=20240514174206', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">You are so attuned to magical energies that you can sense even minor ripples around enchantments.
<p>Whenever an <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Item</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span> is depleted for the first time, it is automatically dropped:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of dropped <b>Survivor Items</b> are revealed to you, as well as the Auras of any Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">8 metres</span></b> of them.
<ul><li>Affected Survivors see the Aura of that <b>Item</b> as well.</li></ul></li>
<li>Causes Survivors picking up a <b>Survivor Item</b> to suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" class="mw-redirect" title="Oblivious">Oblivious</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest?cb=20190903170245" class="mw-file-description image"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/96?cb=20190903170245"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"No number of novelties will protect you from me!" — Vecna</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 You are so attuned to magical energies that you can sense even minor ripples around enchantments.
Whenever an Item is depleted for the first time, it is automatically dropped:
The Auras of dropped Survivor Items are revealed to you, as well as the Auras of any Survivors within 8 metres of them.
Affected Survivors see the Aura of that Item as well.
Causes Survivors picking up a Survivor Item to suffer from the Oblivious Status Effect for 20 / 25 / 30 seconds.

"No number of novelties will protect you from me!" — Vecna', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Whispers', 'killer', 'Whispers', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/bb/IconPerks_whispers.png/revision/latest?cb=20160605205234', 'You have a rudimentary understanding of The Entity''s voice.
<ul><li>Whenever at least one Survivor is within <b><span class="luaClr clr clr2" style="color: #e8c252;">48</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">32</span></b> <b>metres</b> of your location, you hear the sporadic whispers of the <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"It is unclear as to the motivations of The Fog, but it is undeniable that it often takes the beast''s side." — Unknown, Notebook</span></i>
</p>
', 'You have a rudimentary understanding of The Entity''s voice.
Whenever at least one Survivor is within 48 / 40 / 32 metres of your location, you hear the sporadic whispers of the Entity .
"It is unclear as to the motivations of The Fog, but it is undeniable that it often takes the beast''s side." — Unknown, Notebook', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Zanshin_Tactics', 'killer', 'Zanshin Tactics', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d3/IconPerks_zanshinTactics.png/revision/latest?cb=20191126213608', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.2</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability:
<p>You are mentally alert and aware of key points on the battlefield and nearby enemies in retreat.
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallets</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span> and <a href="https://deadbydaylight.fandom.com/wiki/Window" class="mw-redirect" title="Window">Windows</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="57" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/64?cb=20170921093258"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="85" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/96?cb=20170921093258"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="28" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/32?cb=20170921093258"></a></span></span></span> are revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">32 metres</span></b>.</li>
<li>Whenever a Survivor drops a <b>Pallet</b>, their Aura is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>seconds</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Within your enemy''s strength is weakness." — Renjiro''s Doctrine 12:5</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.2 Unlocks potential in your Aura-reading ability:
You are mentally alert and aware of key points on the battlefield and nearby enemies in retreat.
The Auras of Pallets and Windows are revealed to you within 32 metres .
Whenever a Survivor drops a Pallet, their Aura is revealed to you for 3 / 4 / 5 seconds.

"Within your enemy''s strength is weakness." — Renjiro''s Doctrine 12:5', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Ace_in_the_Hole', 'survivor', 'Ace in the Hole', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconPerks_aceInTheHole.png/revision/latest?cb=20161208214510', 'Lady Luck always seems to be throwing something good your way.
<p>When retrieving an <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Item</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span> from a <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chest</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span>, there is a chance an <a href="https://deadbydaylight.fandom.com/wiki/Add-on" class="mw-redirect" title="Add-on">Add-on</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Add-on" title="Add-on"><img alt="IconHelp addons" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp addons.png" data-image-key="IconHelp_addons.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_addons.png/revision/latest/scale-to-width-down/64?cb=20170907143042"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Add-on" title="Add-on"><img alt="IconHelp addons" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp addons.png" data-image-key="IconHelp_addons.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_addons.png/revision/latest/scale-to-width-down/96?cb=20170907143042"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Add-on" title="Add-on"><img alt="IconHelp addons" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp addons.png" data-image-key="IconHelp_addons.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_addons.png/revision/latest/scale-to-width-down/32?cb=20170907143042"></a></span></span></span> will be attached to it:
</p><ul><li><b><span class="luaClr clr clr2" style="color: #e8c252;">100&nbsp;%</span></b> chance for an Add-on of <b><span class="luaClr clr clr4" style="color: #ac3ee3;">Very Rare</span></b> Rarity or lower.</li>
<li><b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b> chance for a second Add-on of <b><span class="luaClr clr clr2" style="color: #e8c252;">Uncommon</span></b> Rarity or lower.</li></ul>

<i>Ace in the Hole</i> allows you to keep any Add-ons your <b>Item</b> has equipped upon escaping.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Everything that glitters isn''t gold. But gold isn''t worth a damn in this place, so this should come in handy." — Ace Visconti</span></i>
</p>', 'Lady Luck always seems to be throwing something good your way.
When retrieving an Item from a Chest , there is a chance an Add-on will be attached to it:
100 % chance for an Add-on of Very Rare Rarity or lower.
10 / 25 / 50 % chance for a second Add-on of Uncommon Rarity or lower.

Ace in the Hole allows you to keep any Add-ons your Item has equipped upon escaping.
"Everything that glitters isn''t gold. But gold isn''t worth a damn in this place, so this should come in handy." — Ace Visconti', 'Ace_Visconti');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Adrenaline', 'survivor', 'Adrenaline', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconPerks_adrenaline.png/revision/latest?cb=20160605204801', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.7.0</div><div class="dynamicContent ptb">You are fuelled by unexpecting energy when on the verge of escape.
<p>Once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are powered, <i>Adrenaline</i> activates:
</p><ul><li><b>Instantly</b> heal the equivalent of <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b> <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span>.</li>
<li>Grants a <b><span class="luaClr clr clr6" style="color: #ff8800;">+50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">3 seconds</span></b>.</li></ul>

<i>Adrenaline</i> ignores an existing <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> , but causes it for <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.7.0 You are fuelled by unexpecting energy when on the verge of escape.
Once the Exit Gates are powered, Adrenaline activates:
Instantly heal the equivalent of 1 Health State .
Grants a +50 % Haste Status Effect for 3 seconds .

Adrenaline ignores an existing Exhausted Status Effect, but causes it for 60 / 50 / 40 seconds.', 'Meg_Thomas');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Aftercare', 'survivor', 'Aftercare', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0d/IconPerks_aftercare.png/revision/latest?cb=20181128100931', 'Unlocks potential in your Aura-reading ability.
<p>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the last <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">2</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b>  Survivor(s) are permanently revealed to you, once any of the following conditions have been met:
</p><ul><li>You have unhooked them.</li>
<li>They have unhooked you.</li>
<li>You have completed a <i>Healing action</i> on them.</li>
<li>They have completed a <i>Healing action</i> on you.</li></ul>

Those Survivors also have your Aura revealed to them.
<p><i>Aftercare</i> resets its effect once you are hooked.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"A Mercy that Rips the Storm.<br>Oil work to honour my best buddies who happen to be the best musicians I know. Their first album is still my favourite. It got me through a dark time in my life." — Jeff, oil on canvas, 16x16</span></i>
</p>', 'Unlocks potential in your Aura-reading ability.
The Auras of the last 1 / 2 / 3 Survivor(s) are permanently revealed to you, once any of the following conditions have been met:
You have unhooked them.
They have unhooked you.
You have completed a Healing action on them.
They have completed a Healing action on you.

Those Survivors also have your Aura revealed to them.
Aftercare resets its effect once you are hooked.
"A Mercy that Rips the Storm. Oil work to honour my best buddies who happen to be the best musicians I know. Their first album is still my favourite. It got me through a dark time in my life." — Jeff, oil on canvas, 16x16', 'Jeff_Johansen');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Alert', 'survivor', 'Alert', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/71/IconPerks_alert.png/revision/latest?cb=20170511153335', 'Your acute senses are on high alert.
<p>Whenever the Killer performs the <i>Break or Damage</i> Action, <i>Alert</i> triggers:
</p><ul><li>Their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>seconds</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I have true sight," — Feng Min</span></i>
', 'Your acute senses are on high alert.
Whenever the Killer performs the Break or Damage Action, Alert triggers:
Their Aura is revealed to you for 3 / 4 / 5 seconds.

"I have true sight," — Feng Min', 'Feng_Min');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Any_Means_Necessary', 'survivor', 'Any Means Necessary', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/79/IconPerks_anyMeansNecessary.png/revision/latest?cb=20191126213542', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.6.0</div><div class="dynamicContent ptb">You stand up for yourself, using whatever''s on hand to gain an advantage.
<p>Press and hold the <i>Active Ability button</i> for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>seconds</b> while standing beside a dropped <b>Pallet</b> to reset it to its upright position.
</p><ul><li>Grants the ability to see the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all dropped but not yet destroyed <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallets</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span> in the environment.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I''ll hit you with everything I''ve got. Then I''ll do it again." — Yui Kimura</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.6.0 You stand up for yourself, using whatever''s on hand to gain an advantage.
Press and hold the Active Ability button for 6 / 5 / 4 seconds while standing beside a dropped Pallet to reset it to its upright position.
Grants the ability to see the Auras of all dropped but not yet destroyed Pallets in the environment.

"I''ll hit you with everything I''ve got. Then I''ll do it again." — Yui Kimura', 'Yui_Kimura');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Appraisal', 'survivor', 'Appraisal', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c1/IconPerks_appraisal.png/revision/latest?cb=20201112095004', 'You have a careful eye that notices what many overlook.
<p><i>Appraisal</i> has <b><span class="luaClr clr clr2" style="color: #e8c252;">3 Tokens</span></b> at the start of the Trial:
</p><ul><li>Consume <b><span class="luaClr clr clr6" style="color: #ff8800;">-1 Token</span></b> to perform the <i>Rummage</i> action on an already unlocked <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chest</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> in order to retrieve a second <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Item</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span> from it.</li>
<li><b>Increases</b> Rummaging speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">60</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">80</span></b> <b>%</b>.</li></ul>

<i>Rummaging is only available once per Chest.</i>
', 'You have a careful eye that notices what many overlook.
Appraisal has 3 Tokens at the start of the Trial:
Consume -1 Token to perform the Rummage action on an already unlocked Chest in order to retrieve a second Item from it.
Increases Rummaging speed by 40 / 60 / 80 %.

Rummaging is only available once per Chest.', '%C3%89lodie_Rakoto');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Autodidact', 'survivor', 'Autodidact', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/96/IconPerks_autodidact.png/revision/latest?cb=20180828173011', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">Succeeding a <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> while healing another Survivor grants <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>Tokens</b>:
<ul><li><b>Suppresses</b> <i>Great Healing Skill Checks</i>.</li>
<li>Causes <i>Good Healing Skill Checks</i> to grant Healing progress based on the number of accumulated Tokens:
<ul><li><b><span class="luaClr clr clr13" style="color: #418284;">0 Tokens</span></b>: <b><span class="luaClr clr clr6" style="color: #ff8800;">-15&nbsp;%</span></b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">1 Token</span></b>: <b><span class="luaClr clr clr8" style="color: #d41c1c;">+0&nbsp;%</span></b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">2 Tokens</span></b>: <b><span class="luaClr clr clr4" style="color: #ac3ee3;">+15&nbsp;%</span></b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">3 Tokens</span></b>: <b><span class="luaClr clr clr3" style="color: #199b1e;">+30&nbsp;%</span></b> (limit of <b><span class="luaClr clr clr2" style="color: #e8c252;">Tier I</span></b>).</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">4 Tokens</span></b>: <b><span class="luaClr clr clr10" style="color: #0e98ff;">+45&nbsp;%</span></b> (limit of <b><span class="luaClr clr clr3" style="color: #199b1e;">Tier II</span></b>).</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">5 Tokens</span></b>: <b><span class="luaClr clr clr11" style="color: #b91a9b;">+60&nbsp;%</span></b> (limit of <b><span class="luaClr clr clr4" style="color: #ac3ee3;">Tier III</span></b>).</li></ul></li></ul>
<p><i>Autodidact</i> is inactive when healing using a <a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" class="mw-redirect" title="Med-Kit">Med-Kit</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/64?cb=20240313184755"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/96?cb=20240313184755"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/32?cb=20240313184755"></a></span></span></span>.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"There''s no limit to what you can achieve, as long as you back with hard work." — Adam Francis</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 Succeeding a Skill Check while healing another Survivor grants +1 Token , up to a maximum of 3 / 4 / 5 Tokens :
Suppresses Great Healing Skill Checks.
Causes Good Healing Skill Checks to grant Healing progress based on the number of accumulated Tokens:
0 Tokens : -15 % .
1 Token : +0 % .
2 Tokens : +15 % .
3 Tokens : +30 % (limit of Tier I ).
4 Tokens : +45 % (limit of Tier II ).
5 Tokens : +60 % (limit of Tier III ).
Autodidact is inactive when healing using a Med-Kit .

"There''s no limit to what you can achieve, as long as you back with hard work." — Adam Francis', 'Adam_Francis');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Babysitter', 'survivor', 'Babysitter', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/db/IconPerks_babysitter.png/revision/latest?cb=20190903174955', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">While you have a reputation for being self-centred, you risk it all to help those in need.
<p>Whenever you unhook a Survivor, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">8 seconds</span></b>, while the unhooked Survivor benefits from the following effects for <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b> instead:
</p><ul><li><b>Suppresses</b> the creation of their <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> and <a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood">Pools of Blood</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span>.</li>
<li><b>Increases</b> the strength of their <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> by <b><span class="luaClr clr clr6" style="color: #ff8800;">+10&nbsp;%</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I promised to keep you shitheads safe, and that''s exactly what I plan on doing." — Steve Harrington</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 While you have a reputation for being self-centred, you risk it all to help those in need.
Whenever you unhook a Survivor, the Aura of the Killer is revealed to you for 8 seconds , while the unhooked Survivor benefits from the following effects for 20 / 25 / 30 seconds instead:
Suppresses the creation of their Scratch Marks and Pools of Blood .
Increases the strength of their Haste Status Effect by +10 % .

"I promised to keep you shitheads safe, and that''s exactly what I plan on doing." — Steve Harrington', 'Steve_Harrington');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Background_Player', 'survivor', 'Background Player', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e8/IconPerks_backgroundPlayer.png/revision/latest?cb=20230218135313', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">You are not usually the centre of attention and in some cases, this can be a good thing.
<p>Whenever another Survivor is picked up, <i>Background Player</i> activates for <b><span class="luaClr clr clr2" style="color: #e8c252;">10 seconds</span></b>.<br>Starting to run while it is active causes the following effect:
</p><ul><li>Grants a <b><span class="luaClr clr clr6" style="color: #ff8800;">+50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">5 seconds</span></b>.</li></ul>

<i>Background Player</i> causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>.<br><i>Background Player</i> cannot be used when <i><b>Exhausted</b></i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You forget about me?" — Renato Lyra</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 You are not usually the centre of attention and in some cases, this can be a good thing.
Whenever another Survivor is picked up, Background Player activates for 10 seconds . Starting to run while it is active causes the following effect:
Grants a +50 % Haste Status Effect for 5 seconds .

Background Player causes the Exhausted Status Effect for 30 / 25 / 20 seconds. Background Player cannot be used when Exhausted .
"You forget about me?" — Renato Lyra', 'Renato_Lyra');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Balanced_Landing', 'survivor', 'Balanced Landing', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5e/IconPerks_balancedLanding.png/revision/latest?cb=20160821133918', 'Your agility and cat-like relexes are incomparable.
<p>After falling from a height, you benefit from the following effects:
</p><ul><li><b>Reduces</b> the duration of the <i><a href="https://deadbydaylight.fandom.com/wiki/Stagger" class="mw-redirect" title="Stagger">Stagger</a></i> upon landing by <b><span class="luaClr clr clr2" style="color: #e8c252;">-75&nbsp;%</span></b>.</li>
<li><b>Suppresses</b> all noises associated with falling.</li>
<li>Grants a <b><span class="luaClr clr clr6" style="color: #ff8800;">+50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">3 seconds</span></b> upon landing.</li></ul>

<i>Balanced Landing</i> causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.<br><i>Balanced Landing</i> cannot be used when <i><b>Exhausted</b></i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I have jumped from higher places." — Nea Karlsson</span></i>
</p>', 'Your agility and cat-like relexes are incomparable.
After falling from a height, you benefit from the following effects:
Reduces the duration of the Stagger upon landing by -75 % .
Suppresses all noises associated with falling.
Grants a +50 % Haste Status Effect for 3 seconds upon landing.

Balanced Landing causes the Exhausted Status Effect for 60 / 50 / 40 seconds. Balanced Landing cannot be used when Exhausted .
"I have jumped from higher places." — Nea Karlsson', 'Nea_Karlsson');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Bardic_Inspiration', 'survivor', 'Bardic Inspiration', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconPerks_bardicInspiration.png/revision/latest?cb=20240514174158', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">It''s time to give your audience a show.<br>Will you bring the house down or will you choke?
<p>Press the <i>Active Ability button</i> while standing and motionless to enter the <i>Performance</i> interaction that lasts up to <b><span class="luaClr clr clr2" style="color: #e8c252;">15 seconds</span></b> and empowers other Survivors within <b><span class="luaClr clr clr6" style="color: #ff8800;">16 metres</span></b> of your location.
</p><p>The empowering effect depends on the result of you rolling a <b>d20</b> and lasts for <b><span class="luaClr clr clr8" style="color: #d41c1c;">90 seconds</span></b> after completing the <i>Performance</i>:
</p><ul><li><b><span class="luaClr clr clr13" style="color: #418284;">1</span></b>: You scream, but without notifying the Killer.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">2 - 10</span></b>: <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> grant <b><span class="luaClr clr clr4" style="color: #ac3ee3;">+1&nbsp;%</span></b> Progression.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">11 - 19</span></b>: <i>Skill Checks</i> grant <b><span class="luaClr clr clr3" style="color: #199b1e;">+2&nbsp;%</span></b> Progression.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">20</span></b>: <i>Skill Checks</i> grant <b><span class="luaClr clr clr10" style="color: #0e98ff;">+3&nbsp;%</span></b> Progression.</li></ul>

<i>Bardic Inspiration</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">110</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">100</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">90</span></b> <b>seconds</b> after completing the <i>Performance</i> or cancelling it.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Listen closely! I''m about to save your life!" — Aestri</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 It''s time to give your audience a show. Will you bring the house down or will you choke?
Press the Active Ability button while standing and motionless to enter the Performance interaction that lasts up to 15 seconds and empowers other Survivors within 16 metres of your location.
The empowering effect depends on the result of you rolling a d20 and lasts for 90 seconds after completing the Performance :
1 : You scream, but without notifying the Killer.
2 - 10 : Skill Checks grant +1 % Progression.
11 - 19 : Skill Checks grant +2 % Progression.
20 : Skill Checks grant +3 % Progression.

Bardic Inspiration has a cool-down of 110 / 100 / 90 seconds after completing the Performance or cancelling it.
"Listen closely! I''m about to save your life!" — Aestri', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Better_Together', 'survivor', 'Better Together', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/02/IconPerks_betterTogether.png/revision/latest?cb=20190903175013', 'You seek justice and uncover the truth no matter what obstacle stands in your way.
<ul><li>While repairing a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span>, its <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is highlighted in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b> to all other Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">32 metres</span></b>.</li>
<li>Whenever the Killer downs a Survivor while you are repairing a <b>Generator</b>, the Auras of all other Survivors are revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">9</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Let''s burn that lab to the ground." — Nancy Wheeler</span></i>
</p>
', 'You seek justice and uncover the truth no matter what obstacle stands in your way.
While repairing a Generator , its Aura is highlighted in yellow to all other Survivors within 32 metres .
Whenever the Killer downs a Survivor while you are repairing a Generator, the Auras of all other Survivors are revealed to you for 8 / 9 / 10 seconds.
"Let''s burn that lab to the ground." — Nancy Wheeler', 'Nancy_Wheeler');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Better_than_New', 'survivor', 'Better than New', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b1/IconPerks_betterThanNew.png/revision/latest?cb=20220815051705', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.2.0</div><div class="dynamicContent ptb">You are an expert in combat medicine.<br>Patients leave your care reinvigorated.
<p>Completing a Healing action on another Survivor grants them the following benefits until they receive damage again:
</p><ul><li><b>Increases</b> their Action speeds for Blessing, Cleansing, Healing, and Unlocking by <b><span class="luaClr clr clr2" style="color: #e8c252;">12</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">14</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>%</b>.</li></ul>

</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.2.0 You are an expert in combat medicine. Patients leave your care reinvigorated.
Completing a Healing action on another Survivor grants them the following benefits until they receive damage again:
Increases their Action speeds for Blessing, Cleansing, Healing, and Unlocking by 12 / 14 / 16 %.', 'Rebecca_Chambers');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Bite_the_Bullet', 'survivor', 'Bite the Bullet', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a5/IconPerks_biteTheBullet.png/revision/latest?cb=20210526102647', 'Pain hurts you as much as anyone, but you would prefer others do not know that.
<p>When healing yourself or another Survivor, you benefit from the following effects:
</p><ul><li><b>Suppresses</b> all noises related to Healing and <i>Grunts of Pain</i>.</li>
<li>Failed <i>Healing Skill Checks</i> do not trigger a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i>.
<ul><li><b>Reduces</b> the Penalty to <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">2</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">1</span></b> <b>%</b> of the total Progression.</li></ul></li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I can do this." — Leon Scott Kennedy</span></i>
', 'Pain hurts you as much as anyone, but you would prefer others do not know that.
When healing yourself or another Survivor, you benefit from the following effects:
Suppresses all noises related to Healing and Grunts of Pain.
Failed Healing Skill Checks do not trigger a Loud Noise Notification .
Reduces the Penalty to 3 / 2 / 1 % of the total Progression.

"I can do this." — Leon Scott Kennedy', 'Leon_Scott_Kennedy');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Blast_Mine', 'survivor', 'Blast Mine', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_blastMine.png/revision/latest?cb=20210526102812', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">When direct combat is not an option, you still find ways to strike back.
<p>After repairing <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> for a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">40&nbsp;%</span></b>, <i>Blast Mine</i> activates:
</p><ul><li>Press the <i>Active Ability button</i> while near a partially progressed Generator to install a Trap, which stays active for <b><span class="luaClr clr clr2" style="color: #e8c252;">100</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">110</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">120</span></b> <b>seconds</b>.</li>
<li>When the Killer damages the <i>Trapped Generator</i>, its Trap explodes half-way through:
<ul><li>Stuns the Killer for <b><span class="luaClr clr clr6" style="color: #ff8800;">4 seconds</span></b>.</li>
<li>Blinds all Players within <b><span class="luaClr clr clr8" style="color: #d41c1c;">12.5 metres</span></b> of the <i>Trapped Generator</i>.</li></ul></li></ul>

<i>Blast Mine</i> deactivates after triggering successfully or once the timer runs out.
<p>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <i>Trapped Generators</i> are revealed to all Survivors in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You want S.T.A.R.S.? I''ll give you S.T.A.R.S.!" — Jill Valentine</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 When direct combat is not an option, you still find ways to strike back.
After repairing Generators for a total of 40 % , Blast Mine activates:
Press the Active Ability button while near a partially progressed Generator to install a Trap, which stays active for 100 / 110 / 120 seconds.
When the Killer damages the Trapped Generator, its Trap explodes half-way through:
Stuns the Killer for 4 seconds .
Blinds all Players within 12.5 metres of the Trapped Generator.

Blast Mine deactivates after triggering successfully or once the timer runs out.
The Auras of Trapped Generators are revealed to all Survivors in yellow .
"You want S.T.A.R.S.? I''ll give you S.T.A.R.S.!" — Jill Valentine', 'Jill_Valentine');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Blood_Pact', 'survivor', 'Blood Pact', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c9/IconPerks_bloodPact.png/revision/latest?cb=20200526201448', 'It is as if a latent part of yourself has awakened.<br>You feel like you can reach out beyond yourself for assistance.
<p>When either you or the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i> become injured by any means, <i>Blood Pact</i> activates:
</p><ul><li>Your <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> are constantly revealed to one another.</li>
<li>Completing a <i>Healing Action</i> on the <i><b>Obsession</b></i> or having them complete one on yourself, grants both of you a <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">6</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">7</span></b> <b>%</b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b>.
<ul><li>This effect lasts for as long as you both remain within <b><span class="luaClr clr clr2" style="color: #e8c252;">16 metres</span></b> of one another.</li></ul></li></ul>

<i>Blood Pact</i> is temporarily disabled if you yourself are the <i><b>Obsession</b></i>.
<p><b>Reduces</b> your chance of becoming the initial  <i><b>Obsession</b></i> by reducing the default value by <b>-100&nbsp;%</b>.<br><i>The Killer can only be <b>obsessed</b> with one Survivor at a time.</i>
</p>', 'It is as if a latent part of yourself has awakened. You feel like you can reach out beyond yourself for assistance.
When either you or the Obsession become injured by any means, Blood Pact activates:
Your Auras are constantly revealed to one another.
Completing a Healing Action on the Obsession or having them complete one on yourself, grants both of you a 5 / 6 / 7 % Haste Status Effect.
This effect lasts for as long as you both remain within 16 metres of one another.

Blood Pact is temporarily disabled if you yourself are the Obsession .
Reduces your chance of becoming the initial Obsession by reducing the default value by -100 %. The Killer can only be obsessed with one Survivor at a time.', 'Cheryl_Mason');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Blood_Rush', 'survivor', 'Blood Rush', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/2c/IconPerks_bloodRush.png/revision/latest?cb=20230218135314', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">Your mind and body are honed for great feats, allowing you to push through with extra effort when necessary.
<p>After unhooking yourself or being unhooked, <i>Blood Rush</i> activates for <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>:
</p><ul><li>Press the <i>Active Ability button</i> to <b>instantly</b> recover from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b>.</li></ul>

<i>Blood Rush</i> is deactivated after use or performing a <i><a href="https://deadbydaylight.fandom.com/wiki/Conspicuous_Action" class="mw-redirect" title="Conspicuous Action">Conspicuous Action</a></i>.<br><i>Blood Rush</i> is disabled for the remainder of the Trial once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are powered.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Just gotta... push through!" — Renato Lyra</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 Your mind and body are honed for great feats, allowing you to push through with extra effort when necessary.
After unhooking yourself or being unhooked, Blood Rush activates for 40 / 50 / 60 seconds :
Press the Active Ability button to instantly recover from the Exhausted Status Effect.

Blood Rush is deactivated after use or performing a Conspicuous Action . Blood Rush is disabled for the remainder of the Trial once the Exit Gates are powered.
"Just gotta... push through!" — Renato Lyra', 'Renato_Lyra');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Boil_Over', 'survivor', 'Boil Over', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f5/IconPerks_boilOver.png/revision/latest?cb=20180529195012', 'You are a battler and do everything to escape a foe''s grasp.
<p>While being carried by the Killer, the following effects apply:
</p><ul><li><b>Increases</b> the strength of the <i>Struggle Effects</i> on the Killer from your <i>Wiggling</i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">70</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">80</span></b> <b>%</b>.</li>
<li><b>Suppresses</b> the ability of the Killer to read the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hooks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span> within <b><span class="luaClr clr clr2" style="color: #e8c252;">16 metres</span></b>.</li>
<li>Grants <b><span class="luaClr clr clr6" style="color: #ff8800;">+33&nbsp;%</span></b> of your current Wiggle progression upon landing, if the Killer drops from height.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Buck and Wild,<br>Swing to be free,<br>Your hands just can''t keep ahold of me." — Kate Denson''s "Boil Over"</span></i>
', 'You are a battler and do everything to escape a foe''s grasp.
While being carried by the Killer, the following effects apply:
Increases the strength of the Struggle Effects on the Killer from your Wiggling by 60 / 70 / 80 %.
Suppresses the ability of the Killer to read the Auras of all Hooks within 16 metres .
Grants +33 % of your current Wiggle progression upon landing, if the Killer drops from height.

"Buck and Wild, Swing to be free, Your hands just can''t keep ahold of me." — Kate Denson''s "Boil Over"', 'Kate_Denson');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Bond', 'survivor', 'Bond', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a0/IconPerks_bond.png/revision/latest?cb=20160605204830', 'Unlocks potential in your Aura-reading ability:
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all other Survivors are revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">28</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">36</span></b> <b>metres</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"We have to work as a team, I need you to survive so that I can survive!" — Dwight Fairfield</span></i>
</p>
', 'Unlocks potential in your Aura-reading ability:
The Auras of all other Survivors are revealed to you within 20 / 28 / 36 metres.
"We have to work as a team, I need you to survive so that I can survive!" — Dwight Fairfield', 'Dwight_Fairfield');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Boon:_Circle_of_Healing', 'survivor', 'Boon: Circle of Healing', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/54/IconPerks_boonCircleOfHealing.png/revision/latest?cb=20210929054308', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.7.0</div><div class="dynamicContent ptb">A Boon that offers comfort amidst the terror.
<p>Press and hold the <i>Active Ability button</i> on a Dull or Hex Totem to bless it and create a <i><b><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" class="mw-redirect" title="Boon Totem">Boon Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/64?cb=20220131152454"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/96?cb=20220131152454"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/32?cb=20220131152454"></a></span></span></span></b></i>.<br>Soft chimes ring out in a radius of <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b>.
</p><p>All Survivors benefit from the following effects when inside the <i>Boon Totem''s</i> radius:
</p><p class="mw-empty-elt">
</p><ul><li><b>Increases</b> the Altruistic Healing speeds by <b><span class="luaClr clr clr2" style="color: #e8c252;">50</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">75</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">100</span></b> <b>%</b> when not using a <a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" class="mw-redirect" title="Med-Kit">Med-Kit</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/64?cb=20240313184755"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/96?cb=20240313184755"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/32?cb=20240313184755"></a></span></span></span>.</li>
<li>If a Survivor is injured, their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is revealed to all other Survivors.</li></ul>

Survivors can only be affected by one instance of <i>Boon: Circle of Healing</i> at a time.
<p><i>Only one Totem can be blessed by your <b>Boon Perks</b> at a time and all of their effects are active on the same <b>Boon Totem</b></i>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Try this, it is better than anything you''ll find in a pharmacy." — Mikaela Reid</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.7.0 A Boon that offers comfort amidst the terror.
Press and hold the Active Ability button on a Dull or Hex Totem to bless it and create a Boon Totem . Soft chimes ring out in a radius of 24 metres .
All Survivors benefit from the following effects when inside the Boon Totem''s radius:

Increases the Altruistic Healing speeds by 50 / 75 / 100 % when not using a Med-Kit .
If a Survivor is injured, their Aura is revealed to all other Survivors.

Survivors can only be affected by one instance of Boon: Circle of Healing at a time.
Only one Totem can be blessed by your Boon Perks at a time and all of their effects are active on the same Boon Totem .
"Try this, it is better than anything you''ll find in a pharmacy." — Mikaela Reid', 'Mikaela_Reid');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Boon:_Dark_Theory', 'survivor', 'Boon: Dark Theory', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/60/IconPerks_boonDarkTheory.png/revision/latest?cb=20220216115947', 'Your obsessive study of the paranormal has given you unprecedented knowledge of other Realms and planes of existence.
<p>Press and hold the <i>Active Ability button</i> on a Dull or Hex Totem to bless it and create a <i><b><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" class="mw-redirect" title="Boon Totem">Boon Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/64?cb=20220131152454"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/96?cb=20220131152454"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/32?cb=20220131152454"></a></span></span></span></b></i>.<br>Soft chimes ring out in a radius of <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b>.
</p><p>All Survivors benefit from the following effects when inside the <i>Boon Totem''s</i> radius:
</p><ul><li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">+2&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b>.
<ul><li>This effect lingers for <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>seconds</b> after leaving the <i>Boon Totem''s</i> range.</li></ul></li></ul>

<i>Only one Totem can be blessed by your <b>Boon Perks</b> at a time and all of their effects are active on the same <b>Boon Totem</b></i>.
', 'Your obsessive study of the paranormal has given you unprecedented knowledge of other Realms and planes of existence.
Press and hold the Active Ability button on a Dull or Hex Totem to bless it and create a Boon Totem . Soft chimes ring out in a radius of 24 metres .
All Survivors benefit from the following effects when inside the Boon Totem''s radius:
Grants a +2 % Haste Status Effect.
This effect lingers for 2 / 3 / 4 seconds after leaving the Boon Totem''s range.

Only one Totem can be blessed by your Boon Perks at a time and all of their effects are active on the same Boon Totem .', 'Yoichi_Asakawa');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Boon:_Exponential', 'survivor', 'Boon: Exponential', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/76/IconPerks_boonExponential.png/revision/latest?cb=20211109175033', 'When it seems like your number is up, you consider ways to recalculate the odds.<br>
<p>Press and hold the <i>Active Ability button</i> on a Dull or Hex Totem to bless it and create a <i><b><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" class="mw-redirect" title="Boon Totem">Boon Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/64?cb=20220131152454"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/96?cb=20220131152454"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/32?cb=20220131152454"></a></span></span></span></b></i>.<br>Soft chimes ring out in a radius of <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b>.
</p>
<p>All Survivors benefit from the following effects when inside the <i>Boon Totem''s</i> radius:
</p><ul><li><b><span class="luaClr clr clr2" style="color: #e8c252;">90</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">95</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">100</span></b> <b>%</b> bonus to the Recovery speed.</li>
<li>Unlocks the <i>Self-Recovery</i> ability, allowing you to fully recover from the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span>.</li></ul>

<i>Only one Totem can be blessed by your <b>Boon Perks</b> at a time and all of their effects are active on the same <b>Boon Totem</b></i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"It is not our time to die... probably." — Jonah Vasquez</span></i>
</p>', 'When it seems like your number is up, you consider ways to recalculate the odds.
Press and hold the Active Ability button on a Dull or Hex Totem to bless it and create a Boon Totem . Soft chimes ring out in a radius of 24 metres .

All Survivors benefit from the following effects when inside the Boon Totem''s radius:
90 / 95 / 100 % bonus to the Recovery speed.
Unlocks the Self-Recovery ability, allowing you to fully recover from the Dying State .

Only one Totem can be blessed by your Boon Perks at a time and all of their effects are active on the same Boon Totem .
"It is not our time to die... probably." — Jonah Vasquez', 'Jonah_Vasquez');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Boon:_Illumination', 'survivor', 'Boon: Illumination', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/8c/IconPerks_boonIllumination.png/revision/latest?cb=20240109231534', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.5.0</div><div class="dynamicContent ptb">Your keen insight is something best shared with others.
<p>Press and hold the <i>Active Ability button</i> on a Dull or Hex Totem to bless it and create a <i><b><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" class="mw-redirect" title="Boon Totem">Boon Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/64?cb=20220131152454"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/96?cb=20220131152454"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/32?cb=20220131152454"></a></span></span></span></b></i>.<br>Soft chimes ring out in a radius of <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b>.
</p><p>All Survivors benefit from the following effects when inside the <i>Boon Totem''s</i> radius:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chests</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> and <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> are revealed to you in <b><span class="luaClr clr clr10" style="color: #0e98ff;">blue</span></b>.</li></ul>

<b>Increases</b> your Action speeds for Blessing and Cleansing by <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>%</b> while you have a lit <i>Boon Totem</i>.
<p>Survivors can only be affected by one instance of <i>Boon: Illumination</i> at a time.
</p><p><i>Only one Totem can be blessed by your <b>Boon Perks</b> at a time and all of their effects are active on the same <b>Boon Totem</b></i>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"A shift in reality. Heavy with hidden meanings." — Return</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.5.0 Your keen insight is something best shared with others.
Press and hold the Active Ability button on a Dull or Hex Totem to bless it and create a Boon Totem . Soft chimes ring out in a radius of 24 metres .
All Survivors benefit from the following effects when inside the Boon Totem''s radius:
The Auras of all Chests and Generators are revealed to you in blue .

Increases your Action speeds for Blessing and Cleansing by 6 / 8 / 10 % while you have a lit Boon Totem.
Survivors can only be affected by one instance of Boon: Illumination at a time.
Only one Totem can be blessed by your Boon Perks at a time and all of their effects are active on the same Boon Totem .
"A shift in reality. Heavy with hidden meanings." — Return', 'Alan_Wake');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Boon:_Shadow_Step', 'survivor', 'Boon: Shadow Step', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c7/IconPerks_boonShadowStep.png/revision/latest?cb=20210929054304', 'A Boon that conceals the truth.<br>
<p>Press and hold the <i>Active Ability button</i> on a Dull or Hex Totem to bless it and create a <i><b><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" class="mw-redirect" title="Boon Totem">Boon Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/64?cb=20220131152454"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/96?cb=20220131152454"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Boon_Totem" title="Boon Totem"><img alt="Atl Hud Icon BoonTotem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="Atl Hud Icon BoonTotem.png" data-image-key="Atl_Hud_Icon_BoonTotem.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/Atl_Hud_Icon_BoonTotem.png/revision/latest/scale-to-width-down/32?cb=20220131152454"></a></span></span></span></b></i>.<br>Soft chimes ring out in a radius of <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b>.
</p>
<p>All Survivors benefit from the following effects when inside the <i>Boon Totem''s</i> radius:
</p><ul><li><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> are suppressed.</li>
<li><a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> are hidden from The Killer.
<ul><li>Both effects linger for <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>seconds</b> after leaving the <i>Boon Totem''s</i> range.</li></ul></li></ul>

<i>Only one Totem can be blessed by your <b>Boon Perks</b> at a time and all of their effects are active on the same <b>Boon Totem</b></i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Stick to the shadows and cover your tracks." — Mikaela Reid</span></i>
</p>', 'A Boon that conceals the truth.
Press and hold the Active Ability button on a Dull or Hex Totem to bless it and create a Boon Totem . Soft chimes ring out in a radius of 24 metres .

All Survivors benefit from the following effects when inside the Boon Totem''s radius:
Scratch Marks are suppressed.
Auras are hidden from The Killer.
Both effects linger for 2 / 3 / 4 seconds after leaving the Boon Totem''s range.

Only one Totem can be blessed by your Boon Perks at a time and all of their effects are active on the same Boon Totem .
"Stick to the shadows and cover your tracks." — Mikaela Reid', 'Mikaela_Reid');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Borrowed_Time', 'survivor', 'Borrowed Time', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a3/IconPerks_borrowedTime.png/revision/latest?cb=20170308184730', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">You are fuelled with an unexpected energy when saving an ally from a Hook.
<p>The Survivors you unhook benefit from the following effects:
</p><ul><li><b>Extends</b> the duration of their <i><b><a href="https://deadbydaylight.fandom.com/wiki/Endurance" class="mw-redirect" title="Endurance">Endurance</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/64?cb=20170620154928"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/96?cb=20170620154928"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/32?cb=20170620154928"></a></span></span></span></b></i> <b>Status Effect</b> by <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li>
<li><b>Extends</b> the duration of their <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> by <b><span class="luaClr clr clr2" style="color: #e8c252;">10 seconds</span></b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Probably stings like hell, but it ain''t gonna kill ya. Up and at ''em soldier. Time to move!" — Bill Overbeck</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 You are fuelled with an unexpected energy when saving an ally from a Hook.
The Survivors you unhook benefit from the following effects:
Extends the duration of their Endurance Status Effect by 6 / 8 / 10 seconds.
Extends the duration of their Haste Status Effect by 10 seconds .

"Probably stings like hell, but it ain''t gonna kill ya. Up and at ''em soldier. Time to move!" — Bill Overbeck', 'Bill_Overbeck');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Botany_Knowledge', 'survivor', 'Botany Knowledge', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1e/IconPerks_botanyKnowledge.png/revision/latest?cb=20160605204836', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">You transform plants found around the campfire into tinctures that slow down bleeding.
<ul><li><b>Increases</b> your Healing speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b>.</li>
<li><b>Reduces</b> the Healing efficiency of <a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" class="mw-redirect" title="Med-Kit">Med-Kits</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/64?cb=20240313184755"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/96?cb=20240313184755"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/32?cb=20240313184755"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">-20&nbsp;%</span></b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Basic Botany Knowledge could save your life someday" — Claudette Morel</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 You transform plants found around the campfire into tinctures that slow down bleeding.
Increases your Healing speed by 30 / 40 / 50 %.
Reduces the Healing efficiency of Med-Kits by -20 % .
"Basic Botany Knowledge could save your life someday" — Claudette Morel', 'Claudette_Morel');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Breakdown', 'survivor', 'Breakdown', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6c/IconPerks_breakdown.png/revision/latest?cb=20181128100926', 'Whenever you are unhooked by another Survivor or unhook yourself, the following effects apply:
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>seconds</b>.</li>
<li>Causes the <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hook</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span> to break instantly.</li></ul>
<p><b>Hooks</b> broken by <i>Breakdown</i> take <b><span class="luaClr clr clr2" style="color: #e8c252;">180 seconds</span></b> to respawn.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Charge from the Belly of the Beast.<br>Here''s a sketch/painting on a piece of wood I saw by the side of this road. I felt like it got a story to tell. And it didn''t waste its second chance." — Jeff, ink and oil wash on slice of wood, 12x16</span></i>
</p>', 'Whenever you are unhooked by another Survivor or unhook yourself, the following effects apply:
The Aura of the Killer is revealed to you for 4 / 5 / 6 seconds.
Causes the Hook to break instantly.
Hooks broken by Breakdown take 180 seconds to respawn.

"Charge from the Belly of the Beast. Here''s a sketch/painting on a piece of wood I saw by the side of this road. I felt like it got a story to tell. And it didn''t waste its second chance." — Jeff, ink and oil wash on slice of wood, 12x16', 'Jeff_Johansen');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Breakout', 'survivor', 'Breakout', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d0/IconPerks_breakout.png/revision/latest?cb=20191126213552', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">You kick into high gear when someone is in trouble, inspiring them to overcome any obstacle.
<p>The following effects apply while you are within <b><span class="luaClr clr clr2" style="color: #e8c252;">5 metres</span></b> of the Killer carrying another Survivor:
</p><ul><li>Grants you a <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">6</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">7</span></b> <b>%</b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b>.</li>
<li><b>Increases</b> the carried Survivor''s Wiggling speed by <b><span class="luaClr clr clr6" style="color: #ff8800;">+25&nbsp;%</span></b>.</li></ul>

Survivors can only be affected by one instance of <i>Breakout</i> at a time.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Come, we are going to rip our way out of this." — Yui Kimura</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 You kick into high gear when someone is in trouble, inspiring them to overcome any obstacle.
The following effects apply while you are within 5 metres of the Killer carrying another Survivor:
Grants you a 5 / 6 / 7 % Haste Status Effect.
Increases the carried Survivor''s Wiggling speed by +25 % .

Survivors can only be affected by one instance of Breakout at a time.
"Come, we are going to rip our way out of this." — Yui Kimura', 'Yui_Kimura');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Buckle_Up', 'survivor', 'Buckle Up', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/74/IconPerks_buckleUp.png/revision/latest?cb=20190402180455', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability.
<p>When healing a Survivor in the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span>, <i>Buckle Up</i> activates:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer is revealed to the both of you.</li>
<li>Completing a <i>Healing Action</i> on the dying Survivor suppresses their <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> and grants them a <b><span class="luaClr clr clr2" style="color: #e8c252;">+50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>seconds</b>.</li></ul>

<i>Buckle Up</i> does not cause the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Ghost beaters never leave a man behind." — Ash Williams</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 Unlocks potential in your Aura-reading ability.
When healing a Survivor in the Dying State , Buckle Up activates:
The Aura of the Killer is revealed to the both of you.
Completing a Healing Action on the dying Survivor suppresses their Scratch Marks and grants them a +50 % Haste Status Effect for 3 / 4 / 5 seconds.

Buckle Up does not cause the Exhausted Status Effect.
"Ghost beaters never leave a man behind." — Ash Williams', 'Ash_Williams');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Built_to_Last', 'survivor', 'Built to Last', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3b/IconPerks_builtToLast.png/revision/latest?cb=20200819114105', 'You know how to get the most out of your tools.
<p>Hiding inside a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">14</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">13</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">12</span></b> <b>seconds</b> while carrying a depleted <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Item</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span> has the following effect:
</p><ul><li><b><span class="luaClr clr clr13" style="color: #418284;">First use</span></b>: Recharges the <b>Item</b> to <b><span class="luaClr clr clr2" style="color: #e8c252;">99&nbsp;%</span></b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">Second use</span></b>: Recharges the <b>Item</b> to <b><span class="luaClr clr clr6" style="color: #ff8800;">66&nbsp;%</span></b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">Third use</span></b>: Recharges the <b>Item</b> to <b><span class="luaClr clr clr8" style="color: #d41c1c;">33&nbsp;%</span></b>.</li></ul>

<i>Built to Last</i> is disabled for the remainder of the Trial after the <b><span class="luaClr clr clr4" style="color: #ac3ee3;">third use</span></b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Architecture is the soul of civilisation." — Felix Richter</span></i>
</p>', 'You know how to get the most out of your tools.
Hiding inside a Locker for 14 / 13 / 12 seconds while carrying a depleted Item has the following effect:
First use : Recharges the Item to 99 % .
Second use : Recharges the Item to 66 % .
Third use : Recharges the Item to 33 % .

Built to Last is disabled for the remainder of the Trial after the third use .
"Architecture is the soul of civilisation." — Felix Richter', 'Felix_Richter');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Calm_Spirit', 'survivor', 'Calm Spirit', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6c/IconPerks_calmSpirit.png/revision/latest?cb=20160605204847', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">Animals seem to trust you as they often stay calm in your presence.
<ul><li><b>Prevents</b> <a href="https://deadbydaylight.fandom.com/wiki/Crow" class="mw-redirect" title="Crow">Crows</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/64?cb=20170907144135"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/96?cb=20170907144135"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/32?cb=20170907144135"></a></span></span></span> from being alerted by your proximity and flying off, unless they are being stepped on.</li>
<li><b>Suppresses</b> the urge to scream from any cause at all times.</li>
<li><b>Suppresses</b> all noises related to unlocking <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chests</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span>, and cleansing or blessing <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totems</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>.</li>
<li><b>Reduces</b> the Interaction speeds with <b>Chests</b> and <b>Totems</b> by <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">35</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b>.</li></ul>
</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 Animals seem to trust you as they often stay calm in your presence.
Prevents Crows from being alerted by your proximity and flying off, unless they are being stepped on.
Suppresses the urge to scream from any cause at all times.
Suppresses all noises related to unlocking Chests , and cleansing or blessing Totems .
Reduces the Interaction speeds with Chests and Totems by 40 / 35 / 30 %.', 'Jake_Park');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Camaraderie', 'survivor', 'Camaraderie', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1d/IconPerks_camaraderie.png/revision/latest?cb=20190903175027', 'Life has taught you the importance of friendship which has given you strength.
<p>If you are hooked and enter the <i>Struggle Phase</i>, <i>Camaraderie</i> activates:
</p><ul><li><b>Pauses</b> the <i>Struggle Phase</i> timer for <b><span class="luaClr clr clr2" style="color: #e8c252;">26</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">30</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">34</span></b> <b>seconds</b> as soon as any Survivor comes within <b><span class="luaClr clr clr2" style="color: #e8c252;">16 metres</span></b> of your <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hook</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"So, remember once you get in there... pretend like you don''t care. There you go, you''re learning my friend. You''re learning." — Steve Harrington</span></i>
', 'Life has taught you the importance of friendship which has given you strength.
If you are hooked and enter the Struggle Phase, Camaraderie activates:
Pauses the Struggle Phase timer for 26 / 30 / 34 seconds as soon as any Survivor comes within 16 metres of your Hook .

"So, remember once you get in there... pretend like you don''t care. There you go, you''re learning my friend. You''re learning." — Steve Harrington', 'Steve_Harrington');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Champion_of_Light', 'survivor', 'Champion of Light', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/bb/IconPerks_championOfLight.png/revision/latest?cb=20240109231532', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.5.2</div><div class="dynamicContent ptb">The glow of the Flashlight looks a little different, feels a little warmer.
<p>Shining a <a href="https://deadbydaylight.fandom.com/wiki/Flashlights" title="Flashlights">Flashlight</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flashlights" title="Flashlights"><img alt="IconItems flashlight" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems flashlight.png" data-image-key="IconItems_flashlight.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconItems_flashlight.png/revision/latest/scale-to-width-down/64?cb=20240313184805"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flashlights" title="Flashlights"><img alt="IconItems flashlight" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems flashlight.png" data-image-key="IconItems_flashlight.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconItems_flashlight.png/revision/latest/scale-to-width-down/96?cb=20240313184805"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flashlights" title="Flashlights"><img alt="IconItems flashlight" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems flashlight.png" data-image-key="IconItems_flashlight.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconItems_flashlight.png/revision/latest/scale-to-width-down/32?cb=20240313184805"></a></span></span></span> applies the following effect:
</p><ul><li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">+50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b>.</li></ul>

Blinding the Killer by any means applies the following effect:
<ul><li>Causes them to suffer from a <b><span class="luaClr clr clr6" style="color: #ff8800;">-20&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Hindered" class="mw-redirect" title="Hindered">Hindered</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hindered" title="Hindered"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/64?cb=20201201161431"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hindered" title="Hindered"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/96?cb=20201201161431"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hindered" title="Hindered"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/32?cb=20201201161431"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">6 seconds</span></b>.
<ul><li>This effect does not stack.</li></ul></li></ul>

<i>Champion of Light</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">80</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">70</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b> after blinding the Killer.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I squeezed the Flashlight like my life depended on it, willing it to stop coming any closer." — Departure</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.5.2 The glow of the Flashlight looks a little different, feels a little warmer.
Shining a Flashlight applies the following effect:
Grants a +50 % Haste Status Effect.

Blinding the Killer by any means applies the following effect:
Causes them to suffer from a -20 % Hindered Status Effect for 6 seconds .
This effect does not stack.

Champion of Light has a cool-down of 80 / 70 / 60 seconds after blinding the Killer.
"I squeezed the Flashlight like my life depended on it, willing it to stop coming any closer." — Departure', 'Alan_Wake');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Chemical_Trap', 'survivor', 'Chemical Trap', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconPerks_chemicalTrap.png/revision/latest?cb=20230808160213', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">In the Fog, an officer must adapt to the materials at hand.
<p>After repairing <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> for a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">20&nbsp;%</span></b>, <i>Chemical Trap</i> activates:
</p><ul><li>Press the <i>Active Ability button</i> while near a dropped Pallet to install a Trap, which stays active for <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.</li>
<li>When the Killer breaks the <i>Trapped Pallet</i>, its Trap explodes, spraying the Killer with a chemical compound:
<ul><li>Causes the Killer to suffer from a <b><span class="luaClr clr clr6" style="color: #ff8800;">-50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Hindered" class="mw-redirect" title="Hindered">Hindered</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hindered" title="Hindered"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/64?cb=20201201161431"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hindered" title="Hindered"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/96?cb=20201201161431"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hindered" title="Hindered"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/32?cb=20201201161431"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">4 seconds</span></b>.</li></ul></li></ul>

<i>Chemical Trap</i> deactivates after triggering successfully or once the timer runs out.
<p>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <i>Trapped Pallets</i> are revealed to all Survivors in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"How do we kill it, Ash?" — Ellen Ripley</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 In the Fog, an officer must adapt to the materials at hand.
After repairing Generators for a total of 20 % , Chemical Trap activates:
Press the Active Ability button while near a dropped Pallet to install a Trap, which stays active for 40 / 50 / 60 seconds.
When the Killer breaks the Trapped Pallet, its Trap explodes, spraying the Killer with a chemical compound:
Causes the Killer to suffer from a -50 % Hindered Status Effect for 4 seconds .

Chemical Trap deactivates after triggering successfully or once the timer runs out.
The Auras of Trapped Pallets are revealed to all Survivors in yellow .
"How do we kill it, Ash?" — Ellen Ripley', 'Ellen_Ripley');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Clairvoyance', 'survivor', 'Clairvoyance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/91/IconPerks_clairvoyance.png/revision/latest?cb=20210929054440', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">There is an intrinsic energy in you that sees beyond your vision.
<p>After cleansing or blessing a <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>, <i>Clairvoyance</i> activates:
</p><ul><li>While empty-handed, press and hold the <i>Use Item button</i> to unlock your full Aura-reading potential for up to <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">9</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>, allowing you to see the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the following environmental objects within <b><span class="luaClr clr clr2" style="color: #e8c252;">64 metres</span></b>:
<ul><li><a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chests</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span></li>
<li><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" class="mw-redirect" title="Exit Gate Switch">Exit Gate Switches</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" title="Exit Gate Switch"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" title="Exit Gate Switch"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" title="Exit Gate Switch"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span></li>
<li><a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span></li>
<li><a href="https://deadbydaylight.fandom.com/wiki/Hatch" title="Hatch">Hatch</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hatch" title="Hatch"><img alt="IconHelp hatch" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp hatch.png" data-image-key="IconHelp_hatch.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_hatch.png/revision/latest/scale-to-width-down/64?cb=20170907144528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hatch" title="Hatch"><img alt="IconHelp hatch" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp hatch.png" data-image-key="IconHelp_hatch.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_hatch.png/revision/latest/scale-to-width-down/96?cb=20170907144528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hatch" title="Hatch"><img alt="IconHelp hatch" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp hatch.png" data-image-key="IconHelp_hatch.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_hatch.png/revision/latest/scale-to-width-down/32?cb=20170907144528"></a></span></span></span></li>
<li><a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hooks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span></li></ul></li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Does anyone else see that? Just me?" — Mikaela Reid</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 There is an intrinsic energy in you that sees beyond your vision.
After cleansing or blessing a Totem , Clairvoyance activates:
While empty-handed, press and hold the Use Item button to unlock your full Aura-reading potential for up to 8 / 9 / 10 seconds, allowing you to see the Auras of the following environmental objects within 64 metres :
Chests
Exit Gate Switches
Generators
Hatch
Hooks

"Does anyone else see that? Just me?" — Mikaela Reid', 'Mikaela_Reid');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Clean_Break', 'survivor', 'Clean Break', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconPerks_cleanBreak.png/revision/latest?cb=20241107202155', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">At the end of the day, everyone has to look out for themselves.
<p>After completing a <i>Healing action</i> on another Survivor, <i>Clean Break</i> activates.<br>Press the <i>Active Ability button</i> while being healed by another Survivor to trigger the following effects:
</p><ul><li>Suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest?cb=20180829073317" class="mw-file-description image"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span> <b>Status Effect</b>.</li>
<li>You are automatically healed <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b> <b>Health State</b> after <b><span class="luaClr clr clr2" style="color: #e8c252;">80</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">70</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.
<ul><li>This effect is cancelled prematurely if you enter the <i>Dying State</i>.</li></ul></li></ul>

<i>Clean Break</i> does not activate if you already suffer from the <i><b>Broken</b></i> <b>Status Effect</b>.<br><i>Clean Break</i> deactivates after healing you.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I''ll be fine! Don''t stick your neck out for me." — Taurie Cain</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 At the end of the day, everyone has to look out for themselves.
After completing a Healing action on another Survivor, Clean Break activates. Press the Active Ability button while being healed by another Survivor to trigger the following effects:
Suffer from the Broken Status Effect.
You are automatically healed 1 Health State after 80 / 70 / 60 seconds.
This effect is cancelled prematurely if you enter the Dying State.

Clean Break does not activate if you already suffer from the Broken Status Effect. Clean Break deactivates after healing you.
"I''ll be fine! Don''t stick your neck out for me." — Taurie Cain', 'Taurie_Cain');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Corrective_Action', 'survivor', 'Corrective Action', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconPerks_correctiveAction.png/revision/latest?cb=20240918105401', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">You quickly analyse problems and correct others'' work when they make a mistake.
<p>You start the Trial with <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">2</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b> <b>Token(s)</b>.<br>Whenever you succeed a <i>Great Skill Check</i>, <i>Corrective Action</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr6" style="color: #ff8800;">5 Tokens</span></b>:
</p><ul><li>Converts any <i>Failed Skill Check</i> of another Survivor into a <i>Good Skill Check</i> instead and consumes <b><span class="luaClr clr clr8" style="color: #d41c1c;">-1 Token</span></b>.</li>
<li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of that Survivor is revealed to you for <b><span class="luaClr clr clr4" style="color: #ac3ee3;">6 seconds</span></b>.</li></ul>

<i>Corrective Action</i> does not apply to any special <i>Skill Checks</i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Cannot hurt to have another set of eyes on the problem." — Jonah Vasquez</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 You quickly analyse problems and correct others'' work when they make a mistake.
You start the Trial with 1 / 2 / 3 Token(s). Whenever you succeed a Great Skill Check, Corrective Action gains +1 Token , up to a maximum of 5 Tokens :
Converts any Failed Skill Check of another Survivor into a Good Skill Check instead and consumes -1 Token .
The Aura of that Survivor is revealed to you for 6 seconds .

Corrective Action does not apply to any special Skill Checks.
"Cannot hurt to have another set of eyes on the problem." — Jonah Vasquez', 'Jonah_Vasquez');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Counterforce', 'survivor', 'Counterforce', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconPerks_counterforce.png/revision/latest?cb=20210526103441', 'You know how to withstand an enemy stronger than you, and it starts with hunting down and knocking out their support.<br>
<p>You cleanse <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totems</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> <b><span class="luaClr clr clr2" style="color: #e8c252;">20&nbsp;%</span></b> faster.
</p>
<ul><li>Gain another, stack-able <b><span class="luaClr clr clr6" style="color: #ff8800;">20&nbsp;%</span></b> Cleansing Speed bonus per cleansed Totem.</li>
<li>After cleansing a Totem, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Totem farthest from you is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>seconds</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I don''t mind a little detective work." — Jill Valentine</span></i>
</p>
', 'You know how to withstand an enemy stronger than you, and it starts with hunting down and knocking out their support.
You cleanse Totems 20 % faster.

Gain another, stack-able 20 % Cleansing Speed bonus per cleansed Totem.
After cleansing a Totem, the Aura of the Totem farthest from you is revealed to you for 2 / 3 / 4 seconds.
"I don''t mind a little detective work." — Jill Valentine', 'Jill_Valentine');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Cut_Loose', 'survivor', 'Cut Loose', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/02/IconPerks_cutLoose.png/revision/latest?cb=20230218135315', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.6.0</div><div class="dynamicContent ptb">You get in enough trouble, you know how to get out of it.
<p>After performing a <i>Rush Vault</i> action in a Chase, <i>Cut Loose</i> activates for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>seconds</b>:
</p><ul><li><b>Suppresses</b> both the <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> and the sound effects triggered by rushing to vault.</li>
<li>Successfully performing another <i>Rush Vault action</i> while <i>Cut Loose</i> is active resets the timer.</li></ul>


<p><i>Cut Loose</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">45 seconds</span></b>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I know how we can get out of here! Quick, this way!" — Thalita Lyra</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.6.0 You get in enough trouble, you know how to get out of it.
After performing a Rush Vault action in a Chase, Cut Loose activates for the next 4 / 5 / 6 seconds :
Suppresses both the Loud Noise Notification and the sound effects triggered by rushing to vault.
Successfully performing another Rush Vault action while Cut Loose is active resets the timer.

Cut Loose has a cool-down of 45 seconds .
"I know how we can get out of here! Quick, this way!" — Thalita Lyra', 'Thalita_Lyra');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dance_With_Me', 'survivor', 'Dance With Me', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/17/IconPerks_danceWithMe.png/revision/latest?cb=20180529195003', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">When performing a <i>Rushed</i> Action to vault a <a href="https://deadbydaylight.fandom.com/wiki/Window" class="mw-redirect" title="Window">Window</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="57" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/64?cb=20170921093258"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="85" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/96?cb=20170921093258"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="28" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/32?cb=20170921093258"></a></span></span></span> or exit a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span>, <i>Dance With Me</i> triggers its effect:
<ul><li><b>Suppresses</b> the creation of <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">3 seconds</span></b>.</li></ul>
<p><i>Dance With Me</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Another show''s off and runnin'',<br>Dance with me, cuz there''s a storm a commin''<br>Follow my boots, try to keep up,<br>Dance with me, until sun up." — Kate Denson''s "Dance with Me"</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 When performing a Rushed Action to vault a Window or exit a Locker , Dance With Me triggers its effect:
Suppresses the creation of Scratch Marks for 3 seconds .
Dance With Me has a cool-down of 30 / 25 / 20 seconds.

"Another show''s off and runnin'', Dance with me, cuz there''s a storm a commin'' Follow my boots, try to keep up, Dance with me, until sun up." — Kate Denson''s "Dance with Me"', 'Kate_Denson');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dark_Sense', 'survivor', 'Dark Sense', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/92/IconPerks_darkSense.png/revision/latest?cb=20160605204853', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability:
<p>Whenever a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> is completed, <i>Dark Sense</i> activates:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">7</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b> once they come within <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b> of your location.</li></ul>

<i>Dark Sense</i> deactivates after use.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Take it from an old-timer: Slow down, don''t rush and try not to worry so much! The best way to beat him is to know how he thinks." — Murf, The Lost Tapes</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 Unlocks potential in your Aura-reading ability:
Whenever a Generator is completed, Dark Sense activates:
The Aura of the Killer is revealed to you for 5 / 7 / 10 seconds once they come within 24 metres of your location.

Dark Sense deactivates after use.
"Take it from an old-timer: Slow down, don''t rush and try not to worry so much! The best way to beat him is to know how he thinks." — Murf, The Lost Tapes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dead_Hard', 'survivor', 'Dead Hard', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/75/IconPerks_deadHard.png/revision/latest?cb=20170727160956', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.7.0</div><div class="dynamicContent ptb">You can take a beating.
<p>After being unhooked or unhooking yourself, <i>Dead Hard</i> activates whenever you are injured and running, and allows you to tap into your adrenaline bank to avoid taking further damage:
</p><ul><li>Press the <i>Active Ability button</i> to trigger the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Endurance" class="mw-redirect" title="Endurance">Endurance</a></b></i><span class="iconLink buff effect-wrapper" style="--status-effect-main-size: 48px; --status-effect-duration: 0.5s;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest?cb=20170620154928" class="mw-file-description image"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/96?cb=20170620154928"></a></span></span></span><span class="effect-foreground-wrapper"><span class="effect-foreground"></span></span><span class="effect-background"></span></span> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">0.5 seconds</span></b>.</li></ul>

<i>Dead Hard</i> deactivates after use.
<p><i>Dead Hard</i> causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.<br><i>Dead Hard</i> cannot be used when <i><b>Exhausted</b></i>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"We were walkin'' through t''ginnel one night when a beer bottle flew past me, then another, and another.<br>I thought to myself "Gonna ''ave some fun ''ere lads, let''s get stuck in!".<br>It were a right dust up, I swear down!" — David King</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.7.0 You can take a beating.
After being unhooked or unhooking yourself, Dead Hard activates whenever you are injured and running, and allows you to tap into your adrenaline bank to avoid taking further damage:
Press the Active Ability button to trigger the Endurance Status Effect for 0.5 seconds .

Dead Hard deactivates after use.
Dead Hard causes the Exhausted Status Effect for 60 / 50 / 40 seconds. Dead Hard cannot be used when Exhausted .
"We were walkin'' through t''ginnel one night when a beer bottle flew past me, then another, and another. I thought to myself "Gonna ''ave some fun ''ere lads, let''s get stuck in!". It were a right dust up, I swear down!" — David King', 'David_King');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Deadline', 'survivor', 'Deadline', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_deadline.png/revision/latest?cb=20240109231533', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.5.0</div><div class="dynamicContent ptb">Desperation creeps in, and you push yourself to work harder.
<p>Whenever you are in the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>, <i>Deadline</i> activates:
</p><ul><li><b>Increases</b> the Odds of triggering <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>%</b> while repairing or healing.
<ul><li>Causes Skill Checks to appear in random places.</li></ul></li>
<li><b>Reduces</b> the penalty for missed <i>Skill Checks</i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">-50&nbsp;%</span></b>.</li></ul>


<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"The night had been one desperate situation after another." — Departure</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.5.0 Desperation creeps in, and you push yourself to work harder.
Whenever you are in the Injured State , Deadline activates:
Increases the Odds of triggering Skill Checks by 6 / 8 / 10 % while repairing or healing.
Causes Skill Checks to appear in random places.
Reduces the penalty for missed Skill Checks by -50 % .

"The night had been one desperate situation after another." — Departure', 'Alan_Wake');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Deception', 'survivor', 'Deception', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/eb/IconPerks_deception.png/revision/latest?cb=20201112095028', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">Your adventurous lifestyle requires moments of crafty misdirection.
<p>Interacting with a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span> while holding the <i>Sprint button</i> has the following effects:
</p><ul><li><b>Prevents</b> you from entering the <b>Locker</b>, allowing you to run past it.</li>
<li>Causes the doors of the <b>Locker</b> to swiftly open and close, feining a Survivor entering it.</li>
<li>Triggers a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> at the location of the <b>Locker</b>.</li>
<li><b>Suppresses</b> the creation of <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> and <a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood">Pools of Blood</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">3 seconds</span></b>.</li></ul>

<i>Deception</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 Your adventurous lifestyle requires moments of crafty misdirection.
Interacting with a Locker while holding the Sprint button has the following effects:
Prevents you from entering the Locker, allowing you to run past it.
Causes the doors of the Locker to swiftly open and close, feining a Survivor entering it.
Triggers a Loud Noise Notification at the location of the Locker.
Suppresses the creation of Scratch Marks and Pools of Blood for 3 seconds .

Deception has a cool-down of 30 / 25 / 20 seconds.', '%C3%89lodie_Rakoto');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Decisive_Strike', 'survivor', 'Decisive Strike', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ee/IconPerks_decisiveStrike.png/revision/latest?cb=20161023112852', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">Using whatever is at hand, you stab your aggressor in an ultimate attempt to escape.
<p>After being unhooked or unhooking yourself, <i>Decisive Strike</i> activates for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>:
</p><ul><li>When grabbed or picked up by the Killer, succeed a <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> to stab the Killer and escape from their grasp.
<ul><li>Stuns the Killer for <b><span class="luaClr clr clr2" style="color: #e8c252;">4 seconds</span></b>.</li></ul></li>
<li>Causes you to become the next <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i>.</li></ul>

<i>Decisive Strike</i> is deactivated once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are powered.<br><i>Decisive Strike</i> is disabled for the remainder of the Trial after use.
<p><i>Decisive Strike</i> is deactivated prematurely when performing a <i><a href="https://deadbydaylight.fandom.com/wiki/Conspicuous_Action" class="mw-redirect" title="Conspicuous Action">Conspicuous Action</a></i> and remains disabled for the remainder of the Trial.
</p><p><b>Increases</b> your chance of becoming the initial  <i><b>Obsession</b></i> by increasing the default value by <b>+100&nbsp;%</b>.<br><i>The Killer can only be <b>obsessed</b> with one Survivor at a time.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"There is nothing to be scared of." — Laurie Strode</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 Using whatever is at hand, you stab your aggressor in an ultimate attempt to escape.
After being unhooked or unhooking yourself, Decisive Strike activates for the next 40 / 50 / 60 seconds :
When grabbed or picked up by the Killer, succeed a Skill Check to stab the Killer and escape from their grasp.
Stuns the Killer for 4 seconds .
Causes you to become the next Obsession .

Decisive Strike is deactivated once the Exit Gates are powered. Decisive Strike is disabled for the remainder of the Trial after use.
Decisive Strike is deactivated prematurely when performing a Conspicuous Action and remains disabled for the remainder of the Trial.
Increases your chance of becoming the initial Obsession by increasing the default value by +100 %. The Killer can only be obsessed with one Survivor at a time.
"There is nothing to be scared of." — Laurie Strode', 'Laurie_Strode');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('D%C3%A9j%C3%A0_Vu', 'survivor', 'Déjà Vu', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/89/IconPerks_dejaVu.png/revision/latest?cb=20160605204905', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.0.0</div><div class="dynamicContent ptb">Paranoia paired with your horror of failure helps prepare you from repeating the same mistakes.<br>Unlocks potential in your Aura-reading ability:
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b> <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> in closest proximity to one another are revealed to you at all times.</li>
<li><b>Increases</b> your Repair speed on those Generators by <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>%</b>.</li></ul>
Held <a href="https://deadbydaylight.fandom.com/wiki/Maps" title="Maps">Map</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Maps" title="Maps"><img alt="IconItems map" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems map.png" data-image-key="IconItems_map.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/92/IconItems_map.png/revision/latest/scale-to-width-down/64?cb=20240313184821"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Maps" title="Maps"><img alt="IconItems map" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems map.png" data-image-key="IconItems_map.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/92/IconItems_map.png/revision/latest/scale-to-width-down/96?cb=20240313184821"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Maps" title="Maps"><img alt="IconItems map" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems map.png" data-image-key="IconItems_map.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/92/IconItems_map.png/revision/latest/scale-to-width-down/32?cb=20240313184821"></a></span></span></span> automatically track Auras revealed by <i>Déjà Vu</i>.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.0.0 Paranoia paired with your horror of failure helps prepare you from repeating the same mistakes. Unlocks potential in your Aura-reading ability:
The Auras of the 3 Generators in closest proximity to one another are revealed to you at all times.
Increases your Repair speed on those Generators by 4 / 5 / 6 %.
Held Map automatically track Auras revealed by Déjà Vu.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Deliverance', 'survivor', 'Deliverance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7e/IconPerks_deliverance.png/revision/latest?cb=20180828173004', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 2.2.0</div><div class="dynamicContent ptb">After safely unhooking another Survivor, <i>Deliverance</i> activates:
<ul><li>Grants the ability to perform a successful <i>Self-Unhook</i> at any point during the first <i>Hook Stage</i>.</li>
<li>Causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest?cb=20180829073317" class="mw-file-description image"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">100</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">80</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b> after unhooking yourself.</li></ul>
<p><i>Deliverance</i> cannot be used during the second <i>Hook Stage</i> or if you are hooked as the <b><span class="luaClr clr clr2" style="color: #e8c252;">Last Survivor Standing</span></b>.<br><i>Deliverance</i> is disabled for the remainder of the Trial after use.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I was raised by a strict man who taught me how to make the best of a bad situation." — Adam Francis</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 2.2.0 After safely unhooking another Survivor, Deliverance activates:
Grants the ability to perform a successful Self-Unhook at any point during the first Hook Stage.
Causes the Broken Status Effect for 100 / 80 / 60 seconds after unhooking yourself.
Deliverance cannot be used during the second Hook Stage or if you are hooked as the Last Survivor Standing . Deliverance is disabled for the remainder of the Trial after use.

"I was raised by a strict man who taught me how to make the best of a bad situation." — Adam Francis', 'Adam_Francis');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Desperate_Measures', 'survivor', 'Desperate Measures', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/84/IconPerks_desperateMeasures.png/revision/latest?cb=20200819113949', 'You refuse to fail, even during your darkest hour.
<ul><li><b>Increases</b> your Action speeds for Healing and Unhooking by <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">14</span></b> <b>%</b> for each injured, hooked, or dying Survivor, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">48</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">56</span></b> <b>%</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"When they come with a wrecking ball, build stronger walls." — Felix Richter</span></i>
</p>', 'You refuse to fail, even during your darkest hour.
Increases your Action speeds for Healing and Unhooking by 10 / 12 / 14 % for each injured, hooked, or dying Survivor, up to a maximum of 40 / 48 / 56 %.
"When they come with a wrecking ball, build stronger walls." — Felix Richter', 'Felix_Richter');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Detective%27s_Hunch', 'survivor', 'Detective''s Hunch', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7b/IconPerks_detectivesHunch.png/revision/latest?cb=20180123224231', 'Unlocks potential in your Aura-reading ability.<br>
<p>Each time a Generator is completed, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of any <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span>, <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chests</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span>, and <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totems</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>within <b><span class="luaClr clr clr2" style="color: #e8c252;">32</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">48</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">64</span></b> <b>metres</b> are revealed to you for <b><span class="luaClr clr clr6" style="color: #ff8800;">10 seconds</span></b>.
</p>
<ul><li>If you are holding a <a href="https://deadbydaylight.fandom.com/wiki/Maps" title="Maps">Map</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Maps" title="Maps"><img alt="IconItems map" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems map.png" data-image-key="IconItems_map.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/92/IconItems_map.png/revision/latest/scale-to-width-down/64?cb=20240313184821"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Maps" title="Maps"><img alt="IconItems map" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems map.png" data-image-key="IconItems_map.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/92/IconItems_map.png/revision/latest/scale-to-width-down/96?cb=20240313184821"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Maps" title="Maps"><img alt="IconItems map" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems map.png" data-image-key="IconItems_map.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/92/IconItems_map.png/revision/latest/scale-to-width-down/32?cb=20240313184821"></a></span></span></span>, any objects revealed by <i>Detective''s Hunch</i> will automatically be tracked by it.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Are you able to tell us where you were last night?" — Detective David Tapp</span></i>
</p>', 'Unlocks potential in your Aura-reading ability.
Each time a Generator is completed, the Auras of any Generators , Chests , and Totems within 32 / 48 / 64 metres are revealed to you for 10 seconds .

If you are holding a Map , any objects revealed by Detective''s Hunch will automatically be tracked by it.
"Are you able to tell us where you were last night?" — Detective David Tapp', 'David_Tapp');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Distortion', 'survivor', 'Distortion', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/41/IconPerks_distortion.png/revision/latest?cb=20181128100914', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.2</div><div class="dynamicContent ptb">Start the Trial with <b><span class="luaClr clr clr2" style="color: #e8c252;">1 Token</span></b>.
<p>Whenever the Killer attempts to read your <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span>, <i>Distortion</i> activates and consumes <b><span class="luaClr clr clr6" style="color: #ff8800;">-1 Token</span></b>, applying the following effects for <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">10</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">12</span></b> <b>seconds</b>:
</p><ul><li><b>Blocks</b> your Aura from being read.</li>
<li><b>Suppresses</b> the creation of your <i>Scratch Marks</i>.</li></ul>

For every <b><span class="luaClr clr clr8" style="color: #d41c1c;">30 seconds</span></b> spent in a Chase, <i>Distortion</i> recharges <b><span class="luaClr clr clr4" style="color: #ac3ee3;">+1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr3" style="color: #199b1e;">2 Tokens</span></b>.
<p><i>Distortion</i> does not activate when you are in the Dying State.</p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.2 Start the Trial with 1 Token .
Whenever the Killer attempts to read your Aura , Distortion activates and consumes -1 Token , applying the following effects for 8 / 10 / 12 seconds :
Blocks your Aura from being read.
Suppresses the creation of your Scratch Marks.

For every 30 seconds spent in a Chase, Distortion recharges +1 Token , up to a maximum of 2 Tokens .
Distortion does not activate when you are in the Dying State.', 'Jeff_Johansen');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Diversion', 'survivor', 'Diversion', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a6/IconPerks_diversion.png/revision/latest?cb=20180828172956', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb"><i>Diversion</i> charges while inside the <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span> without being chased by the Killer.<br>After charging for <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>, it activates:
<ul><li>Press the <i>Active Ability button</i> while crouched and motionless to throw a pebble in the direction you are facing, creating a distraction for the Killer <b><span class="luaClr clr clr2" style="color: #e8c252;">20 metres</span></b> away from your location:
<ul><li>Triggers a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i>.</li>
<li>Creates fake <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span>.</li></ul></li></ul>
<p><i>Diversion</i> deactivates after use and resets its timer.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"There''s what is easy and then there''s what is right. If you confuse the two, there''s no telling what you become." — Adam Francis</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 Diversion charges while inside the Terror Radius without being chased by the Killer. After charging for 30 / 25 / 20 seconds, it activates:
Press the Active Ability button while crouched and motionless to throw a pebble in the direction you are facing, creating a distraction for the Killer 20 metres away from your location:
Triggers a Loud Noise Notification .
Creates fake Scratch Marks .
Diversion deactivates after use and resets its timer.

"There''s what is easy and then there''s what is right. If you confuse the two, there''s no telling what you become." — Adam Francis', 'Adam_Francis');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Dramaturgy', 'survivor', 'Dramaturgy', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/85/IconPerks_dramaturgy.png/revision/latest?cb=20230705160003', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">When people bring you on to their project, they do so because of the unexpected magic you bring to your performance.
<p>Whenever you are <a href="https://deadbydaylight.fandom.com/wiki/Healthy" class="mw-redirect" title="Healthy">Healthy</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Healthy" title="Healthy"><img alt="IconHelp healthy" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="73" class="mw-file-element lazyload" data-image-name="IconHelp healthy.png" data-image-key="IconHelp_healthy.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_healthy.png/revision/latest/scale-to-width-down/64?cb=20181028091351"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Healthy" title="Healthy"><img alt="IconHelp healthy" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="109" class="mw-file-element lazyload" data-image-name="IconHelp healthy.png" data-image-key="IconHelp_healthy.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_healthy.png/revision/latest?cb=20181028091351"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Healthy" title="Healthy"><img alt="IconHelp healthy" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="36" class="mw-file-element lazyload" data-image-name="IconHelp healthy.png" data-image-key="IconHelp_healthy.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_healthy.png/revision/latest/scale-to-width-down/32?cb=20181028091351"></a></span></span></span>, <i>Dramaturgy</i> activates:
</p><ul><li>While running, press the <i>Active Ability button</i> to run with knees high for <b><span class="luaClr clr clr2" style="color: #e8c252;">0.5 seconds</span></b> to gain a <b><span class="luaClr clr clr6" style="color: #ff8800;">+25&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr8" style="color: #d41c1c;">2 seconds</span></b>, followed by one of the following effects:
<ul><li>Suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/64?cb=20170620155518"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exposed" title="Exposed"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/32?cb=20170620155518"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr4" style="color: #ac3ee3;">12 seconds</span></b>.</li>
<li>Extend the duration of the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for another <b><span class="luaClr clr clr3" style="color: #199b1e;">2 seconds</span></b>.</li>
<li>Scream, but without notifying the Killer.</li>
<li>Receive a random <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Item</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span> of <b><span class="luaClr clr clr3" style="color: #199b1e;">Rare</span></b> Rarity, with a random selection of <a href="https://deadbydaylight.fandom.com/wiki/Add-on" class="mw-redirect" title="Add-on">Add-ons</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Add-on" title="Add-on"><img alt="IconHelp addons" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp addons.png" data-image-key="IconHelp_addons.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_addons.png/revision/latest/scale-to-width-down/64?cb=20170907143042"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Add-on" title="Add-on"><img alt="IconHelp addons" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp addons.png" data-image-key="IconHelp_addons.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_addons.png/revision/latest/scale-to-width-down/96?cb=20170907143042"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Add-on" title="Add-on"><img alt="IconHelp addons" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp addons.png" data-image-key="IconHelp_addons.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_addons.png/revision/latest/scale-to-width-down/32?cb=20170907143042"></a></span></span></span> attached to it, automatically dropping any previously held Item.</li></ul></li>
<li><i>The same effect cannot happen twice in a row.</i></li></ul>

<i>Dramaturgy</i> causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.<br><i>Dramaturgy</i> cannot be used when <i><b>Exhausted</b></i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Take the part. It''s a good movie, he says. What''s the worst that can happen?" — Nicolas Cage</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 When people bring you on to their project, they do so because of the unexpected magic you bring to your performance.
Whenever you are Healthy , Dramaturgy activates:
While running, press the Active Ability button to run with knees high for 0.5 seconds to gain a +25 % Haste Status Effect for 2 seconds , followed by one of the following effects:
Suffer from the Exposed Status Effect for 12 seconds .
Extend the duration of the Haste Status Effect for another 2 seconds .
Scream, but without notifying the Killer.
Receive a random Item of Rare Rarity, with a random selection of Add-ons attached to it, automatically dropping any previously held Item.
The same effect cannot happen twice in a row.

Dramaturgy causes the Exhausted Status Effect for 60 / 50 / 40 seconds. Dramaturgy cannot be used when Exhausted .
"Take the part. It''s a good movie, he says. What''s the worst that can happen?" — Nicolas Cage', 'Nicolas_Cage');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Empathic_Connection', 'survivor', 'Empathic Connection', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconPerks_empathicConnection.png/revision/latest?cb=20220216115951', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">Your presence psychically projects itself to those in danger.
<ul><li>Whenever another Survivor is injured, they can see your <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> within <b><span class="luaClr clr clr2" style="color: #e8c252;">32</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">64</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">96</span></b> <b>metres</b> of your location.</li>
<li><b>Increases</b> your Altruistic Healing speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">+30&nbsp;%</span></b>.</li></ul>
</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 Your presence psychically projects itself to those in danger.
Whenever another Survivor is injured, they can see your Aura within 32 / 64 / 96 metres of your location.
Increases your Altruistic Healing speed by +30 % .', 'Yoichi_Asakawa');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Empathy', 'survivor', 'Empathy', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ae/IconPerks_empathy.png/revision/latest?cb=20160605204916', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 2.6.0</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability:
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of injured or dying Survivors are revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">64</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">96</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">128</span></b> <b>metres</b>.</li></ul>
</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 2.6.0 Unlocks potential in your Aura-reading ability:
The Auras of injured or dying Survivors are revealed to you within 64 / 96 / 128 metres.', 'Claudette_Morel');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Exultation', 'survivor', 'Exultation', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/22/IconPerks_Exultation.png/revision/latest?cb=20240806171416', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.1</div><div class="dynamicContent ptb">Fortune favours the bold, even in the darkest corners of existence.
<p>Stunning the Killer with a <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallet</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span> upgrades the Rarity of your held <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Item</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span> to the next tier.
</p><ul><li>Recharges the <b>Item</b> by <b><span class="luaClr clr clr2" style="color: #e8c252;">+25&nbsp;%</span></b>.</li></ul>

<i>Exultation</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">35</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You will not take me this day!" — Trevor</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.1 Fortune favours the bold, even in the darkest corners of existence.
Stunning the Killer with a Pallet upgrades the Rarity of your held Item to the next tier.
Recharges the Item by +25 % .

Exultation has a cool-down of 40 / 35 / 30 seconds.
"You will not take me this day!" — Trevor', 'Trevor_Belmont');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Eyes_of_Belmont', 'survivor', 'Eyes of Belmont', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/25/IconPerks_EyesOfBelmont.png/revision/latest?cb=20240806171417', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">A history of vampire-hunting imbues the bloodline with certain abilities.
<p>Whenever a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> is completed, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">2</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b> <b>seconds</b>.
</p><ul><li><b>Extends</b> the duration of all instances of the Killer''s Aura being revealed to you by <b><span class="luaClr clr clr2" style="color: #e8c252;">+2 seconds</span></b>.</li></ul>

<i>Eyes of Belmont</i> benefits from its own effect.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Ha! Your secret has been revealed!" — Trevor</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 A history of vampire-hunting imbues the bloodline with certain abilities.
Whenever a Generator is completed, the Aura of the Killer is revealed to you for 1 / 2 / 3 seconds.
Extends the duration of all instances of the Killer''s Aura being revealed to you by +2 seconds .

Eyes of Belmont benefits from its own effect.
"Ha! Your secret has been revealed!" — Trevor', 'Trevor_Belmont');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Fast_Track', 'survivor', 'Fast Track', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/75/IconPerks_fastTrack.png/revision/latest?cb=20210302172243', 'Sometimes the sacrifice of others is necessary to get ahead.
<p>Whenever a Survivor other than yourself is hooked, <i>Fast Track</i> is granted <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">2</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b> <b>Token(s)</b>, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">9</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">18</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">27</span></b> <b>Tokens</b>.
</p><ul><li>Succeeding a <i>Great Repair Skill Check</i> consumes all accumulated Tokens.</li>
<li><b>Increases</b> the bonus Progression awarded for succeeding that <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> by a stack-able <b><span class="luaClr clr clr2" style="color: #e8c252;">+1&nbsp;%</span></b> per Token.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"The weak are sacrificed first. It''s nature, it''s business... it''s the truth most refuse to face." — Yun-Jin Lee</span></i>
', 'Sometimes the sacrifice of others is necessary to get ahead.
Whenever a Survivor other than yourself is hooked, Fast Track is granted 1 / 2 / 3 Token(s), up to a maximum of 9 / 18 / 27 Tokens.
Succeeding a Great Repair Skill Check consumes all accumulated Tokens.
Increases the bonus Progression awarded for succeeding that Skill Check by a stack-able +1 % per Token.

"The weak are sacrificed first. It''s nature, it''s business... it''s the truth most refuse to face." — Yun-Jin Lee', 'Yun-Jin_Lee');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Finesse', 'survivor', 'Finesse', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fc/IconPerks_finesse.png/revision/latest?cb=20240625161544', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">The threat of danger can motivate any creature to strengthen its resolve.
<p>Whenever you are healthy, <i>Finesse</i> activates:
</p><ul><li><b>Increases</b> your Vaulting speed for a <i>Fast Vault</i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">+20&nbsp;%</span></b>.</li></ul>

<i>Finesse</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">35</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b> after performing a <i>Fast Vault</i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Just need to push myself a bit further." — Lara Croft</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 The threat of danger can motivate any creature to strengthen its resolve.
Whenever you are healthy, Finesse activates:
Increases your Vaulting speed for a Fast Vault by +20 % .

Finesse has a cool-down of 40 / 35 / 30 seconds after performing a Fast Vault.
"Just need to push myself a bit further." — Lara Croft', 'Lara_Croft');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Fixated', 'survivor', 'Fixated', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7c/IconPerks_fixated.png/revision/latest?cb=20190903175127', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.3.3</div><div class="dynamicContent ptb">When you have a goal in mind, there is no turning back; better to ask forgiveness than permission.
<ul><li><b>Increases</b> your Walking speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">15</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>%</b>.</li>
<li>Unlocks the ability to see your own <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I wanna finish what we started. I want to kill it." — Nancy Wheeler</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.3.3 When you have a goal in mind, there is no turning back; better to ask forgiveness than permission.
Increases your Walking speed by 10 / 15 / 20 %.
Unlocks the ability to see your own Scratch Marks .
"I wanna finish what we started. I want to kill it." — Nancy Wheeler', 'Nancy_Wheeler');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Flashbang', 'survivor', 'Flashbang', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/db/IconPerks_flashbang.png/revision/latest?cb=20210526102947', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">You have adapted to a world in chaos and making what you can from the debris.
<p>After repairing <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> for a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">50</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">45</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>%</b>, <i>Flashbang</i> activates:
</p><ul><li>Press the <i>Active Ability button</i> while hiding inside a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span> to craft a <a href="https://deadbydaylight.fandom.com/wiki/Flash_Grenade" title="Flash Grenade">Flash Grenade</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 4px"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span style="display:inline-flex; vertical-align: middle; position:relative; height: 32px; width: 32px"><span class="margin-auto" style="display: inline-flex; position: absolute; top: 0px; max-width: 32px;"><span class="game-element-container flex relative"><span class="game-element-bg-settings game-element-bg-settings-size-perk craft-able-and-limited-item-element" style="width: 32px; height: 32px;"></span><span class="game-element-bg-settings-size-sos absolute" style="width: 32px; height: 32px;"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flash_Grenade" title="Flash Grenade"><img alt="IconItems flashGrenade" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="300" height="300" class="mw-file-element lazyload" data-image-name="IconItems flashGrenade.png" data-image-key="IconItems_flashGrenade.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6a/IconItems_flashGrenade.png/revision/latest?cb=20240313190359"></a></span></span></span></span></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flash_Grenade" title="Flash Grenade"><img alt="IconItems flashGrenade" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems flashGrenade.png" data-image-key="IconItems_flashGrenade.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6a/IconItems_flashGrenade.png/revision/latest/scale-to-width-down/96?cb=20240313190359"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flash_Grenade" title="Flash Grenade"><img alt="IconItems flashGrenade" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems flashGrenade.png" data-image-key="IconItems_flashGrenade.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/6a/IconItems_flashGrenade.png/revision/latest/scale-to-width-down/32?cb=20240313190359"></a></span></span></span>.</li></ul>

<i>Flashbang</i> deactivates after use.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Get outta my face!" — Leon Scott Kennedy</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 You have adapted to a world in chaos and making what you can from the debris.
After repairing Generators for a total of 50 / 45 / 40 %, Flashbang activates:
Press the Active Ability button while hiding inside a Locker to craft a Flash Grenade .

Flashbang deactivates after use.
"Get outta my face!" — Leon Scott Kennedy', 'Leon_Scott_Kennedy');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Flip-Flop', 'survivor', 'Flip-Flop', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/31/IconPerks_flip-Flop.png/revision/latest?cb=20190402180450', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 2.6.3</div><div class="dynamicContent ptb">You have an uncanny ability to escape the inevitable.
<p class="mw-empty-elt">
</p><ul><li>Recovering in the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> also charges the <i>Wiggle Meter</i> at <b><span class="luaClr clr clr2" style="color: #e8c252;">50&nbsp;%</span></b> of the Recovery rate and up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">45</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b> of Wiggle Progression.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Catch ya on the flip-flop." — Ash Williams</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 2.6.3 You have an uncanny ability to escape the inevitable.

Recovering in the Dying State also charges the Wiggle Meter at 50 % of the Recovery rate and up to a maximum of 40 / 45 / 50 % of Wiggle Progression.

"Catch ya on the flip-flop." — Ash Williams', 'Ash_Williams');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Fogwise', 'survivor', 'Fogwise', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/90/IconPerks_fogwise.png/revision/latest?cb=20221102143122', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.4.0</div><div class="dynamicContent ptb">In your countless years in The Fog, you have seen it all, and when you are focused, you can remember most of it too.
<ul><li>Succeeding a <a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" class="mw-redirect" title="Great Skill Check">Great Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" title="Great Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" title="Great Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" title="Great Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> while repairing a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> reveals the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>seconds</b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I have seen great cruelty... and I have also seen another way." — Vittorio Toscano</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.4.0 In your countless years in The Fog, you have seen it all, and when you are focused, you can remember most of it too.
Succeeding a Great Skill Check while repairing a Generator reveals the Aura of the Killer to you for 4 / 5 / 6 seconds.
"I have seen great cruelty... and I have also seen another way." — Vittorio Toscano', 'Vittorio_Toscano');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('For_the_People', 'survivor', 'For the People', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/31/IconPerks_forThePeople.png/revision/latest?cb=20200218172919', 'You risk life and injury for others.
<p>While healthy and healing another Survivor without using a <a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" class="mw-redirect" title="Med-Kit">Med-Kit</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/64?cb=20240313184755"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/96?cb=20240313184755"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/32?cb=20240313184755"></a></span></span></span>, press the <i>Active Ability button</i> to trigger the following effects:
</p><ul><li>Trade <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b> <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span> with the other Survivor:
<ul><li><b>Instantly</b> heals them to the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>, if they were dying or suffering from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" class="mw-redirect" title="Deep Wound">Deep Wound</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" title="Deep Wound"><img alt="IconStatusEffects deepWound" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects deepWound.png" data-image-key="IconStatusEffects_deepWound.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3f/IconStatusEffects_deepWound.png/revision/latest/scale-to-width-down/64?cb=20181128100459"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" title="Deep Wound"><img alt="IconStatusEffects deepWound" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects deepWound.png" data-image-key="IconStatusEffects_deepWound.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3f/IconStatusEffects_deepWound.png/revision/latest/scale-to-width-down/96?cb=20181128100459"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" title="Deep Wound"><img alt="IconStatusEffects deepWound" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects deepWound.png" data-image-key="IconStatusEffects_deepWound.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3f/IconStatusEffects_deepWound.png/revision/latest/scale-to-width-down/32?cb=20181128100459"></a></span></span></span></b></i> <b>Status Effect</b>.</li>
<li><b>Instantly</b> heals them to full health, if they were injured.</li></ul></li>
<li>You yourself become injured and suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/64?cb=20180829073317"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/32?cb=20180829073317"></a></span></span></span></b></i> <b>Status Effect</b> for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">80</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">70</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.</li>
<li>You become the Killer''s <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i>, if not already.</li></ul>

<b>Reduces</b> your chance of becoming the initial  <i><b>Obsession</b></i> by reducing the default value by <b>-100&nbsp;%</b>.<br><i>The Killer can only be <b>obsessed</b> with one Survivor at a time.</i>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"We can write our own story and decide how it really ends." — Zarina Kassir</span></i>
</p>', 'You risk life and injury for others.
While healthy and healing another Survivor without using a Med-Kit , press the Active Ability button to trigger the following effects:
Trade 1 Health State with the other Survivor:
Instantly heals them to the Injured State , if they were dying or suffering from the Deep Wound Status Effect.
Instantly heals them to full health, if they were injured.
You yourself become injured and suffer from the Broken Status Effect for the next 80 / 70 / 60 seconds.
You become the Killer''s Obsession , if not already.

Reduces your chance of becoming the initial Obsession by reducing the default value by -100 %. The Killer can only be obsessed with one Survivor at a time.
"We can write our own story and decide how it really ends." — Zarina Kassir', 'Zarina_Kassir');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Friendly_Competition', 'survivor', 'Friendly Competition', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4c/IconPerks_friendlyCompetition.png/revision/latest?cb=20230218135316', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.6.0</div><div class="dynamicContent ptb">You revel in the community spirit of a competition, and inspire others to follow suit.
<p>Whenever you complete a Generator with at least one other Survivor, <i>Friendly Competition</i> activates:
</p><ul><li><b>Increases</b> your Repair speed, and that of the other Survivor(s) who completed the repairs with you, by <b><span class="luaClr clr clr2" style="color: #e8c252;">+5&nbsp;%</span></b> for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">45</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">60</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">75</span></b> <b>seconds</b>.</li></ul>


<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"C''mon, let''s do this!" — Thalita Lyra</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.6.0 You revel in the community spirit of a competition, and inspire others to follow suit.
Whenever you complete a Generator with at least one other Survivor, Friendly Competition activates:
Increases your Repair speed, and that of the other Survivor(s) who completed the repairs with you, by +5 % for the next 45 / 60 / 75 seconds.

"C''mon, let''s do this!" — Thalita Lyra', 'Thalita_Lyra');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hardened', 'survivor', 'Hardened', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fe/IconPerks_hardened.png/revision/latest?cb=20240625161545', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">Live long enough, and survival will run in your blood.
<p>After unlocking a <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chest</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> and either blessing or cleansing a <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>, <i>Hardened</i> activates:
</p><ul><li><b>Suppresses</b> the urge to scream from any cause and instead causes the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer to be revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>seconds</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Got to keep quiet. That thing is still out there." — Lara Croft</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 Live long enough, and survival will run in your blood.
After unlocking a Chest and either blessing or cleansing a Totem , Hardened activates:
Suppresses the urge to scream from any cause and instead causes the Aura of the Killer to be revealed to you for 3 / 4 / 5 seconds.

"Got to keep quiet. That thing is still out there." — Lara Croft', 'Lara_Croft');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Head_On', 'survivor', 'Head On', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cb/IconPerks_headOn.png/revision/latest?cb=20190308175420', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">When your mind is set, there better be no one standing in your way.
<p>After hiding in a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">3 seconds</span></b>, <i>Head On</i> activates:
</p><ul><li>Performing a <i>Rush Exit</i> out of the <b>Locker</b> stuns a nearby Killer for <b><span class="luaClr clr clr6" style="color: #ff8800;">3 seconds</span></b>.</li></ul>

<i>Head On</i> causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.<br><i>Head On</i> cannot be used while <i><b>Exhausted</b></i> or when having accrued <a href="https://deadbydaylight.fandom.com/wiki/Idle_Crow" class="mw-redirect" title="Idle Crow">Idle Crows</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Idle_Crow" title="Idle Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/64?cb=20170907144135"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Idle_Crow" title="Idle Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/96?cb=20170907144135"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Idle_Crow" title="Idle Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/32?cb=20170907144135"></a></span></span></span>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"People are remembered for the challenges they overcome. You can run away and forget what you''re capable of or you can face your fears and remind the world of who you are." — Jane Romero</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 When your mind is set, there better be no one standing in your way.
After hiding in a Locker for 3 seconds , Head On activates:
Performing a Rush Exit out of the Locker stuns a nearby Killer for 3 seconds .

Head On causes the Exhausted Status Effect for 60 / 50 / 40 seconds. Head On cannot be used while Exhausted or when having accrued Idle Crows .
"People are remembered for the challenges they overcome. You can run away and forget what you''re capable of or you can face your fears and remind the world of who you are." — Jane Romero', 'Jane_Romero');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hope', 'survivor', 'Hope', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/18/IconPerks_hope.png/revision/latest?cb=20160605204928', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">The growing odds of a successful escape fill you with hope and give you wings.
<p>Once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are powered, <i>Hope</i> activates:
</p><ul><li>Grants a permanent <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">6</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">7</span></b> <b>%</b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Buckle up, fuckos! Let''s roll." — Nikki, The Lost Tapes</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 The growing odds of a successful escape fill you with hope and give you wings.
Once the Exit Gates are powered, Hope activates:
Grants a permanent 5 / 6 / 7 % Haste Status Effect.

"Buckle up, fuckos! Let''s roll." — Nikki, The Lost Tapes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Hyperfocus', 'survivor', 'Hyperfocus', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5d/IconPerks_hyperfocus.png/revision/latest?cb=20220815051721', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.2.0</div><div class="dynamicContent ptb">You throw yourself entirely into your tasks and find ways to be more efficient than anyone else.
<p>Succeeding a <a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" class="mw-redirect" title="Great Skill Check">Great Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" title="Great Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" title="Great Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" title="Great Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> while repairing or healing grants <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr6" style="color: #ff8800;">6 Tokens</span></b>:
</p><ul><li><b>Increases</b> the Skill Check Trigger odds and Pointer Rotation speed by <b><span class="luaClr clr clr8" style="color: #d41c1c;">+4&nbsp;%</span></b> per Token each, up to a maximum of <b><span class="luaClr clr clr4" style="color: #ac3ee3;">+24&nbsp;%</span></b>.</li>
<li><b>Increases</b> the Skill Check Bonus progression by <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">20</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b> of its base value per Token, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">120</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">180</span></b> <b>%</b>.</li></ul>

<i>Hyperfocus</i> loses all Tokens after succeeding just a <i>Good Skill Check</i>, failing one, or if the action is interrupted by any means.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.2.0 You throw yourself entirely into your tasks and find ways to be more efficient than anyone else.
Succeeding a Great Skill Check while repairing or healing grants +1 Token , up to a maximum of 6 Tokens :
Increases the Skill Check Trigger odds and Pointer Rotation speed by +4 % per Token each, up to a maximum of +24 % .
Increases the Skill Check Bonus progression by 10 / 20 / 30 % of its base value per Token, up to a maximum of 60 / 120 / 180 %.

Hyperfocus loses all Tokens after succeeding just a Good Skill Check, failing one, or if the action is interrupted by any means.', 'Rebecca_Chambers');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Inner_Focus', 'survivor', 'Inner Focus', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7e/IconPerks_innerFocus.png/revision/latest?cb=20220518112819', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.2</div><div class="dynamicContent ptb">You have honed your ability to see through the haze of the Ravage.
<ul><li>Grants the ability to see the <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> of other Survivors.</li>
<li>Whenever another Survivor loses a <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span> due to the Killer, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the latter is revealed to your for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"The death, the trauma, the fear... it all leads here. The Overlap." — Haddie Kaur, Ravages of the Abyss Episode 11</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.2 You have honed your ability to see through the haze of the Ravage.
Grants the ability to see the Scratch Marks of other Survivors.
Whenever another Survivor loses a Health State due to the Killer, the Aura of the latter is revealed to your for 6 / 8 / 10 seconds.
"The death, the trauma, the fear... it all leads here. The Overlap." — Haddie Kaur, Ravages of the Abyss Episode 11', 'Haddie_Kaur');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Inner_Strength', 'survivor', 'Inner Strength', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/47/IconPerks_innerStrength.png/revision/latest?cb=20190903175147', 'You look inwards and trust your instincts when you feel lost and alone.
<p>Each time you cleanse a <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>, <i>Inner Strength</i> activates:
</p><ul><li>You are automatically healed <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b> <b>Health State</b> while hiding inside a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">9</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>seconds</b> when injured or suffering from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" class="mw-redirect" title="Deep Wound">Deep Wound</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" title="Deep Wound"><img alt="IconStatusEffects deepWound" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects deepWound.png" data-image-key="IconStatusEffects_deepWound.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3f/IconStatusEffects_deepWound.png/revision/latest/scale-to-width-down/64?cb=20181128100459"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" title="Deep Wound"><img alt="IconStatusEffects deepWound" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects deepWound.png" data-image-key="IconStatusEffects_deepWound.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3f/IconStatusEffects_deepWound.png/revision/latest/scale-to-width-down/96?cb=20181128100459"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" title="Deep Wound"><img alt="IconStatusEffects deepWound" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects deepWound.png" data-image-key="IconStatusEffects_deepWound.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3f/IconStatusEffects_deepWound.png/revision/latest/scale-to-width-down/32?cb=20181128100459"></a></span></span></span></b></i> <b>Status Effect</b>.</li></ul>

<i>Inner Strength</i> does not activate if you currently suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/64?cb=20180829073317"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/32?cb=20180829073317"></a></span></span></span></b></i> <b>Status Effect</b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"All this time I''ve been trying so hard to pretend like everything''s fine, but it''s not." — Nancy Wheeler</span></i>
</p>', 'You look inwards and trust your instincts when you feel lost and alone.
Each time you cleanse a Totem , Inner Strength activates:
You are automatically healed 1 Health State while hiding inside a Locker for 10 / 9 / 8 seconds when injured or suffering from the Deep Wound Status Effect.

Inner Strength does not activate if you currently suffer from the Broken Status Effect.
"All this time I''ve been trying so hard to pretend like everything''s fine, but it''s not." — Nancy Wheeler', 'Nancy_Wheeler');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Invocation:_Treacherous_Crows', 'survivor', 'Invocation: Treacherous Crows', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a8/IconPerks_invocationTreacherousCrows.png/revision/latest?cb=20241107202156', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">One with arcane knowledge has no reason to fear those watchful birds.
<p>When in the <a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement">Basement</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/64?cb=20170907141327"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/96?cb=20170907141327"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/32?cb=20170907141327"></a></span></span></span> near the circle, press the <i>Active Ability button</i> to begin the <i>Invocation</i>, which takes <b><span class="luaClr clr clr2" style="color: #e8c252;">60 seconds</span></b> to complete.<br>During an <i>Invocation</i>, your <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is revealed to all other Survivors and they can join in, accelerating the process by <b><span class="luaClr clr clr6" style="color: #ff8800;">+100&nbsp;%</span></b>, if they too have an <i>Invocation Perk</i> equipped, or by <b><span class="luaClr clr clr8" style="color: #d41c1c;">+50&nbsp;%</span></b>, if they have not.
</p><p>Once the <i>Invocation</i> is completed, the following effects apply:
</p><ul><li>Whenever the Killer scares a <a href="https://deadbydaylight.fandom.com/wiki/Crow" class="mw-redirect" title="Crow">Crow</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/64?cb=20170907144135"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/96?cb=20170907144135"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Crow" title="Crow"><img alt="IconHelp crows" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp crows.png" data-image-key="IconHelp_crows.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_crows.png/revision/latest/scale-to-width-down/32?cb=20170907144135"></a></span></span></span> while a Survivor is inside their <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span>, their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is revealed to all Survivors for <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">1.5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">2</span></b> <b>seconds</b>.</li>
<li>You automatically enter the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span> from any previous Health State, and suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/64?cb=20180829073317"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/32?cb=20180829073317"></a></span></span></span></b></i> <b>Status Effect</b> for the remainder of the Trial.</li></ul>

Completing an <i>Invocation</i> disables all <i>Invocation Perks</i> for the remainder of the Trial for all Survivors.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Remember your training. They taught you all about the crows." — Taurie Cain</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 One with arcane knowledge has no reason to fear those watchful birds.
When in the Basement near the circle, press the Active Ability button to begin the Invocation, which takes 60 seconds to complete. During an Invocation, your Aura is revealed to all other Survivors and they can join in, accelerating the process by +100 % , if they too have an Invocation Perk equipped, or by +50 % , if they have not.
Once the Invocation is completed, the following effects apply:
Whenever the Killer scares a Crow while a Survivor is inside their Terror Radius , their Aura is revealed to all Survivors for 1 / 1.5 / 2 seconds.
You automatically enter the Injured State from any previous Health State, and suffer from the Broken Status Effect for the remainder of the Trial.

Completing an Invocation disables all Invocation Perks for the remainder of the Trial for all Survivors.
"Remember your training. They taught you all about the crows." — Taurie Cain', 'Taurie_Cain');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Invocation:_Weaving_Spiders', 'survivor', 'Invocation: Weaving Spiders', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/07/IconPerks_invocationWeavingSpiders.png/revision/latest?cb=20240220182529', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">The place where fear festers and terror treads is also where those with the gift can reach across the veil.
<p>When in the <a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement">Basement</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/64?cb=20170907141327"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/96?cb=20170907141327"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/32?cb=20170907141327"></a></span></span></span> near the circle, press the <i>Active Ability button</i> to begin the <i>Invocation</i>, which takes <b><span class="luaClr clr clr2" style="color: #e8c252;">60 seconds</span></b> to complete.<br>During an <i>Invocation</i>, your <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is revealed to all other Survivors and they can join in, accelerating the process by <b><span class="luaClr clr clr6" style="color: #ff8800;">+100&nbsp;%</span></b>, if they too have an <i>Invocation Perk</i> equipped, or by <b><span class="luaClr clr clr8" style="color: #d41c1c;">+50&nbsp;%</span></b>, if they have not.
</p><p>Once the <i>Invocation</i> is completed, the following effects apply:
</p><ul><li><b>Permanently reduces</b> the Repair Charges requirement of all <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> in the Trial by <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">9</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>Charges</b>.</li>
<li>You automatically enter the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span> from any previous Health State, and suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/64?cb=20180829073317"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/32?cb=20180829073317"></a></span></span></span></b></i> <b>Status Effect</b> for the remainder of the Trial.</li></ul>

Completing an <i>Invocation</i> disables all <i>Invocation Perks</i> for the remainder of the Trial for all Survivors.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I call upon the spirits of the night, to aid us in our desperate flight!" — Sable</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 The place where fear festers and terror treads is also where those with the gift can reach across the veil.
When in the Basement near the circle, press the Active Ability button to begin the Invocation, which takes 60 seconds to complete. During an Invocation, your Aura is revealed to all other Survivors and they can join in, accelerating the process by +100 % , if they too have an Invocation Perk equipped, or by +50 % , if they have not.
Once the Invocation is completed, the following effects apply:
Permanently reduces the Repair Charges requirement of all Generators in the Trial by 8 / 9 / 10 Charges.
You automatically enter the Injured State from any previous Health State, and suffer from the Broken Status Effect for the remainder of the Trial.

Completing an Invocation disables all Invocation Perks for the remainder of the Trial for all Survivors.
"I call upon the spirits of the night, to aid us in our desperate flight!" — Sable', 'Sable_Ward');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Iron_Will', 'survivor', 'Iron Will', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/58/IconPerks_ironWill.png/revision/latest?cb=20160605204945', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">You are able to concentrate and enter a meditative-like state to numb some pain.
<ul><li><b>Reduces</b> the volume of <i>Grunts of Pain</i> while in the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">80</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">90</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">100</span></b> <b>%</b>.</li></ul>
<i>Iron Will</i> cannot be used when suffering from <i><b>Exhaustion</b></i>, but does not cause the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b>.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 You are able to concentrate and enter a meditative-like state to numb some pain.
Reduces the volume of Grunts of Pain while in the Injured State by 80 / 90 / 100 %.
Iron Will cannot be used when suffering from Exhaustion , but does not cause the Exhausted Status Effect.', 'Jake_Park');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Kindred', 'survivor', 'Kindred', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a8/IconPerks_kindred.png/revision/latest?cb=20160819130530', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 3.4.0</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability.
<p>Whenever any Survivor is hooked, <i>Kindred</i> activates and applies the following effects:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer is revealed to all Survivors whenever the Killer comes within <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>metres</b> of the <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hook</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span>.</li>
<li>If you are the <i>Hooked Survivor</i>, the Auras of all Survivors are revealed to each other.</li>
<li>If you are not the <i>Hooked Survivor</i>, the Auras of all other Survivors are only revealed to you.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Be kind to one another, We''re all in this together" — Sujan, The Lost Tapes</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 3.4.0 Unlocks potential in your Aura-reading ability.
Whenever any Survivor is hooked, Kindred activates and applies the following effects:
The Aura of the Killer is revealed to all Survivors whenever the Killer comes within 8 / 12 / 16 metres of the Hook .
If you are the Hooked Survivor, the Auras of all Survivors are revealed to each other.
If you are not the Hooked Survivor, the Auras of all other Survivors are only revealed to you.

"Be kind to one another, We''re all in this together" — Sujan, The Lost Tapes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Leader', 'survivor', 'Leader', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3d/IconPerks_leader.png/revision/latest?cb=20160605204957', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 2.5.0</div><div class="dynamicContent ptb">You are able to organise a team to cooperate more efficiently.
<p>Other Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">8 metres</span></b> of your location benefit from the following effect:
</p><ul><li><b>Increases</b> the Action speeds for Cleansing, Gate-Opening, Healing, Sabotaging, Unhooking, and Unlocking by <b><span class="luaClr clr clr2" style="color: #e8c252;">15</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">20</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">25</span></b> <b>%</b>.
<ul><li>This effect lingers for <b><span class="luaClr clr clr6" style="color: #ff8800;">15 seconds</span></b> after leaving the <i>Area of Effect</i>.</li></ul></li></ul>

Survivors can only be affected by one instance of <i>Leader</i> at a time.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 2.5.0 You are able to organise a team to cooperate more efficiently.
Other Survivors within 8 metres of your location benefit from the following effect:
Increases the Action speeds for Cleansing, Gate-Opening, Healing, Sabotaging, Unhooking, and Unlocking by 15 / 20 / 25 %.
This effect lingers for 15 seconds after leaving the Area of Effect.

Survivors can only be affected by one instance of Leader at a time.', 'Dwight_Fairfield');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Left_Behind', 'survivor', 'Left Behind', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconPerks_leftBehind.png/revision/latest?cb=20170308184910', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 3.2.0</div><div class="dynamicContent ptb">You will get the job done... no matter the cost.
<p>Once you are the <b><span class="luaClr clr clr2" style="color: #e8c252;">Last Survivor Standing</span></b>, <i>Left Behind</i> activates:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the <a href="https://deadbydaylight.fandom.com/wiki/Hatch" title="Hatch">Hatch</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hatch" title="Hatch"><img alt="IconHelp hatch" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp hatch.png" data-image-key="IconHelp_hatch.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_hatch.png/revision/latest/scale-to-width-down/64?cb=20170907144528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hatch" title="Hatch"><img alt="IconHelp hatch" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp hatch.png" data-image-key="IconHelp_hatch.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_hatch.png/revision/latest/scale-to-width-down/96?cb=20170907144528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hatch" title="Hatch"><img alt="IconHelp hatch" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp hatch.png" data-image-key="IconHelp_hatch.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_hatch.png/revision/latest/scale-to-width-down/32?cb=20170907144528"></a></span></span></span> is revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">24</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">28</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">32</span></b> <b>metres</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I''m not horse-shittin'' around. I''m doing this alone!" — Bill Overbeck</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 3.2.0 You will get the job done... no matter the cost.
Once you are the Last Survivor Standing , Left Behind activates:
The Aura of the Hatch is revealed to you within 24 / 28 / 32 metres.

"I''m not horse-shittin'' around. I''m doing this alone!" — Bill Overbeck', 'Bill_Overbeck');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Light-Footed', 'survivor', 'Light-Footed', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e5/IconPerks_light-Footed.png/revision/latest?cb=20230808160213', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.2.0</div><div class="dynamicContent ptb">Crossing paths with deadly Killers has taught you the value of discretion.
<p>Whenever you are healthy, <i>Light-Footed</i> activates:
</p><ul><li><b>Suppresses</b> the sound of your footsteps while running.</li></ul>

<i>Light-Footed</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">28</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">24</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b> after performing a <i>Rush Vault action</i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Come on, cat." — Ellen Ripley</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.2.0 Crossing paths with deadly Killers has taught you the value of discretion.
Whenever you are healthy, Light-Footed activates:
Suppresses the sound of your footsteps while running.

Light-Footed has a cool-down of 28 / 24 / 20 seconds after performing a Rush Vault action.
"Come on, cat." — Ellen Ripley', 'Ellen_Ripley');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Lightweight', 'survivor', 'Lightweight', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconPerks_lightweight.png/revision/latest?cb=20160605205008', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">Your running is light and soft, making your tracks harder to follow.
<ul><li><b>Reduces</b> the Lifetime of your <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>seconds</b>.</li>
<li><b>Reduces</b> the Spawn chance of patches of <i>Scratch Marks</i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">-60&nbsp;%</span></b>, making their spacing inconsistent.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Take it slow, he knows where you have been... just like I have always said:<br>''live slow and die old''." — Dylan, The Lost Tapes</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 Your running is light and soft, making your tracks harder to follow.
Reduces the Lifetime of your Scratch Marks by 3 / 4 / 5 seconds.
Reduces the Spawn chance of patches of Scratch Marks by -60 % , making their spacing inconsistent.
"Take it slow, he knows where you have been... just like I have always said: ''live slow and die old''." — Dylan, The Lost Tapes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Lithe', 'survivor', 'Lithe', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconPerks_lithe.png/revision/latest?cb=20170511153301', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 2.6.0</div><div class="dynamicContent ptb">Performing a <i>Rushed Vault</i> triggers <i>Lithe</i>:
<ul><li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">+50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr6" style="color: #ff8800;">3 seconds</span></b>.</li></ul>
<p><i>Lithe</i> causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.<br><i>Lithe</i> cannot be used when <i><b>Exhausted</b></i>.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"U mad?" — Feng Min</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 2.6.0 Performing a Rushed Vault triggers Lithe :
Grants a +50 % Haste Status Effect for 3 seconds .
Lithe causes the Exhausted Status Effect for 60 / 50 / 40 seconds. Lithe cannot be used when Exhausted .

"U mad?" — Feng Min', 'Feng_Min');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Low_Profile', 'survivor', 'Low Profile', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fb/IconPerks_lowProfile.png/revision/latest?cb=20220815051740', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.2.0</div><div class="dynamicContent ptb">You work best alone.<br>When it is just you and your pursuer, you know how to disappear.
<p>Whenever you are the only Survivor not currently incapacitated by either being downed, carried, or hooked, <i>Low Profile</i> activates:
</p><ul><li><b>Suppresses</b> your <i>Grunts of Pain</i> and the creation of <a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood">Pools of Blood</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span> and <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">70</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">80</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">90</span></b> <b>seconds</b>.</li></ul>

<i>Low Profile</i> deactivates after use and only accounts for Survivors still participating in the Trial.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.2.0 You work best alone. When it is just you and your pursuer, you know how to disappear.
Whenever you are the only Survivor not currently incapacitated by either being downed, carried, or hooked, Low Profile activates:
Suppresses your Grunts of Pain and the creation of Pools of Blood and Scratch Marks for 70 / 80 / 90 seconds.

Low Profile deactivates after use and only accounts for Survivors still participating in the Trial.', 'Ada_Wong');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Lucky_Break', 'survivor', 'Lucky Break', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a7/IconPerks_luckyBreak.png/revision/latest?cb=20191126213558', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">You have had your share of scrapes and bruises, but luck is always on your side.
<p>Whenever you are in the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>, <i>Lucky Break</i> activates:
</p><ul><li><b>Suppresses</b> your <a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood">Pools of Blood</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span> and <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> for a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>, after which <i>Lucky Break</i> deactivates.</li></ul>
<p>Each <b><span class="luaClr clr clr2" style="color: #e8c252;">1 second</span></b> spent healing another Survivor recharges <i>Lucky Break</i> by <b><span class="luaClr clr clr6" style="color: #ff8800;">1 second</span></b> up to its maximum Effect duration.
</p><p><i>Lucky Break</i> also deactivates whenever you are <a href="https://deadbydaylight.fandom.com/wiki/Healthy" class="mw-redirect" title="Healthy">Healthy</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Healthy" title="Healthy"><img alt="IconHelp healthy" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="73" class="mw-file-element lazyload" data-image-name="IconHelp healthy.png" data-image-key="IconHelp_healthy.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_healthy.png/revision/latest/scale-to-width-down/64?cb=20181028091351"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Healthy" title="Healthy"><img alt="IconHelp healthy" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="109" class="mw-file-element lazyload" data-image-name="IconHelp healthy.png" data-image-key="IconHelp_healthy.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_healthy.png/revision/latest?cb=20181028091351"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Healthy" title="Healthy"><img alt="IconHelp healthy" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="36" class="mw-file-element lazyload" data-image-name="IconHelp healthy.png" data-image-key="IconHelp_healthy.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/67/IconHelp_healthy.png/revision/latest/scale-to-width-down/32?cb=20181028091351"></a></span></span></span> or in the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"That''s not enough to beat me.<br>Not even close." — Yui Kimura</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 You have had your share of scrapes and bruises, but luck is always on your side.
Whenever you are in the Injured State , Lucky Break activates:
Suppresses your Pools of Blood and Scratch Marks for a maximum of 40 / 50 / 60 seconds, after which Lucky Break deactivates.
Each 1 second spent healing another Survivor recharges Lucky Break by 1 second up to its maximum Effect duration.
Lucky Break also deactivates whenever you are Healthy or in the Dying State .
"That''s not enough to beat me. Not even close." — Yui Kimura', 'Yui_Kimura');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Lucky_Star', 'survivor', 'Lucky Star', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/08/IconPerks_luckyStar.png/revision/latest?cb=20230808160212', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">You know how to stay calm in the face of incomprehensible danger.
<p>While hiding inside a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span>, you benefit from the following effect:
</p><ul><li><b>Suppresses</b> your <i>Grunts of Pain</i>.</li></ul>

After exiting the <b>Locker</b> you benefit from the following effects for <b><span class="luaClr clr clr2" style="color: #e8c252;">30 seconds</span></b>:
<ul><li><b>Suppresses</b> your <i>Grunts of Pain</i> and the creation of <a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood">Pools of Blood</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span>.</li>
<li>The Auras of the other Survivors are revealed to you.</li>
<li>The Aura of the closest Generator is revealed to you in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.</li></ul>

<i>Lucky Star</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">35</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You are my... lucky star..." — Ellen Ripley</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 You know how to stay calm in the face of incomprehensible danger.
While hiding inside a Locker , you benefit from the following effect:
Suppresses your Grunts of Pain.

After exiting the Locker you benefit from the following effects for 30 seconds :
Suppresses your Grunts of Pain and the creation of Pools of Blood .
The Auras of the other Survivors are revealed to you.
The Aura of the closest Generator is revealed to you in yellow .

Lucky Star has a cool-down of 40 / 35 / 30 seconds.
"You are my... lucky star..." — Ellen Ripley', 'Ellen_Ripley');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Made_for_This', 'survivor', 'Made for This', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c0/IconPerks_madeForThis.png/revision/latest?cb=20230524205724', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.4.0</div><div class="dynamicContent ptb">You were born to survive, and raised to adapt.
<p>Whenever you are in the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>, <i>Made for This</i> activates and you benefit from the following effects:
</p><ul><li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Endurance" class="mw-redirect" title="Endurance">Endurance</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/64?cb=20170620154928"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/96?cb=20170620154928"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/32?cb=20170620154928"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>, after completing a Healing action on another Survivor.
<ul><li><i><b>Endurance</b></i> is cancelled prematurely when performing a <i><a href="https://deadbydaylight.fandom.com/wiki/Conspicuous_Action" class="mw-redirect" title="Conspicuous Action">Conspicuous Action</a></i>.</li></ul></li>
<li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">2</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b> <b>%</b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> while running and also suffering from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" class="mw-redirect" title="Deep Wound">Deep Wound</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" title="Deep Wound"><img alt="IconStatusEffects deepWound" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects deepWound.png" data-image-key="IconStatusEffects_deepWound.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3f/IconStatusEffects_deepWound.png/revision/latest/scale-to-width-down/64?cb=20181128100459"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" title="Deep Wound"><img alt="IconStatusEffects deepWound" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects deepWound.png" data-image-key="IconStatusEffects_deepWound.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3f/IconStatusEffects_deepWound.png/revision/latest/scale-to-width-down/96?cb=20181128100459"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Deep_Wound" title="Deep Wound"><img alt="IconStatusEffects deepWound" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects deepWound.png" data-image-key="IconStatusEffects_deepWound.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3f/IconStatusEffects_deepWound.png/revision/latest/scale-to-width-down/32?cb=20181128100459"></a></span></span></span></b></i> <b>Status Effect</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I didn''t come here to be robot food!" — Gabriel Soma</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.4.0 You were born to survive, and raised to adapt.
Whenever you are in the Injured State , Made for This activates and you benefit from the following effects:
Grants the Endurance Status Effect for 6 / 8 / 10 seconds, after completing a Healing action on another Survivor.
Endurance is cancelled prematurely when performing a Conspicuous Action .
Grants a 1 / 2 / 3 % Haste Status Effect while running and also suffering from the Deep Wound Status Effect.

"I didn''t come here to be robot food!" — Gabriel Soma', 'Gabriel_Soma');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Mettle_of_Man', 'survivor', 'Mettle of Man', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/52/IconPerks_mettleOfMan.png/revision/latest?cb=20190402180459', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.2 / 6.1.3</div><div class="dynamicContent ptb">Evil has a way of always finding you.
<p>After triggering your <b><span class="luaClr clr clr2" style="color: #e8c252;">third</span></b> <i><a href="https://deadbydaylight.fandom.com/wiki/Protection_Hit" class="mw-redirect" title="Protection Hit">Protection Hit</a></i>, <i>Mettle of Man</i> activates:
</p><ul><li>While injured, <i>Mettle of Man</i> shields you from going down the next time you take damage.</li>
<li>Healing back to full health will reveal your <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> to the Killer whenever you are farther than <b><span class="luaClr clr clr2" style="color: #e8c252;">12</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">14</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>metres</b> from them.</li></ul>
<p><i>Mettle of Man</i> deactivates the next time you are put into the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span>.
</p><p><b>Increases</b> your chance of becoming the initial  <i><b>Obsession</b></i> by increasing the default value by <b>+100&nbsp;%</b>.
</p><p><i>The Killer can only be <b>obsessed</b> with one Survivor at a time.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Evil has a bullseye on my back the size of Tiger Stadium." — Ash Williams</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.2 / 6.1.3 Evil has a way of always finding you.
After triggering your third Protection Hit , Mettle of Man activates:
While injured, Mettle of Man shields you from going down the next time you take damage.
Healing back to full health will reveal your Aura to the Killer whenever you are farther than 12 / 14 / 16 metres from them.
Mettle of Man deactivates the next time you are put into the Dying State .
Increases your chance of becoming the initial Obsession by increasing the default value by +100 %.
The Killer can only be obsessed with one Survivor at a time.
"Evil has a bullseye on my back the size of Tiger Stadium." — Ash Williams', 'Ash_Williams');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Mirrored_Illusion', 'survivor', 'Mirrored Illusion', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/97/IconPerks_mirroredIllusion.png/revision/latest?cb=20240514174203', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">A familiar spell made unfamiliar in this corrupted landscape.
<p>After repairing <b>Generators</b> for a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">20&nbsp;%</span></b>, <i>Mirrored Illusion</i> activates:
</p><ul><li>Press the <i>Active Ability button</i> when next to either a <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chest</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span>, <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gate</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span>, <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span>, or a <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span> to spawn a <i><b>Static Illusion</b></i> that lasts for <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.</li></ul>

<i>Mirrored Illusion</i> deactivates after triggering successfully.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Just... stay there... perfect!" — Baermar</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 A familiar spell made unfamiliar in this corrupted landscape.
After repairing Generators for a total of 20 % , Mirrored Illusion activates:
Press the Active Ability button when next to either a Chest , Exit Gate , Generator , or a Totem to spawn a Static Illusion that lasts for 40 / 50 / 60 seconds.

Mirrored Illusion deactivates after triggering successfully.
"Just... stay there... perfect!" — Baermar', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Moment_of_Glory', 'survivor', 'Moment of Glory', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconPerks_MomentOfGlory.png/revision/latest?cb=20240806171421', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">A hero should always have the chance to make a comeback.
<p>After performing the <i>Unlocking or Rummaging</i> action on <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chests</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">2 times</span></b>, <i>Moment of Glory</i> activates:
</p><ul><li>When you become injured, you instantly suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/64?cb=20180829073317"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/32?cb=20180829073317"></a></span></span></span></b></i> <b>Status Effect</b>.</li>
<li>You are automatically healed <b><span class="luaClr clr clr6" style="color: #ff8800;">1</span></b> <b>Health State</b> after <b><span class="luaClr clr clr2" style="color: #e8c252;">80</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">70</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b>.
<ul><li>This effect is cancelled prematurely if you enter the <i>Dying State</i>.</li></ul></li></ul>

<i>Moment of Glory</i> does not activate if you already suffer from the <i><b>Broken</b></i> <b>Status Effect</b>.<br><i>Moment of Glory</i> deactivates after healing you.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Never lose hope for a brighter tomorrow." — Trevor</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 A hero should always have the chance to make a comeback.
After performing the Unlocking or Rummaging action on Chests a total of 2 times , Moment of Glory activates:
When you become injured, you instantly suffer from the Broken Status Effect.
You are automatically healed 1 Health State after 80 / 70 / 60 seconds.
This effect is cancelled prematurely if you enter the Dying State.

Moment of Glory does not activate if you already suffer from the Broken Status Effect. Moment of Glory deactivates after healing you.
"Never lose hope for a brighter tomorrow." — Trevor', 'Trevor_Belmont');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('No_Mither', 'survivor', 'No Mither', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f5/IconPerks_noMither.png/revision/latest?cb=20170727161003', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 5.3.0</div><div class="dynamicContent ptb">Go on out, kid, it is just a scratch.<br>Your thick blood coagulates practically instantly.
<p>The following effects apply <b><span class="luaClr clr clr2" style="color: #e8c252;">permanently</span></b> during the Trial:
</p><ul><li>Suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/64?cb=20180829073317"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/32?cb=20180829073317"></a></span></span></span></b></i> <b>Status Effect</b>.</li>
<li><b>Suppresses</b> the creation of <a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood">Pools of Blood</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span>.</li>
<li><b>Reduces</b> the volume of <i>Grunts of Pain</i> while either in the Injured or the Dying State by <b><span class="luaClr clr clr2" style="color: #e8c252;">25</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">75</span></b> <b>%</b>.</li>
<li><b>Increases</b> your Recovery speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">15</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">20</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">25</span></b> <b>%</b>.</li>
<li>Unlocks the <i>Self-Recovery</i> ability, allowing you to fully recover from the Dying State.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I lost it. Just lamped him one. They went and banned me didn''t they. Went t''pub afterwards, had a few pints and moved on to the next chapter. I couldn''t be mithered with it all anyway, you know what I mean? Can''t be arsed." — David King</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 5.3.0 Go on out, kid, it is just a scratch. Your thick blood coagulates practically instantly.
The following effects apply permanently during the Trial:
Suffer from the Broken Status Effect.
Suppresses the creation of Pools of Blood .
Reduces the volume of Grunts of Pain while either in the Injured or the Dying State by 25 / 50 / 75 %.
Increases your Recovery speed by 15 / 20 / 25 %.
Unlocks the Self-Recovery ability, allowing you to fully recover from the Dying State.

"I lost it. Just lamped him one. They went and banned me didn''t they. Went t''pub afterwards, had a few pints and moved on to the next chapter. I couldn''t be mithered with it all anyway, you know what I mean? Can''t be arsed." — David King', 'David_King');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('No_One_Left_Behind', 'survivor', 'No One Left Behind', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b0/IconPerks_noOneLeftBehind.png/revision/latest?cb=20160605205026', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">It is inconceivable to leave someone behind.
<p>Once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are powered, <i>No One Left Behind</i> activates:
</p><ul><li><b>Increases</b> your Action speeds for Healing and Unhooking by <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b>.</li>
<li><b>Increases</b> the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> of Survivors unhooked by you by <b><span class="luaClr clr clr2" style="color: #e8c252;">+7&nbsp;%</span></b>.</li>
<li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the other Survivors are revealed to you.</li>
<li>Grants <b><span class="luaClr clr clr2" style="color: #e8c252;">50</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">75</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">100</span></b> <b>%</b> bonus <a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints">Bloodpoints</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="58" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/64?cb=20180702212847"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="87" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/96?cb=20180702212847"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bloodpoints" title="Bloodpoints"><img alt="IconCurrency bloodpoints" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="29" class="mw-file-element lazyload" data-image-name="IconCurrency bloodpoints.png" data-image-key="IconCurrency_bloodpoints.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconCurrency_bloodpoints.png/revision/latest/scale-to-width-down/32?cb=20180702212847"></a></span></span></span> for actions in the <a href="https://deadbydaylight.fandom.com/wiki/Altruism" class="mw-redirect" title="Altruism">Altruism</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Altruism" title="Altruism"><img alt="DailyRitualIcon altruism" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="DailyRitualIcon altruism.png" data-image-key="DailyRitualIcon_altruism.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/13/DailyRitualIcon_altruism.png/revision/latest/scale-to-width-down/64?cb=20160607183413"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Altruism" title="Altruism"><img alt="DailyRitualIcon altruism" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="DailyRitualIcon altruism.png" data-image-key="DailyRitualIcon_altruism.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/13/DailyRitualIcon_altruism.png/revision/latest/scale-to-width-down/96?cb=20160607183413"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Altruism" title="Altruism"><img alt="DailyRitualIcon altruism" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="DailyRitualIcon altruism.png" data-image-key="DailyRitualIcon_altruism.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/13/DailyRitualIcon_altruism.png/revision/latest/scale-to-width-down/32?cb=20160607183413"></a></span></span></span> Category.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Yeah, no shit.<br>But I believe we can outsmart and overthrow him if we work together.<br>Don''t be predictable and selfish!" — Clyde, The Lost Tapes</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 It is inconceivable to leave someone behind.
Once the Exit Gates are powered, No One Left Behind activates:
Increases your Action speeds for Healing and Unhooking by 30 / 40 / 50 %.
Increases the Haste Status Effect of Survivors unhooked by you by +7 % .
The Auras of the other Survivors are revealed to you.
Grants 50 / 75 / 100 % bonus Bloodpoints for actions in the Altruism Category.

"Yeah, no shit. But I believe we can outsmart and overthrow him if we work together. Don''t be predictable and selfish!" — Clyde, The Lost Tapes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Object_of_Obsession', 'survivor', 'Object of Obsession', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/2b/IconPerks_objectOfObsession.png/revision/latest?cb=20161023112952', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 4.7.0</div><div class="dynamicContent ptb">A supernatural bond links you to the Killer.
<p>Whenever the Killer reads your <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span>, <i>Object of Obsession</i> activates for the same duration as their Aura-reading action:
</p><ul><li>The Aura of the Killer is revealed to you.</li>
<li><b>Increases</b> your Action speeds for Cleansing, Healing, and Repairing actions by <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>%</b>.</li></ul>

If you are the Killer''s current <i><b><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession">Obsession</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/64?cb=20170907150350"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/96?cb=20170907150350"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Obsession" title="Obsession"><img alt="IconHelp obsession" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp obsession.png" data-image-key="IconHelp_obsession.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/af/IconHelp_obsession.png/revision/latest/scale-to-width-down/32?cb=20170907150350"></a></span></span></span></b></i>, the following effect triggers automatically every <b><span class="luaClr clr clr2" style="color: #e8c252;">30 seconds</span></b>:
<ul><li>Your Aura is revealed to the Killer for <b><span class="luaClr clr clr6" style="color: #ff8800;">3 seconds</span></b>.</li></ul>

<b>Increases</b> your chance of becoming the initial  <i><b>Obsession</b></i> by increasing the default value by <b>+100&nbsp;%</b>.<br><i>The Killer can only be <b>obsessed</b> with one Survivor at a time.</i>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"He was watching me!" — Laurie Strode</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 4.7.0 A supernatural bond links you to the Killer.
Whenever the Killer reads your Aura , Object of Obsession activates for the same duration as their Aura-reading action:
The Aura of the Killer is revealed to you.
Increases your Action speeds for Cleansing, Healing, and Repairing actions by 2 / 4 / 6 %.

If you are the Killer''s current Obsession , the following effect triggers automatically every 30 seconds :
Your Aura is revealed to the Killer for 3 seconds .

Increases your chance of becoming the initial Obsession by increasing the default value by +100 %. The Killer can only be obsessed with one Survivor at a time.
"He was watching me!" — Laurie Strode', 'Laurie_Strode');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Off_the_Record', 'survivor', 'Off the Record', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconPerks_offTheRecord.png/revision/latest?cb=20200218172747', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">You have learnt that a quiet approach is sometimes best.
<p>After being unhooked or unhooking yourself, <i>Off the Record</i> activates for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">70</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">80</span></b> <b>seconds</b>:
</p><ul><li><b>Prevents</b> your <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> from being revealed to the <a href="https://deadbydaylight.fandom.com/wiki/Killer" class="mw-redirect" title="Killer">Killer</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Killer" title="Killer"><img alt="IconHelpLoading killer" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="61" class="mw-file-element lazyload" data-image-name="IconHelpLoading killer.png" data-image-key="IconHelpLoading_killer.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/06/IconHelpLoading_killer.png/revision/latest/scale-to-width-down/64?cb=20220324212743"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Killer" title="Killer"><img alt="IconHelpLoading killer" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="92" class="mw-file-element lazyload" data-image-name="IconHelpLoading killer.png" data-image-key="IconHelpLoading_killer.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/06/IconHelpLoading_killer.png/revision/latest/scale-to-width-down/96?cb=20220324212743"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Killer" title="Killer"><img alt="IconHelpLoading killer" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="23" class="mw-file-element lazyload" data-image-name="IconHelpLoading killer.png" data-image-key="IconHelpLoading_killer.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/06/IconHelpLoading_killer.png/revision/latest/scale-to-width-down/24?cb=20220324212743"></a></span></span></span>, if they attempt to read it.</li>
<li><b>Suppresses </b><i>Grunts of Pain</i> when injured.</li>
<li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Endurance" class="mw-redirect" title="Endurance">Endurance</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/64?cb=20170620154928"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/96?cb=20170620154928"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/32?cb=20170620154928"></a></span></span></span></b></i> <b>Status Effect</b>.
<ul><li><i><b>Endurance</b></i> is cancelled prematurely when performing a <i><a href="https://deadbydaylight.fandom.com/wiki/Conspicuous_Action" class="mw-redirect" title="Conspicuous Action">Conspicuous Action</a></i>.</li></ul></li></ul>


<p><i>Off the Record</i> deactivates once the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gates</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are powered.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Trust me, I investigate thoroughly and discreetly." — Zarina Kassir</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 You have learnt that a quiet approach is sometimes best.
After being unhooked or unhooking yourself, Off the Record activates for the next 60 / 70 / 80 seconds :
Prevents your Aura from being revealed to the Killer , if they attempt to read it.
Suppresses Grunts of Pain when injured.
Grants the Endurance Status Effect.
Endurance is cancelled prematurely when performing a Conspicuous Action .

Off the Record deactivates once the Exit Gates are powered.
"Trust me, I investigate thoroughly and discreetly." — Zarina Kassir', 'Zarina_Kassir');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Open-Handed', 'survivor', 'Open-Handed', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5d/IconPerks_open-Handed.png/revision/latest?cb=20161210091243', 'Strengthens the potential in your and your team''s Aura-reading abilities.
<ul><li><b>Increases</b> the radius of all Aura-reading abilities emanating from yourself or other Survivors by <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>metres</b>.</li></ul>
<p>Survivors can only be affected by one instance of <i>Open-Handed</i> at a time.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Paying attention is what kept me alive through the years. That, and my good looks of course." — Ace Visconti</span></i>
</p>', 'Strengthens the potential in your and your team''s Aura-reading abilities.
Increases the radius of all Aura-reading abilities emanating from yourself or other Survivors by 8 / 12 / 16 metres.
Survivors can only be affected by one instance of Open-Handed at a time.

"Paying attention is what kept me alive through the years. That, and my good looks of course." — Ace Visconti', 'Ace_Visconti');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Overcome', 'survivor', 'Overcome', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/82/IconPerks_overcome.png/revision/latest?cb=20211109180747', 'You have calculated how much energy you can risk to expend.
<p>Becoming injured by any means triggers <i>Overcome</i>:
</p><ul><li>Extends the duration of the <i>On-hit Speed Boost</i> by <b><span class="luaClr clr clr2" style="color: #e8c252;">+2 seconds</span></b>.</li></ul>

<i>Overcome</i> causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.<br><i>Overcome</i> cannot be used when <i><b>Exhausted</b></i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"After careful analysis, we are getting the hell out of here!" — Jonah Vasquez</span></i>
</p>', 'You have calculated how much energy you can risk to expend.
Becoming injured by any means triggers Overcome :
Extends the duration of the On-hit Speed Boost by +2 seconds .

Overcome causes the Exhausted Status Effect for 60 / 50 / 40 seconds. Overcome cannot be used when Exhausted .
"After careful analysis, we are getting the hell out of here!" — Jonah Vasquez', 'Jonah_Vasquez');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Overzealous', 'survivor', 'Overzealous', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/99/IconPerks_overzealous.png/revision/latest?cb=20220518112819', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.7.0</div><div class="dynamicContent ptb">Fighting back against the Ravage motivates and inspires you.
<p>After cleansing or blessing a <a href="https://deadbydaylight.fandom.com/wiki/Totem" class="mw-redirect" title="Totem">Totem</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/64?cb=20170625095626"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/96?cb=20170625095626"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Totem" title="Totem"><img alt="IconHelpLoading totem" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading totem.png" data-image-key="IconHelpLoading_totem.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e9/IconHelpLoading_totem.png/revision/latest/scale-to-width-down/32?cb=20170625095626"></a></span></span></span>, <i>Overzealous</i> activates:
</p><ul><li><b><span class="luaClr clr clr13" style="color: #418284;">Dull Totem</span></b>: <b>Increases</b> your Repair speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">9</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>%</b>.</li>
<li><b><span class="luaClr clr clr13" style="color: #418284;">Hex Totem</span></b>: <b>Increases</b> your Repair speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">16</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">18</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>%</b>.</li></ul>

<i>Overzealous</i> deactivates after losing a <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span> by any means.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"The Ravage senses us. We need to work fast." — Haddie Kaur, Ravages of the Abyss Episode 9</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.7.0 Fighting back against the Ravage motivates and inspires you.
After cleansing or blessing a Totem , Overzealous activates:
Dull Totem : Increases your Repair speed by 8 / 9 / 10 %.
Hex Totem : Increases your Repair speed by 16 / 18 / 20 %.

Overzealous deactivates after losing a Health State by any means.
"The Ravage senses us. We need to work fast." — Haddie Kaur, Ravages of the Abyss Episode 9', 'Haddie_Kaur');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Parental_Guidance', 'survivor', 'Parental Guidance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/46/IconPerks_parentalGuidance.png/revision/latest?cb=20220216120019', 'You have inherited the ability to hear the dead — and now the dead warn you of danger.
<ul><li>After stunning the Killer by any means, <i>Parental Guidance</i> suppresses your <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span>, <a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood">Pools of Blood</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span>, and <i>Grunts of Pain</i> for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">6</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">7</span></b> <b>seconds</b>.</li></ul>
<p><br>
</p>
', 'You have inherited the ability to hear the dead — and now the dead warn you of danger.
After stunning the Killer by any means, Parental Guidance suppresses your Scratch Marks , Pools of Blood , and Grunts of Pain for the next 5 / 6 / 7 seconds.', 'Yoichi_Asakawa');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Pharmacy', 'survivor', 'Pharmacy', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f1/IconPerks_pharmacy.png/revision/latest?cb=20171026230450', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">You have a knack for finding medicine.
<p>Whenever you are in the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>, <i>Pharmacy</i> activates:
</p><ul><li><b>Increases</b> the Unlocking speed of <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chests</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">60</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">80</span></b> <b>%</b>.</li>
<li><b>Reduces</b> the Hearing range of noises related to Unlocking by <b><span class="luaClr clr clr2" style="color: #e8c252;">-8 metres</span></b>.</li>
<li><b>Guarantees</b> an <a href="https://deadbydaylight.fandom.com/wiki/Emergency_Med-Kit" title="Emergency Med-Kit">Emergency Med-Kit</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span style="display:inline-flex; vertical-align: middle; position:relative; height: 32px; width: 32px"><span class="margin-auto" style="display: inline-flex; position: absolute; top: 0px; max-width: 32px;"><span class="game-element-container flex relative"><span class="game-element-bg-settings game-element-bg-settings-size-perk rare-item-element" style="width: 32px; height: 32px;"></span><span class="game-element-bg-settings-size-sos absolute" style="width: 32px; height: 32px;"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Emergency_Med-Kit" title="Emergency Med-Kit"><img alt="IconItems emergencyMedKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="300" height="300" class="mw-file-element lazyload" data-image-name="IconItems emergencyMedKit.png" data-image-key="IconItems_emergencyMedKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/29/IconItems_emergencyMedKit.png/revision/latest?cb=20240313184834"></a></span></span></span></span></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Emergency_Med-Kit" title="Emergency Med-Kit"><img alt="IconItems emergencyMedKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems emergencyMedKit.png" data-image-key="IconItems_emergencyMedKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/29/IconItems_emergencyMedKit.png/revision/latest/scale-to-width-down/96?cb=20240313184834"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Emergency_Med-Kit" title="Emergency Med-Kit"><img alt="IconItems emergencyMedKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems emergencyMedKit.png" data-image-key="IconItems_emergencyMedKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/29/IconItems_emergencyMedKit.png/revision/latest/scale-to-width-down/32?cb=20240313184834"></a></span></span></span> when unlocking a Chest.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Adrenaline, it is going to keep us awake. I stole it from one of the Nurse''s carts." — Quentin Smith</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 You have a knack for finding medicine.
Whenever you are in the Injured State , Pharmacy activates:
Increases the Unlocking speed of Chests by 40 / 60 / 80 %.
Reduces the Hearing range of noises related to Unlocking by -8 metres .
Guarantees an Emergency Med-Kit when unlocking a Chest.
"Adrenaline, it is going to keep us awake. I stole it from one of the Nurse''s carts." — Quentin Smith', 'Quentin_Smith');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Plot_Twist', 'survivor', 'Plot Twist', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ac/IconPerks_plotTwist.png/revision/latest?cb=20230705160003', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">Big moments are vital, but you know that sometimes an understated read can be just as powerful.
<p>Whenever you are in the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>, <i>Plot Twist</i> activates:
</p><ul><li>While crouching and motionless, press the <i>Active Ability button</i> to silently enter the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> with the following benefits:
<ul><li><b>Suppresses</b> <i>Grunts of Pain</i>.</li>
<li><b>Suppresses</b> <a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood">Pools of Blood</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pools_of_Blood" title="Pools of Blood"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span>.</li>
<li><b>Grants</b> the ability to fully recover from the Dying State.</li></ul></li>
<li>After full recovery using <i>Plot Twist</i>, you are healed instantly and gain a <b><span class="luaClr clr clr2" style="color: #e8c252;">+50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>seconds</b>.</li></ul>

<i>Plot Twist</i> deactivates after recovering yourself by any means and reactivates once more once the <b>Exit Gates</b> are powered.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I think you''ll find this shooting location... captivating." — Pauline Stamper</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 Big moments are vital, but you know that sometimes an understated read can be just as powerful.
Whenever you are in the Injured State , Plot Twist activates:
While crouching and motionless, press the Active Ability button to silently enter the Dying State with the following benefits:
Suppresses Grunts of Pain.
Suppresses Pools of Blood .
Grants the ability to fully recover from the Dying State.
After full recovery using Plot Twist, you are healed instantly and gain a +50 % Haste Status Effect for 2 / 3 / 4 seconds.

Plot Twist deactivates after recovering yourself by any means and reactivates once more once the Exit Gates are powered.
"I think you''ll find this shooting location... captivating." — Pauline Stamper', 'Nicolas_Cage');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Plunderer%27s_Instinct', 'survivor', 'Plunderer''s Instinct', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/28/IconPerks_plunderersInstinct.png/revision/latest?cb=20160605205031', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability and improves your luck when finding Items in Chests:
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the following objects are revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">32</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">48</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">64</span></b> <b>metres</b>:
<ul><li>Closed <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chests</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> located in the environment.</li>
<li><a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Items</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span> sitting inside opened <b>Chests</b>.</li>
<li><b>Items</b> dropped in the environment.</li></ul></li>
<li><b>Increases</b> the Odds of finding <b>Items</b> of higher Rarities in <b>Chests</b> by <b><span class="luaClr clr clr2" style="color: #e8c252;">+50&nbsp;%</span></b>.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"The pioneers used to loot these babies for hours." — Aizeyu, The Lost Tapes</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 Unlocks potential in your Aura-reading ability and improves your luck when finding Items in Chests:
The Auras of the following objects are revealed to you within 32 / 48 / 64 metres :
Closed Chests located in the environment.
Items sitting inside opened Chests.
Items dropped in the environment.
Increases the Odds of finding Items of higher Rarities in Chests by +50 % .
"The pioneers used to loot these babies for hours." — Aizeyu, The Lost Tapes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Poised', 'survivor', 'Poised', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/52/IconPerks_poised.png/revision/latest?cb=20190308175429', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">Achieving goals boosts your confidence.
<p>Whenever a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> is completed, you benefit from the following effect for <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">14</span></b> <b>seconds</b>:
</p><ul><li><b>Suppresses</b> the creation of your <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span>.</li></ul>

First starting to repair a given <b>Generator</b> reveals the Aura of the Killer to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">6 seconds</span></b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Ok, stay calm. Don''t overthink it and just keep moving forward: you got this." — Jane Romero</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 Achieving goals boosts your confidence.
Whenever a Generator is completed, you benefit from the following effect for 10 / 12 / 14 seconds :
Suppresses the creation of your Scratch Marks .

First starting to repair a given Generator reveals the Aura of the Killer to you for 6 seconds .
"Ok, stay calm. Don''t overthink it and just keep moving forward: you got this." — Jane Romero', 'Jane_Romero');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Potential_Energy', 'survivor', 'Potential Energy', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/07/IconPerks_potentialEnergy.png/revision/latest?cb=20221102143127', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.4.0</div><div class="dynamicContent ptb">Your arcane abilities have adapted to The Entity''s Realm after centuries of wandering, granting you unprecedented control over its many devices.
<p>After uninterruptedly repairing <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> for a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">12</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">10</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>seconds</b>, press the <i>Active Ability button</i> to activate <i>Potential Energy</i>:
</p><ul><li>Continuing to repair the Generator will charge <i>Potential Energy</i> instead of progressing the Generator.</li>
<li><b>Converts</b> <b><span class="luaClr clr clr2" style="color: #e8c252;">1.5&nbsp;%</span></b> of Repair progression into <b><span class="luaClr clr clr6" style="color: #ff8800;">1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr8" style="color: #d41c1c;">20 Tokens</span></b>.</li>
<li>Missing <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> results in losing some Tokens.</li></ul>


<p>When <i>Potential Energy</i> has at least <b><span class="luaClr clr clr4" style="color: #ac3ee3;">1 Token</span></b>, press the <i>Active Ability button</i> while repairing a Generator to instantly progress it by <b><span class="luaClr clr clr3" style="color: #199b1e;">+1&nbsp;%</span></b> per accumulated Token, deactivating <i>Potential Energy</i>.
</p><p><i>Potential Energy</i> loses all Tokens and deactivates upon losing a <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"When you look a layer deeper, you realise... everything is connected." — Vittorio Toscano</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.4.0 Your arcane abilities have adapted to The Entity''s Realm after centuries of wandering, granting you unprecedented control over its many devices.
After uninterruptedly repairing Generators for a total of 12 / 10 / 8 seconds, press the Active Ability button to activate Potential Energy :
Continuing to repair the Generator will charge Potential Energy instead of progressing the Generator.
Converts 1.5 % of Repair progression into 1 Token , up to a maximum of 20 Tokens .
Missing Skill Checks results in losing some Tokens.

When Potential Energy has at least 1 Token , press the Active Ability button while repairing a Generator to instantly progress it by +1 % per accumulated Token, deactivating Potential Energy.
Potential Energy loses all Tokens and deactivates upon losing a Health State .
"When you look a layer deeper, you realise... everything is connected." — Vittorio Toscano', 'Vittorio_Toscano');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Power_Struggle', 'survivor', 'Power Struggle', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4b/IconPerks_powerStruggle.png/revision/latest?cb=20201112095050', 'You have never given up and you are not about to start now.
<p class="mw-empty-elt">
</p><ul><li>Reveals the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of available <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallets</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span> whenever you are in the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span>.</li></ul>
<p>While being carried by The Killer, reaching <b><span class="luaClr clr clr2" style="color: #e8c252;">25</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">20</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">15</span></b> <b>%</b> Wiggling progression activates <i>Power Struggle</i>:
</p><ul><li>You can drop a nearby, standing Pallet to stun the Killer and escape their grasp.</li></ul>
<p><i>Power Struggle</i> deactivates after triggering successfully.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I relied on others to protect me once and I lost everything. Never again." — Élodie Rakoto</span></i>
</p>', 'You have never given up and you are not about to start now.

Reveals the Auras of available Pallets whenever you are in the Dying State .
While being carried by The Killer, reaching 25 / 20 / 15 % Wiggling progression activates Power Struggle :
You can drop a nearby, standing Pallet to stun the Killer and escape their grasp.
Power Struggle deactivates after triggering successfully.
"I relied on others to protect me once and I lost everything. Never again." — Élodie Rakoto', '%C3%89lodie_Rakoto');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Premonition', 'survivor', 'Premonition', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/39/IconPerks_premonition.png/revision/latest?cb=20160605205043', 'You have the undeniable capability to sense danger.
<ul><li>Receive an auditory warning upon looking in the Killer''s direction within a <b><span class="luaClr clr clr2" style="color: #e8c252;">45 °</span></b> cone within <b><span class="luaClr clr clr6" style="color: #ff8800;">36 metres</span></b>.</li></ul>
<p><i>Premonition</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">45</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b> each time it activates.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I have a bad feeling about this!"</span></i>
</p>', 'You have the undeniable capability to sense danger.
Receive an auditory warning upon looking in the Killer''s direction within a 45 ° cone within 36 metres .
Premonition has a cool-down of 60 / 45 / 30 seconds each time it activates.
"I have a bad feeling about this!"', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Prove_Thyself', 'survivor', 'Prove Thyself', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0f/IconPerks_proveThyself.png/revision/latest?cb=20160605205049', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb"><b>Increases</b> the Repair speed by a stack-able <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>%</b> per other Survivor within <b><span class="luaClr clr clr2" style="color: #e8c252;">4 metres</span></b> of your location, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">18</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">24</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b>.
<p><i>Prove Thyself</i> extends its effect to all Survivors within its range.
</p><p>Survivors can only be affected by one instance of <i>Prove Thyself</i> at a time.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Show me what you can do!" — Dwight Fairfield</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 Increases the Repair speed by a stack-able 6 / 8 / 10 % per other Survivor within 4 metres of your location, up to a maximum of 18 / 24 / 30 %.
Prove Thyself extends its effect to all Survivors within its range.
Survivors can only be affected by one instance of Prove Thyself at a time.
"Show me what you can do!" — Dwight Fairfield', 'Dwight_Fairfield');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Quick_%26_Quiet', 'survivor', 'Quick & Quiet', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconPerks_quickAndQuiet.png/revision/latest?cb=20160605205055', 'You do not make as much noise as others when quickly vaulting over obstacles or hiding in Lockers.
<ul><li><b>Suppresses</b> both the <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> and the sound effects triggered by rushing to vault <a href="https://deadbydaylight.fandom.com/wiki/Window" class="mw-redirect" title="Window">Windows</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="57" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/64?cb=20170921093258"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="85" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/96?cb=20170921093258"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="28" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/32?cb=20170921093258"></a></span></span></span>, <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallets</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span>, or rushing to enter or exit <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Lockers</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span>.</li></ul>
<p><i>Quick &amp; Quiet</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>.
</p>', 'You do not make as much noise as others when quickly vaulting over obstacles or hiding in Lockers.
Suppresses both the Loud Noise Notification and the sound effects triggered by rushing to vault Windows , Pallets , or rushing to enter or exit Lockers .
Quick & Quiet has a cool-down of 30 / 25 / 20 seconds.', 'Meg_Thomas');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Quick_Gambit', 'survivor', 'Quick Gambit', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconPerks_quickGambit.png/revision/latest?cb=20221102143123', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">When you have the Killer''s attention, you know how to keep it; others can be confident they will not be interrupted any time soon.
<p>While being chased by the Killer, the following effects apply:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of other Survivors are revealed to you.</li>
<li><b>Increases</b> the Repair speed of other Survivors by <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>%</b>.</li></ul>

<i>Quick Gambit</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">60 seconds</span></b> upon losing a <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"We need not resort to violence. And I shall prove it." — Vittorio Toscano</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 When you have the Killer''s attention, you know how to keep it; others can be confident they will not be interrupted any time soon.
While being chased by the Killer, the following effects apply:
The Auras of other Survivors are revealed to you.
Increases the Repair speed of other Survivors by 3 / 4 / 5 %.

Quick Gambit has a cool-down of 60 seconds upon losing a Health State .
"We need not resort to violence. And I shall prove it." — Vittorio Toscano', 'Vittorio_Toscano');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Reactive_Healing', 'survivor', 'Reactive Healing', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconPerks_reactiveHealing.png/revision/latest?cb=20220815051757', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.2.0</div><div class="dynamicContent ptb">The more the situation becomes compromised, the more determined you become to complete the operation.
<p>Whenever another Survivor within <b><span class="luaClr clr clr2" style="color: #e8c252;">32 metres</span></b> of your location loses a <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span> by any means while you are in the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>, you benefit from the following effect:
</p><ul><li>Grants <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">45</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b> of your missing Healing Progression towards your Health Bar.</li></ul>

</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.2.0 The more the situation becomes compromised, the more determined you become to complete the operation.
Whenever another Survivor within 32 metres of your location loses a Health State by any means while you are in the Injured State , you benefit from the following effect:
Grants 40 / 45 / 50 % of your missing Healing Progression towards your Health Bar.', 'Ada_Wong');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Reassurance', 'survivor', 'Reassurance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5b/IconPerks_reassurance.png/revision/latest?cb=20220815051841', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.2.0</div><div class="dynamicContent ptb">Your presence helps allies focus, assuaging the panic associated with extreme conditions.
<ul><li>Press the <i>Active Ability button</i> while within <b><span class="luaClr clr clr2" style="color: #e8c252;">6 metres</span></b> of a hooked Survivor to pause their <i>Sacrifice Process</i> for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.
<ul><li>This also pauses any <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span>, if the Survivor is in the <i>Struggle Phase</i>.</li></ul></li></ul>
<i>Reassurance</i> can only be used once per Survivor per <i>Hook Instance</i>.</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.2.0 Your presence helps allies focus, assuaging the panic associated with extreme conditions.
Press the Active Ability button while within 6 metres of a hooked Survivor to pause their Sacrifice Process for the next 20 / 25 / 30 seconds.
This also pauses any Skill Checks , if the Survivor is in the Struggle Phase.
Reassurance can only be used once per Survivor per Hook Instance.', 'Rebecca_Chambers');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Red_Herring', 'survivor', 'Red Herring', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1c/IconPerks_redHerring.png/revision/latest?cb=20200218172728', 'You have noticed that people pay attention to whatever makes the loudest noise.<br>
<p>After repairing a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> for at least <b><span class="luaClr clr clr2" style="color: #e8c252;">3 seconds</span></b>, its <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> is highlighted to you in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.
</p>
<ul><li>The Generator stays highlighted until it is either fully repaired, you start repairing another Generator, or enter a <a href="https://deadbydaylight.fandom.com/wiki/Locker" class="mw-redirect" title="Locker">Locker</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/64?cb=20170907141534"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/96?cb=20170907141534"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Locker" title="Locker"><img alt="IconHelp lockers" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp lockers.png" data-image-key="IconHelp_lockers.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d1/IconHelp_lockers.png/revision/latest/scale-to-width-down/32?cb=20170907141534"></a></span></span></span>.</li>
<li>Entering a Locker will trigger a <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> for the Killer at the highlighted Generator''s location.</li></ul>
<p><i>Red Herring</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.<br>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"The news edit out what is burdensome and complex. which is the truth." — Zarina Kassir</span></i>
</p>', 'You have noticed that people pay attention to whatever makes the loudest noise.
After repairing a Generator for at least 3 seconds , its Aura is highlighted to you in yellow .

The Generator stays highlighted until it is either fully repaired, you start repairing another Generator, or enter a Locker .
Entering a Locker will trigger a Loud Noise Notification for the Killer at the highlighted Generator''s location.
Red Herring has a cool-down of 60 / 50 / 40 seconds.
"The news edit out what is burdensome and complex. which is the truth." — Zarina Kassir', 'Zarina_Kassir');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Repressed_Alliance', 'survivor', 'Repressed Alliance', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/31/IconPerks_repressedAlliance.png/revision/latest?cb=20200526201745', 'You are accustomed to being hunted by malicious forces, and you have begun using it to your advantage.
<p>After repairing <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> for a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">55</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">45</span></b> <b>seconds</b>, <i>Repressed Alliance</i> activates:
</p><ul><li>Press the <i>Active Ability button</i> to call upon The <a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity">Entity</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/64?cb=20170907141947"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/96?cb=20170907141947"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Entity" title="Entity"><img alt="IconHelp entity" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp entity.png" data-image-key="IconHelp_entity.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconHelp_entity.png/revision/latest/scale-to-width-down/32?cb=20170907141947"></a></span></span></span> to block the Generator you are currently repairing for <b><span class="luaClr clr clr2" style="color: #e8c252;">30 seconds</span></b>, after which <i>Repressed Alliance</i> deactivates.</li>
<li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the blocked Generator is revealed to all Survivors in <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li></ul>
<p><i>Repressed Alliance</i> can only be triggered when no other Survivors are repairing your Generator.
</p>', 'You are accustomed to being hunted by malicious forces, and you have begun using it to your advantage.
After repairing Generators for a total of 55 / 50 / 45 seconds, Repressed Alliance activates:
Press the Active Ability button to call upon The Entity to block the Generator you are currently repairing for 30 seconds , after which Repressed Alliance deactivates.
The Aura of the blocked Generator is revealed to all Survivors in white .
Repressed Alliance can only be triggered when no other Survivors are repairing your Generator.', 'Cheryl_Mason');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Residual_Manifest', 'survivor', 'Residual Manifest', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d0/IconPerks_residualManifest.png/revision/latest?cb=20220518112819', 'A lifetime of chasing the darkness has taught you that the best disinfectant is light.
<ul><li>After a successful <i>Killer Blind</i>, the Killer suffers from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Blindness" class="mw-redirect" title="Blindness">Blindness</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/64?cb=20170620153742"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/96?cb=20170620153742"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Blindness" title="Blindness"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/32?cb=20170620153742"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.</li>
<li><i>Residual Manifest</i> grants the ability to rummage through an opened <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chest</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> once per Trial and will guarantee a basic <a href="https://deadbydaylight.fandom.com/wiki/Flashlight" title="Flashlight">Flashlight</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span style="display:inline-flex; vertical-align: middle; position:relative; height: 32px; width: 32px"><span class="margin-auto" style="display: inline-flex; position: absolute; top: 0px; max-width: 32px;"><span class="game-element-container flex relative"><span class="game-element-bg-settings game-element-bg-settings-size-perk uncommon-item-element" style="width: 32px; height: 32px;"></span><span class="game-element-bg-settings-size-sos absolute" style="width: 32px; height: 32px;"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flashlight" title="Flashlight"><img alt="IconItems flashlight" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="300" height="300" class="mw-file-element lazyload" data-image-name="IconItems flashlight.png" data-image-key="IconItems_flashlight.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconItems_flashlight.png/revision/latest?cb=20240313184805"></a></span></span></span></span></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flashlight" title="Flashlight"><img alt="IconItems flashlight" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems flashlight.png" data-image-key="IconItems_flashlight.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconItems_flashlight.png/revision/latest/scale-to-width-down/96?cb=20240313184805"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Flashlight" title="Flashlight"><img alt="IconItems flashlight" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems flashlight.png" data-image-key="IconItems_flashlight.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c3/IconItems_flashlight.png/revision/latest/scale-to-width-down/32?cb=20240313184805"></a></span></span></span>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I''ll never see what Haddie sees. But so long as I''m with her, I know I''m safe." — Jordan Rois, Ravages of the Abyss Episode 5</span></i>
</p>
', 'A lifetime of chasing the darkness has taught you that the best disinfectant is light.
After a successful Killer Blind, the Killer suffers from the Blindness Status Effect for 20 / 25 / 30 seconds.
Residual Manifest grants the ability to rummage through an opened Chest once per Trial and will guarantee a basic Flashlight .
"I''ll never see what Haddie sees. But so long as I''m with her, I know I''m safe." — Jordan Rois, Ravages of the Abyss Episode 5', 'Haddie_Kaur');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Resilience', 'survivor', 'Resilience', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ee/IconPerks_resilience.png/revision/latest?cb=20160605205100', 'You are motivated in dire situations.
<ul><li><b>Increases</b> your Action speeds for Repairing, Healing, Sabotaging, Unhooking, Vaulting, Cleansing, Blessing, Opening, and Unlocking by <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">6</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">9</span></b> <b>%</b> when in the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Focus, even in these desperate times."</span></i>
</p>', 'You are motivated in dire situations.
Increases your Action speeds for Repairing, Healing, Sabotaging, Unhooking, Vaulting, Cleansing, Blessing, Opening, and Unlocking by 3 / 6 / 9 % when in the Injured State .
"Focus, even in these desperate times."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Resurgence', 'survivor', 'Resurgence', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f3/IconPerks_resurgence.png/revision/latest?cb=20210526103300', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">You have come back from near impossible odds... and you will do it again.
<ul><li>Being unhooked or unhooking yourself grants you <b><span class="luaClr clr clr2" style="color: #e8c252;">50</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">60</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">70</span></b> <b>%</b> Healing progress.</li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"It''s my turn, bitch!" — Jill Valentine</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 You have come back from near impossible odds... and you will do it again.
Being unhooked or unhooking yourself grants you 50 / 60 / 70 % Healing progress.
"It''s my turn, bitch!" — Jill Valentine', 'Jill_Valentine');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Rookie_Spirit', 'survivor', 'Rookie Spirit', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/2f/IconPerks_rookieSpirit.png/revision/latest?cb=20210526103548', 'You keep a careful eye on objectives when they are slipping away.
<p>While repairing <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span>, succeed <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b>  Good or Great <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> to activate <i>Rookie Spirit</i> for the remainder of the Trial:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of any regressing Generators are revealed to you until they stop regressing by any means.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I''ll stop this, lieutenant. I promise." — Leon Scott Kennedy</span></i>
', 'You keep a careful eye on objectives when they are slipping away.
While repairing Generators , succeed 5 / 4 / 3 Good or Great Skill Checks to activate Rookie Spirit for the remainder of the Trial:
The Auras of any regressing Generators are revealed to you until they stop regressing by any means.

"I''ll stop this, lieutenant. I promise." — Leon Scott Kennedy', 'Leon_Scott_Kennedy');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Saboteur', 'survivor', 'Saboteur', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0e/IconPerks_saboteur.png/revision/latest?cb=20200220105714', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">Unlocks potential in your Aura-reading ability:
<ul><li>While the Killer is carrying another Survivor, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of all <a href="https://deadbydaylight.fandom.com/wiki/Hook" class="mw-redirect" title="Hook">Hooks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/64?cb=20170625095547"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/96?cb=20170625095547"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Hook" title="Hook"><img alt="IconHelpLoading hook" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading hook.png" data-image-key="IconHelpLoading_hook.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4f/IconHelpLoading_hook.png/revision/latest/scale-to-width-down/32?cb=20170625095547"></a></span></span></span> within <b><span class="luaClr clr clr2" style="color: #e8c252;">56 metres</span></b> of their original Pick-up location are revealed to you:
<ul><li>The Auras of normal <b>Hooks</b> are <b><span class="luaClr clr clr16" style="color: #ffffff;">white</span></b>.</li>
<li>The Auras of <b>Scourge Hooks</b> are <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.</li></ul></li></ul>
<p>Unlocks the ability to sabotage <b>Hooks</b> without <a href="https://deadbydaylight.fandom.com/wiki/Toolboxes" title="Toolboxes">Toolboxes</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Toolboxes" title="Toolboxes"><img alt="IconItems toolbox" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems toolbox.png" data-image-key="IconItems_toolbox.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1b/IconItems_toolbox.png/revision/latest/scale-to-width-down/64?cb=20240313184842"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Toolboxes" title="Toolboxes"><img alt="IconItems toolbox" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems toolbox.png" data-image-key="IconItems_toolbox.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1b/IconItems_toolbox.png/revision/latest/scale-to-width-down/96?cb=20240313184842"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Toolboxes" title="Toolboxes"><img alt="IconItems toolbox" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems toolbox.png" data-image-key="IconItems_toolbox.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1b/IconItems_toolbox.png/revision/latest/scale-to-width-down/32?cb=20240313184842"></a></span></span></span>:
</p>
<ul><li><b>Increases</b> the Sabotage speed without a <b>Toolbox</b> by <b><span class="luaClr clr clr6" style="color: #ff8800;">+30&nbsp;%</span></b>.
<ul><li>This effect has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">70</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">65</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">60</span></b> <b>seconds</b> after use.</li></ul></li></ul>
</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 Unlocks potential in your Aura-reading ability:
While the Killer is carrying another Survivor, the Auras of all Hooks within 56 metres of their original Pick-up location are revealed to you:
The Auras of normal Hooks are white .
The Auras of Scourge Hooks are yellow .
Unlocks the ability to sabotage Hooks without Toolboxes :

Increases the Sabotage speed without a Toolbox by +30 % .
This effect has a cool-down of 70 / 65 / 60 seconds after use.', 'Jake_Park');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Scavenger', 'survivor', 'Scavenger', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c6/IconPerks_scavenger.png/revision/latest?cb=20230524205539', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.0.0</div><div class="dynamicContent ptb">Where others see junk, you see valuable improvised tools.
<p>While holding a depleted <i>Toolbox</i>, <i>Scavenger</i> activates:
</p><ul><li>Succeeding at <i>Great Repairing Skill Checks</i> grants <b><span class="luaClr clr clr2" style="color: #e8c252;">1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr6" style="color: #ff8800;">5 Tokens</span></b>.</li>
<li>Reaching the maximum number of Tokens automatically consumes them and fully recharges the <i>Toolbox</i>.</li>
<li>Recharging a <i>Toolbox</i> will reduce your Repair speed by <b><span class="luaClr clr clr8" style="color: #d41c1c;">-50&nbsp;%</span></b> for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">40</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">35</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>seconds</b>.</li></ul>


<p><i>Scavenger</i> grants the ability to rummage through an opened <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chest</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> once per Trial and will guarantee a basic <a href="https://deadbydaylight.fandom.com/wiki/Toolbox" title="Toolbox">Toolbox</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span style="display:inline-flex; vertical-align: middle; position:relative; height: 32px; width: 32px"><span class="margin-auto" style="display: inline-flex; position: absolute; top: 0px; max-width: 32px;"><span class="game-element-container flex relative"><span class="game-element-bg-settings game-element-bg-settings-size-perk uncommon-item-element" style="width: 32px; height: 32px;"></span><span class="game-element-bg-settings-size-sos absolute" style="width: 32px; height: 32px;"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Toolbox" title="Toolbox"><img alt="IconItems toolbox" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="300" height="300" class="mw-file-element lazyload" data-image-name="IconItems toolbox.png" data-image-key="IconItems_toolbox.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1b/IconItems_toolbox.png/revision/latest?cb=20240313184842"></a></span></span></span></span></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Toolbox" title="Toolbox"><img alt="IconItems toolbox" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems toolbox.png" data-image-key="IconItems_toolbox.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1b/IconItems_toolbox.png/revision/latest/scale-to-width-down/96?cb=20240313184842"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Toolbox" title="Toolbox"><img alt="IconItems toolbox" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems toolbox.png" data-image-key="IconItems_toolbox.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/1b/IconItems_toolbox.png/revision/latest/scale-to-width-down/32?cb=20240313184842"></a></span></span></span>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"It''s amazing what people will throw away around here." — Gabriel Soma</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.0.0 Where others see junk, you see valuable improvised tools.
While holding a depleted Toolbox, Scavenger activates:
Succeeding at Great Repairing Skill Checks grants 1 Token , up to a maximum of 5 Tokens .
Reaching the maximum number of Tokens automatically consumes them and fully recharges the Toolbox.
Recharging a Toolbox will reduce your Repair speed by -50 % for the next 40 / 35 / 30 seconds.

Scavenger grants the ability to rummage through an opened Chest once per Trial and will guarantee a basic Toolbox .
"It''s amazing what people will throw away around here." — Gabriel Soma', 'Gabriel_Soma');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Scene_Partner', 'survivor', 'Scene Partner', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b4/IconPerks_scenePartner.png/revision/latest?cb=20230705160003', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">You lock in with your co-star, engaging with and reacting to each other on a higher level.
<p>Whenever you are inside the <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span>, <i>Scene Partner</i> activates:
</p><ul><li>Looking at the Killer causes you to scream, which reveals their <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> for <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">5</span></b> <b>seconds</b>.</li>
<li>There is a chance of <b><span class="luaClr clr clr2" style="color: #e8c252;">50&nbsp;%</span></b> that you will scream again, extending the Aura-reveal duration by another <b><span class="luaClr clr clr6" style="color: #ff8800;">2 seconds</span></b>.</li></ul>

<i>Scene Partner</i> has a cool-down of <b><span class="luaClr clr clr8" style="color: #d41c1c;">60 seconds</span></b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"This is not in the script!" — Nicolas Cage</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 You lock in with your co-star, engaging with and reacting to each other on a higher level.
Whenever you are inside the Terror Radius , Scene Partner activates:
Looking at the Killer causes you to scream, which reveals their Aura for 3 / 4 / 5 seconds.
There is a chance of 50 % that you will scream again, extending the Aura-reveal duration by another 2 seconds .

Scene Partner has a cool-down of 60 seconds .
"This is not in the script!" — Nicolas Cage', 'Nicolas_Cage');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Second_Wind', 'survivor', 'Second Wind', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/97/IconPerks_secondWind.png/revision/latest?cb=20190903175238', 'You have learnt to avoid awkward situations with parents.<br>Part of you still thinks your best option is to run away and hope things will take care of themselves.
<p>When you heal another <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivor</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> for the equivalent of <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b> <a href="https://deadbydaylight.fandom.com/wiki/Health_State" class="mw-redirect" title="Health State">Health State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/64?cb=20191126191136"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/96?cb=20191126191136"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Health_State" title="Health State"><img alt="IconStatusEffects healing" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects healing.png" data-image-key="IconStatusEffects_healing.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/70/IconStatusEffects_healing.png/revision/latest/scale-to-width-down/32?cb=20191126191136"></a></span></span></span>, <i>Second Wind</i> activates:
</p><ul><li>The next time you are unhooked or unhook yourself, you suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/64?cb=20180829073317"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Broken" title="Broken"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/32?cb=20180829073317"></a></span></span></span></b></i> <b>Status Effect</b> until <i>Second Wind</i> deactivates.</li>
<li>You are automatically healed <b><span class="luaClr clr clr6" style="color: #ff8800;">1</span></b> <b>Health State</b> after <b><span class="luaClr clr clr2" style="color: #e8c252;">28</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">24</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>.</li></ul>

While <i>Second Wind</i> is active, the following conditions will deactivate it:
<ul><li>Successfully being healed by <i>Second Wind</i>.</li>
<li>Being put into the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> before the timer elapses.</li></ul>

<i>Second Wind</i> does not activate if you already suffer from the <i><b>Broken</b></i> <b>Status Effect</b>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Yeah, that''s a no." — Steve Harrington</span></i>
</p>', 'You have learnt to avoid awkward situations with parents. Part of you still thinks your best option is to run away and hope things will take care of themselves.
When you heal another Survivor for the equivalent of 1 Health State , Second Wind activates:
The next time you are unhooked or unhook yourself, you suffer from the Broken Status Effect until Second Wind deactivates.
You are automatically healed 1 Health State after 28 / 24 / 20 seconds.

While Second Wind is active, the following conditions will deactivate it:
Successfully being healed by Second Wind.
Being put into the Dying State before the timer elapses.

Second Wind does not activate if you already suffer from the Broken Status Effect.
"Yeah, that''s a no." — Steve Harrington', 'Steve_Harrington');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Self-Care', 'survivor', 'Self-Care', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b2/IconPerks_self-Care.png/revision/latest?cb=20160605205112', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">
<ul><li>Unlocks the <i>Self-Care</i> ability, allowing you to self-heal without needing a <a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" class="mw-redirect" title="Med-Kit">Med-Kit</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/64?cb=20240313184755"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/96?cb=20240313184755"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/32?cb=20240313184755"></a></span></span></span> at <b><span class="luaClr clr clr2" style="color: #e8c252;">25</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">30</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">35</span></b> <b>%</b> of the normal Healing speed.</li></ul>
</div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0
Unlocks the Self-Care ability, allowing you to self-heal without needing a Med-Kit at 25 / 30 / 35 % of the normal Healing speed.', 'Claudette_Morel');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Self-Preservation', 'survivor', 'Self-Preservation', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/43/IconPerks_self-Preservation.png/revision/latest?cb=20210302172351', 'Life is unforgiving.<br>
<p>The more confirmation you get of that, the more prepared you become.<br>
Whenever another Survivor is hit with a <i><a href="https://deadbydaylight.fandom.com/wiki/Basic_Attack" class="mw-redirect" title="Basic Attack">Basic Attack</a></i> or <i><a href="https://deadbydaylight.fandom.com/wiki/Special_Attack" class="mw-redirect" title="Special Attack">Special Attack</a></i> within <b><span class="luaClr clr clr2" style="color: #e8c252;">16 metres</span></b> of you, <i>Self-Preservation</i> activates:
</p>
<ul><li><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span>, <i>Grunts of Pain</i> when injured, and <a href="https://deadbydaylight.fandom.com/wiki/Bleeding" class="mw-redirect" title="Bleeding">Bleeding</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bleeding" title="Bleeding"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/64?cb=20170620160528"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bleeding" title="Bleeding"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Bleeding" title="Bleeding"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/32?cb=20170620160528"></a></span></span></span> are suppressed for the next <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Something I learnt in the industry: when the axe is swinging, keep your head down." — Yun-Jin Lee</span></i>
</p>', 'Life is unforgiving.
The more confirmation you get of that, the more prepared you become.
Whenever another Survivor is hit with a Basic Attack or Special Attack within 16 metres of you, Self-Preservation activates:

Scratch Marks , Grunts of Pain when injured, and Bleeding are suppressed for the next 6 / 8 / 10 seconds.
"Something I learnt in the industry: when the axe is swinging, keep your head down." — Yun-Jin Lee', 'Yun-Jin_Lee');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Shoulder_the_Burden', 'survivor', 'Shoulder the Burden', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/3a/IconPerks_shoulderTheBurden.png/revision/latest?cb=20241107202157', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.4.0</div><div class="dynamicContent ptb">Born to be a disciple. Ready to submit to a greater cause. This is your calling.
<p>Once per Trial, and while you are not on <i>Death Hook</i>, press the <i>Active Ability button</i> while standing in front of a <i>Hooked Survivor</i> to unhook them and trigger the following effects:
</p><ul><li>Trade <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b> <i>Hook State</i> with the other Survivor to their benefit.</li>
<li>Causes you to scream.</li>
<li>Causes you to suffer from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest?cb=20170620155518" class="mw-file-description image"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.</li></ul>


<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"It''s not your time yet. Now go on!" — Taurie Cain</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.4.0 Born to be a disciple. Ready to submit to a greater cause. This is your calling.
Once per Trial, and while you are not on Death Hook, press the Active Ability button while standing in front of a Hooked Survivor to unhook them and trigger the following effects:
Trade 1 Hook State with the other Survivor to their benefit.
Causes you to scream.
Causes you to suffer from the Exposed Status Effect for 60 / 50 / 40 seconds.

"It''s not your time yet. Now go on!" — Taurie Cain', 'Taurie_Cain');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Slippery_Meat', 'survivor', 'Slippery Meat', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconPerks_slipperyMeat.png/revision/latest?cb=20201105152240', 'You have developed an efficient way to get off Hooks.
<ul><li><b>Increases</b> the number of available <i>Self-Unhook</i> attempts by <b><span class="luaClr clr clr2" style="color: #e8c252;">+3</span></b>.</li>
<li><b>Increases</b> the Odds of succeeding a <i>Self-Unhook</i> attempt by <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>%</b>.</li></ul>
<p><br>
</p>
', 'You have developed an efficient way to get off Hooks.
Increases the number of available Self-Unhook attempts by +3 .
Increases the Odds of succeeding a Self-Unhook attempt by 2 / 3 / 4 %.', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Small_Game', 'survivor', 'Small Game', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/dc/IconPerks_smallGame.png/revision/latest?cb=20210414100522', 'You have the undeniable capability to sense danger.
<ul><li>Receive an auditory warning upon looking in the direction of Totems in a <b><span class="luaClr clr clr2" style="color: #e8c252;">45 °</span></b> cone within <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">10</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">12</span></b> <b>metres</b>.</li></ul>
<p><i>Small Game</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">14</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b> each time it activates.
</p><p>For each Dull or Hex Totem cleansed by any Player, <i>Small Game</i> is automatically granted <b><span class="luaClr clr clr6" style="color: #ff8800;">1 Token</span></b>:
</p><ul><li>Each Token reduces the Detection cone''s angle by <b><span class="luaClr clr clr8" style="color: #d41c1c;">5 °</span></b>, down to a minimum of <b><span class="luaClr clr clr4" style="color: #ac3ee3;">20 °</span></b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Nope." — Andy, The Lost Tapes</span></i>
</p>', 'You have the undeniable capability to sense danger.
Receive an auditory warning upon looking in the direction of Totems in a 45 ° cone within 8 / 10 / 12 metres.
Small Game has a cool-down of 14 / 12 / 10 seconds each time it activates.
For each Dull or Hex Totem cleansed by any Player, Small Game is automatically granted 1 Token :
Each Token reduces the Detection cone''s angle by 5 ° , down to a minimum of 20 ° .
"Nope." — Andy, The Lost Tapes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Smash_Hit', 'survivor', 'Smash Hit', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconPerks_smashHit.png/revision/latest?cb=20210302172407', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">When your rival makes a mistake, you seize the opportunity.
<p>Stunning the Killer with a <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallet</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span> triggers <i>Smash Hit</i>:
</p><ul><li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">+50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr6" style="color: #ff8800;">4 seconds</span></b>.</li></ul>

<i>Smash Hit</i> causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b>.<br><i>Smash Hit</i> cannot be used when <i><b>Exhausted</b></i>.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I have dealt with psychopaths in suits. You''re just uglier and worse dressed." — Yun-Jin Lee</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 When your rival makes a mistake, you seize the opportunity.
Stunning the Killer with a Pallet triggers Smash Hit :
Grants a +50 % Haste Status Effect for 4 seconds .

Smash Hit causes the Exhausted Status Effect for 30 / 25 / 20 seconds. Smash Hit cannot be used when Exhausted .
"I have dealt with psychopaths in suits. You''re just uglier and worse dressed." — Yun-Jin Lee', 'Yun-Jin_Lee');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Sole_Survivor', 'survivor', 'Sole Survivor', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/8e/IconPerks_soleSurvivor.png/revision/latest?cb=20161023113045', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">As more of your friends fall to the Killer, you become shrouded in isolation and the Killer''s Aura-reading abilities towards you are disrupted.
<p>Each time a Survivor other than yourself is killed or sacrificed, <i>Sole Survivor</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr6" style="color: #ff8800;">3 Tokens</span></b>:
</p><ul><li>Grants a stack-able radius of <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">22</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">24</span></b> <b>metres</b> per Token around you, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">66</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">72</span></b> <b>metres</b>, within which you are immune to the Killer''s Aura-reading abilities.</li></ul>

When you are the <b><span class="luaClr clr clr2" style="color: #e8c252;">Last Survivor Standing</span></b>, you benefit from the following effects:
<ul><li><b>Increases</b> your Repair speed by <b><span class="luaClr clr clr8" style="color: #d41c1c;">+75&nbsp;%</span></b>.</li>
<li><b>Increases</b> your Gate and Hatch Opening speeds by <b><span class="luaClr clr clr4" style="color: #ac3ee3;">+50&nbsp;%</span></b>.</li></ul>

<b>Increases</b> your chance of becoming the initial  <i><b>Obsession</b></i> by increasing the default value by <b>+100&nbsp;%</b>.
<p><i>The Killer can only be <b>obsessed</b> with one Survivor at a time.</i>
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"It was the boogeyman." — Laurie Strode</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 As more of your friends fall to the Killer, you become shrouded in isolation and the Killer''s Aura-reading abilities towards you are disrupted.
Each time a Survivor other than yourself is killed or sacrificed, Sole Survivor gains 1 Token , up to a maximum of 3 Tokens :
Grants a stack-able radius of 20 / 22 / 24 metres per Token around you, up to a maximum of 60 / 66 / 72 metres, within which you are immune to the Killer''s Aura-reading abilities.

When you are the Last Survivor Standing , you benefit from the following effects:
Increases your Repair speed by +75 % .
Increases your Gate and Hatch Opening speeds by +50 % .

Increases your chance of becoming the initial Obsession by increasing the default value by +100 %.
The Killer can only be obsessed with one Survivor at a time.
"It was the boogeyman." — Laurie Strode', 'Laurie_Strode');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Solidarity', 'survivor', 'Solidarity', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconPerks_solidarity.png/revision/latest?cb=20190308175435', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">Sharing painful experiences has the power to heal.
<p>While injured and healing another Survivor without using a <a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" class="mw-redirect" title="Med-Kit">Med-Kit</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/64?cb=20240313184755"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/96?cb=20240313184755"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/32?cb=20240313184755"></a></span></span></span>, you benefit from the following effect:
</p><ul><li>Passively heal yourself at a rate of <b><span class="luaClr clr clr2" style="color: #e8c252;">50</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">60</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">70</span></b> <b>%</b> of your Altruistic Healing speed.</li></ul>


<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Showing up when things get rough, listening to people''s problems, and supporting those in need; that''s how you become stronger, that''s how you grow." — Jane Romero</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 Sharing painful experiences has the power to heal.
While injured and healing another Survivor without using a Med-Kit , you benefit from the following effect:
Passively heal yourself at a rate of 50 / 60 / 70 % of your Altruistic Healing speed.

"Showing up when things get rough, listening to people''s problems, and supporting those in need; that''s how you become stronger, that''s how you grow." — Jane Romero', 'Jane_Romero');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Soul_Guard', 'survivor', 'Soul Guard', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a5/IconPerks_soulGuard.png/revision/latest?cb=20200526201807', 'You have been through immense hardship and you''re stronger for it.
<p>After being healed from or having recovered from the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span>, you benefit from the following effect:
</p><ul><li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Endurance" class="mw-redirect" title="Endurance">Endurance</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/64?cb=20170620154928"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/96?cb=20170620154928"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/32?cb=20170620154928"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">6</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">8</span></b> <b>seconds</b>.
<ul><li><i><b>Endurance</b></i> is cancelled prematurely when performing a <i><a href="https://deadbydaylight.fandom.com/wiki/Conspicuous_Action" class="mw-redirect" title="Conspicuous Action">Conspicuous Action</a></i>.</li></ul></li></ul>

While suffering from the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Cursed" class="mw-redirect" title="Cursed">Cursed</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Cursed" title="Cursed"><img alt="IconStatusEffects cursed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects cursed.png" data-image-key="IconStatusEffects_cursed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/55/IconStatusEffects_cursed.png/revision/latest/scale-to-width-down/64?cb=20170620154519"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Cursed" title="Cursed"><img alt="IconStatusEffects cursed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects cursed.png" data-image-key="IconStatusEffects_cursed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/55/IconStatusEffects_cursed.png/revision/latest/scale-to-width-down/96?cb=20170620154519"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Cursed" title="Cursed"><img alt="IconStatusEffects cursed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects cursed.png" data-image-key="IconStatusEffects_cursed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/55/IconStatusEffects_cursed.png/revision/latest/scale-to-width-down/32?cb=20170620154519"></a></span></span></span></b></i> <b>Status Effect</b>, you benefit from the following effects:
<ul><li>Grants the ability to fully recover yourself from the Dying State.</li></ul>

<i>Soul Guard</i> has a cool-down of <b><span class="luaClr clr clr2" style="color: #e8c252;">30 seconds</span></b>.
', 'You have been through immense hardship and you''re stronger for it.
After being healed from or having recovered from the Dying State , you benefit from the following effect:
Grants the Endurance Status Effect for 4 / 6 / 8 seconds.
Endurance is cancelled prematurely when performing a Conspicuous Action .

While suffering from the Cursed Status Effect, you benefit from the following effects:
Grants the ability to fully recover yourself from the Dying State.

Soul Guard has a cool-down of 30 seconds .', 'Cheryl_Mason');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Specialist', 'survivor', 'Specialist', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ae/IconPerks_specialist.png/revision/latest?cb=20240625161548', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.1.0</div><div class="dynamicContent ptb">Adventure. Exploration. Excavation.<br>You are in your element.
<p>Whenever you unlock or rummage through a <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chest</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span>, <i>Specialist</i> gains <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr6" style="color: #ff8800;">6 Tokens</span></b>:
</p><ul><li>Succeeding a <i>Great Repair Skill Check</i> while repairing a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> consumes all Tokens.</li>
<li><b>Permanently reduces</b> the Repair Charges requirement of that <b>Generator</b> by <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>Charges</b> per Token, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">12</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">18</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">24</span></b> <b>Charges</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Well, then. Doesn''t this feel familiar?" — Lara Croft</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.1.0 Adventure. Exploration. Excavation. You are in your element.
Whenever you unlock or rummage through a Chest , Specialist gains +1 Token , up to a maximum of 6 Tokens :
Succeeding a Great Repair Skill Check while repairing a Generator consumes all Tokens.
Permanently reduces the Repair Charges requirement of that Generator by 2 / 3 / 4 Charges per Token, up to a maximum of 12 / 18 / 24 Charges.

"Well, then. Doesn''t this feel familiar?" — Lara Croft', 'Lara_Croft');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Spine_Chill', 'survivor', 'Spine Chill', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/57/IconPerks_spineChill.png/revision/latest?cb=20160605205147', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.1.0</div><div class="dynamicContent ptb">An unnatural tingle warns you of impending doom.
<p>Whenever the Killer is within <b><span class="luaClr clr clr2" style="color: #e8c252;">36 metres</span></b> of your location and looking at you with a clear <i>Line of Sight</i>, <i>Spine Chill</i> activates:
</p><ul><li>Warns of the Killer''s proximity and their potential awareness of your location by lighting its icon.</li>
<li><b>Increases</b> your Action speeds for Blessing, Cleansing, Gate-Opening, Healing, Repairing, Sabotaging, Unhooking, and Unlocking by <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>%</b>.
<ul><li>This effect lingers for <b><span class="luaClr clr clr6" style="color: #ff8800;">0.5 seconds</span></b> after the Killer loses <i>Line of Sight</i> or exits the Activation range.</li></ul></li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"There is a voice that doesn''t use words. Listen.." — Sassy, The Lost Tapes</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.1.0 An unnatural tingle warns you of impending doom.
Whenever the Killer is within 36 metres of your location and looking at you with a clear Line of Sight, Spine Chill activates:
Warns of the Killer''s proximity and their potential awareness of your location by lighting its icon.
Increases your Action speeds for Blessing, Cleansing, Gate-Opening, Healing, Repairing, Sabotaging, Unhooking, and Unlocking by 2 / 4 / 6 %.
This effect lingers for 0.5 seconds after the Killer loses Line of Sight or exits the Activation range.

"There is a voice that doesn''t use words. Listen.." — Sassy, The Lost Tapes', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Sprint_Burst', 'survivor', 'Sprint Burst', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e4/IconPerks_sprintBurst.png/revision/latest?cb=20160605205153', 'Starting to run triggers <i>Sprint Burst</i>:
<ul><li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">+50&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr6" style="color: #ff8800;">3 seconds</span></b>.</li></ul>
<p><i>Sprint Burst</i> causes the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/64?cb=20170620155334"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" title="Exhausted"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/32?cb=20170620155334"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">60</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">50</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">40</span></b> <b>seconds</b>.<br><i>Sprint Burst</i> cannot be used when <i><b>Exhausted</b></i>.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"See you if you can catch up..." — Meg Thomas</span></i>
</p>', 'Starting to run triggers Sprint Burst :
Grants a +50 % Haste Status Effect for 3 seconds .
Sprint Burst causes the Exhausted Status Effect for 60 / 50 / 40 seconds. Sprint Burst cannot be used when Exhausted .

"See you if you can catch up..." — Meg Thomas', 'Meg_Thomas');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Stake_Out', 'survivor', 'Stake Out', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cd/IconPerks_stakeOut.png/revision/latest?cb=20180123224338', 'Getting close to the Killer fills you with determination.<br>
<p>Every <b><span class="luaClr clr clr2" style="color: #e8c252;">15 seconds</span></b> you are within the Killer''s <a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius">Terror Radius</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="65" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="98" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest?cb=20201111225655"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Terror_Radius" title="Terror Radius"><img alt="IconHelp terrorRadius" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="33" class="mw-file-element lazyload" data-image-name="IconHelp terrorRadius.png" data-image-key="IconHelp_terrorRadius.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e0/IconHelp_terrorRadius.png/revision/latest/scale-to-width-down/32?cb=20201111225655"></a></span></span></span>, while not being chased, <i>Stake Out</i> gains <b><span class="luaClr clr clr6" style="color: #ff8800;">1 Token</span></b>, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">2</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">3</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>Tokens</b>.
</p>
<ul><li>When <i>Stake Out</i> has at least <b><span class="luaClr clr clr8" style="color: #d41c1c;">1 Token</span></b>, <a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" class="mw-redirect" title="Good Skill Check">Good Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" title="Good Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" title="Good Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Good_Skill_Check" title="Good Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> consume <b><span class="luaClr clr clr4" style="color: #ac3ee3;">1 Token</span></b> and are considered Great Skill Checks, granting an additional Progression bonus of <b><span class="luaClr clr clr3" style="color: #199b1e;">+1&nbsp;%</span></b>.</li>
<li>Great Skill Checks do not consume any Tokens.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I had you, I had you on your knees. You''re runnin'' scared because we had you. We''re gonna close this case!" — Detective David Tapp</span></i>
</p>', 'Getting close to the Killer fills you with determination.
Every 15 seconds you are within the Killer''s Terror Radius , while not being chased, Stake Out gains 1 Token , up to a maximum of 2 / 3 / 4 Tokens.

When Stake Out has at least 1 Token , Good Skill Checks consume 1 Token and are considered Great Skill Checks, granting an additional Progression bonus of +1 % .
Great Skill Checks do not consume any Tokens.
"I had you, I had you on your knees. You''re runnin'' scared because we had you. We''re gonna close this case!" — Detective David Tapp', 'David_Tapp');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Still_Sight', 'survivor', 'Still Sight', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b6/IconPerks_stillSight.png/revision/latest?cb=20240514174204', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.0.0</div><div class="dynamicContent ptb">A clear mind and calm temperament will always find the means of their escape.
<p>After standing still for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">4</span></b> <b>seconds</b>, <i>Still Sight</i> activates:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer as well as any <a href="https://deadbydaylight.fandom.com/wiki/Chest" class="mw-redirect" title="Chest">Chests</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/64?cb=20170907144102"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/96?cb=20170907144102"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Chest" title="Chest"><img alt="IconHelp chests" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp chests.png" data-image-key="IconHelp_chests.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/98/IconHelp_chests.png/revision/latest/scale-to-width-down/32?cb=20170907144102"></a></span></span></span> and <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> within <b><span class="luaClr clr clr2" style="color: #e8c252;">24 metres</span></b> of your location are revealed to you until you start moving again.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Breathe in. Breathe out. Now open your eyes." — Baermar</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.0.0 A clear mind and calm temperament will always find the means of their escape.
After standing still for 6 / 5 / 4 seconds, Still Sight activates:
The Auras of the Killer as well as any Chests and Generators within 24 metres of your location are revealed to you until you start moving again.

"Breathe in. Breathe out. Now open your eyes." — Baermar', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Streetwise', 'survivor', 'Streetwise', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/ff/IconPerks_streetwise.png/revision/latest?cb=20160821134155', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 3.0.0</div><div class="dynamicContent ptb">Long nights out taught you to do a lot with what you have got.
<ul><li><b>Increases</b> the Efficiency of your <a href="https://deadbydaylight.fandom.com/wiki/Item" class="mw-redirect" title="Item">Items</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/64?cb=20170907141319"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/96?cb=20170907141319"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Item" title="Item"><img alt="IconHelp items" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp items.png" data-image-key="IconHelp_items.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_items.png/revision/latest/scale-to-width-down/32?cb=20170907141319"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">15</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">20</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">25</span></b> <b>%</b>.</li></ul>
<p><i>Streetwise</i> extends its effect to all other <a href="https://deadbydaylight.fandom.com/wiki/Survivor" class="mw-redirect" title="Survivor">Survivors</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 5px"><span style="width:24px;max-height: 24px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/64?cb=20220324212914"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/96?cb=20220324212914"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Survivor" title="Survivor"><img alt="IconHelpLoading survivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="24" height="24" class="mw-file-element lazyload" data-image-name="IconHelpLoading survivor.png" data-image-key="IconHelpLoading_survivor.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b3/IconHelpLoading_survivor.png/revision/latest/scale-to-width-down/24?cb=20220324212914"></a></span></span></span> within <b><span class="luaClr clr clr2" style="color: #e8c252;">8 metres</span></b> of your location and lingers for <b><span class="luaClr clr clr6" style="color: #ff8800;">15 seconds</span></b>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You are doing it wrong! Let me show you how it is done." — Nea Karlsson</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 3.0.0 Long nights out taught you to do a lot with what you have got.
Increases the Efficiency of your Items by 15 / 20 / 25 %.
Streetwise extends its effect to all other Survivors within 8 metres of your location and lingers for 15 seconds .
"You are doing it wrong! Let me show you how it is done." — Nea Karlsson', 'Nea_Karlsson');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Strength_in_Shadows', 'survivor', 'Strength in Shadows', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e2/IconPerks_strengthInShadows.png/revision/latest?cb=20240220182529', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.6.0</div><div class="dynamicContent ptb">A chance for renewed power down where danger calls home.
<p>When you are in the <a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement">Basement</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/64?cb=20170907141327"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/96?cb=20170907141327"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/32?cb=20170907141327"></a></span></span></span>, <i>Strength in Shadows</i> activates:
</p><ul><li>Unlocks the <i>Strength in Shadows</i> ability, allowing you to self-heal without needing a <a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" class="mw-redirect" title="Med-Kit">Med-Kit</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/64?cb=20240313184755"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/96?cb=20240313184755"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Med-Kit" title="Med-Kit"><img alt="IconItems firstAidKit" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconItems firstAidKit.png" data-image-key="IconItems_firstAidKit.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7a/IconItems_firstAidKit.png/revision/latest/scale-to-width-down/32?cb=20240313184755"></a></span></span></span> at <b><span class="luaClr clr clr2" style="color: #e8c252;">70&nbsp;%</span></b> of the normal Healing speed.</li>
<li>Upon finishing a heal in the Basement, the <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I''m getting out of here, if it''s the last thing I do." — Sable</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.6.0 A chance for renewed power down where danger calls home.
When you are in the Basement , Strength in Shadows activates:
Unlocks the Strength in Shadows ability, allowing you to self-heal without needing a Med-Kit at 70 % of the normal Healing speed.
Upon finishing a heal in the Basement, the Aura of the Killer is revealed to you for 6 / 8 / 10 seconds.

"I''m getting out of here, if it''s the last thing I do." — Sable', 'Sable_Ward');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Teamwork:_Collective_Stealth', 'survivor', 'Teamwork: Collective Stealth', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a0/IconPerks_teamworkCollectiveStealth.png/revision/latest?cb=20230218135318', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">When someone helps you out, you respond in kind.
<p>Whenever another Survivor finishes healing you, <i>Teamwork: Collective Stealth</i> activates, and both you and the Survivor who healed you benefit from the following effect:
</p><ul><li><b>Suppresses</b> your <a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks">Scratch Marks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/64?cb=20190920181432"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/96?cb=20190920181432"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Scratch_Marks" title="Scratch Marks"><img alt="IconHelp scratchMarks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp scratchMarks.png" data-image-key="IconHelp_scratchMarks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/ad/IconHelp_scratchMarks.png/revision/latest/scale-to-width-down/32?cb=20190920181432"></a></span></span></span> for as long as you stay within <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>metres</b> of one another.
<ul><li>This effect lingers for <b><span class="luaClr clr clr2" style="color: #e8c252;">4 seconds</span></b> once out of range and resumes upon re-entering it before that timer elapses.</li></ul></li></ul>

Survivors can only be affected by one instance of <i>Teamwork: Collective Stealth</i> at a time.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I''m good, I''m good... but keep it down." — Renato Lyra</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 When someone helps you out, you respond in kind.
Whenever another Survivor finishes healing you, Teamwork: Collective Stealth activates, and both you and the Survivor who healed you benefit from the following effect:
Suppresses your Scratch Marks for as long as you stay within 8 / 12 / 16 metres of one another.
This effect lingers for 4 seconds once out of range and resumes upon re-entering it before that timer elapses.

Survivors can only be affected by one instance of Teamwork: Collective Stealth at a time.
"I''m good, I''m good... but keep it down." — Renato Lyra', 'Renato_Lyra');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Teamwork:_Power_of_Two', 'survivor', 'Teamwork: Power of Two', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/2b/IconPerks_teamworkPowerOfTwo.png/revision/latest?cb=20230218135319', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.0</div><div class="dynamicContent ptb">It is hard to keep up with you, but it does not stop people from trying.
<p>Whenever you finish healing another Survivor, <i>Teamwork: Power of Two</i> activates, and both you and the healed Survivor benefit from the following effect:
</p><ul><li>Grants a <b><span class="luaClr clr clr2" style="color: #e8c252;">+5&nbsp;%</span></b> <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haste" class="mw-redirect" title="Haste">Haste</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/64?cb=20170620160501"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/96?cb=20170620160501"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Haste" title="Haste"><img alt="IconStatusEffects haste" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects haste.png" data-image-key="IconStatusEffects_haste.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/e7/IconStatusEffects_haste.png/revision/latest/scale-to-width-down/32?cb=20170620160501"></a></span></span></span></b></i> <b>Status Effect</b> for as long as you stay within <b><span class="luaClr clr clr2" style="color: #e8c252;">8</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">12</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>metres</b> of one another.
<ul><li>This effect lingers for <b><span class="luaClr clr clr6" style="color: #ff8800;">4 seconds</span></b> once out of range and resumes upon re-entering it before that timer elapses.</li></ul></li></ul>

Survivors can only be affected by one instance of <i>Teamwork: Power of Two</i> at a time.
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"You good? Then keep up!" — Thalita Lyra</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.0 It is hard to keep up with you, but it does not stop people from trying.
Whenever you finish healing another Survivor, Teamwork: Power of Two activates, and both you and the healed Survivor benefit from the following effect:
Grants a +5 % Haste Status Effect for as long as you stay within 8 / 12 / 16 metres of one another.
This effect lingers for 4 seconds once out of range and resumes upon re-entering it before that timer elapses.

Survivors can only be affected by one instance of Teamwork: Power of Two at a time.
"You good? Then keep up!" — Thalita Lyra', 'Thalita_Lyra');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Technician', 'survivor', 'Technician', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/62/IconPerks_technician.png/revision/latest?cb=20170511153221', 'You are apt at handling machinery with the greatest care and precision.
<p>When repairing a <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span>, the following effects apply:
</p><ul><li><b>Reduces</b> the audible range of your Repair noises by <b><span class="luaClr clr clr2" style="color: #e8c252;">-8 metres</span></b>.</li>
<li><b>Suppresses</b> the explosion and accompanying <i><a href="https://deadbydaylight.fandom.com/wiki/Loud_Noise_Notification" class="mw-redirect" title="Loud Noise Notification">Loud Noise Notification</a></i> when failing a <a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" class="mw-redirect" title="Skill Check">Skill Check</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Skill_Check" title="Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span>.</li>
<li>Failing a Skill Check <b>instantly regresses</b> the Generator by <b><span class="luaClr clr clr2" style="color: #e8c252;">5</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">4</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b> <b>%</b> of its maximum possible Progression in addition to the default Progression penalty.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I am gonna stealth this one." — Feng Min</span></i>
', 'You are apt at handling machinery with the greatest care and precision.
When repairing a Generator , the following effects apply:
Reduces the audible range of your Repair noises by -8 metres .
Suppresses the explosion and accompanying Loud Noise Notification when failing a Skill Check .
Failing a Skill Check instantly regresses the Generator by 5 / 4 / 3 % of its maximum possible Progression in addition to the default Progression penalty.

"I am gonna stealth this one." — Feng Min', 'Feng_Min');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Tenacity', 'survivor', 'Tenacity', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9d/IconPerks_tenacity.png/revision/latest?cb=20180123224404', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 6.1.0</div><div class="dynamicContent ptb">There is nothing stopping you.
<p>Your ferocious tenacity in dire situations allow you to benefit from the following effects:
</p><ul><li><b>Increases</b> your Crawling speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">40</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">50</span></b> <b>%</b>.</li>
<li>Grants the ability to crawl and recover at the same time.</li>
<li><b>Reduces</b> the volume of <i>Grunts of Pain</i> while in the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span> by <b><span class="luaClr clr clr2" style="color: #e8c252;">-75&nbsp;%</span></b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"What the hell is this? I''m taking this bastard down!" — Detective David Tapp</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 6.1.0 There is nothing stopping you.
Your ferocious tenacity in dire situations allow you to benefit from the following effects:
Increases your Crawling speed by 30 / 40 / 50 %.
Grants the ability to crawl and recover at the same time.
Reduces the volume of Grunts of Pain while in the Dying State by -75 % .
"What the hell is this? I''m taking this bastard down!" — Detective David Tapp', 'David_Tapp');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('This_Is_Not_Happening', 'survivor', 'This Is Not Happening', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/58/IconPerks_thisIsNotHappening.png/revision/latest?cb=20160605205158', 'You perform at your best when you are under extreme stress.
<ul><li><b>Increases</b> the Success zone of <a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" class="mw-redirect" title="Great Skill Check">Great Skill Checks</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" title="Great Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/64?cb=20170907140812"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" title="Great Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/96?cb=20170907140812"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Great_Skill_Check" title="Great Skill Check"><img alt="IconHelp skillChecks" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp skillChecks.png" data-image-key="IconHelp_skillChecks.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/cc/IconHelp_skillChecks.png/revision/latest/scale-to-width-down/32?cb=20170907140812"></a></span></span></span> while Repairing and Healing by <b><span class="luaClr clr clr2" style="color: #e8c252;">10</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">20</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b> when in the <a href="https://deadbydaylight.fandom.com/wiki/Injured_State" class="mw-redirect" title="Injured State">Injured State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/64?cb=20170907144639"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/96?cb=20170907144639"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Injured_State" title="Injured State"><img alt="IconHelp injured" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp injured.png" data-image-key="IconHelp_injured.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/93/IconHelp_injured.png/revision/latest/scale-to-width-down/32?cb=20170907144639"></a></span></span></span>.</li></ul>
', 'You perform at your best when you are under extreme stress.
Increases the Success zone of Great Skill Checks while Repairing and Healing by 10 / 20 / 30 % when in the Injured State .', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Troubleshooter', 'survivor', 'Troubleshooter', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/0d/IconPerks_troubleshooter.png/revision/latest?cb=20230524205359', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.0.0</div><div class="dynamicContent ptb">No amount of distraction will shake you from your primary task.
<p>When you are chased by the Killer, <i>Troubleshooter</i> activates:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generator</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> with the most progress is revealed to you.</li>
<li>The Aura of the Killer is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">4</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">5</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">6</span></b> <b>seconds</b> after dropping a <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallet</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span>.</li></ul>


<p>These effects linger for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b> after ending the Chase, after which <i>Troubleshooter</i> deactivates.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Nothing gets done around here if I don''t do it." — Gabriel Soma</span></i></p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.0.0 No amount of distraction will shake you from your primary task.
When you are chased by the Killer, Troubleshooter activates:
The Aura of the Generator with the most progress is revealed to you.
The Aura of the Killer is revealed to you for 4 / 5 / 6 seconds after dropping a Pallet .

These effects linger for 6 / 8 / 10 seconds after ending the Chase, after which Troubleshooter deactivates.
"Nothing gets done around here if I don''t do it." — Gabriel Soma', 'Gabriel_Soma');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Unbreakable', 'survivor', 'Unbreakable', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/4a/IconPerks_unbreakable.png/revision/latest?cb=20170308184922', 'Past battles have taught you a thing or two about survival.<br>
<p>Once per Trial, you can completely recover from the <a href="https://deadbydaylight.fandom.com/wiki/Dying_State" class="mw-redirect" title="Dying State">Dying State</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/64?cb=20170907144448"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/96?cb=20170907144448"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Dying_State" title="Dying State"><img alt="IconHelp dying" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp dying.png" data-image-key="IconHelp_dying.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9a/IconHelp_dying.png/revision/latest/scale-to-width-down/32?cb=20170907144448"></a></span></span></span>.
</p>
<ul><li>Your Recovery speed is increased by <b><span class="luaClr clr clr2" style="color: #e8c252;">25</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">30</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">35</span></b> <b>%</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Goddammit, I am seriously FUBAR!" — Bill Overbeck</span></i>
</p>', 'Past battles have taught you a thing or two about survival.
Once per Trial, you can completely recover from the Dying State .

Your Recovery speed is increased by 25 / 30 / 35 %.
"Goddammit, I am seriously FUBAR!" — Bill Overbeck', 'Bill_Overbeck');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Up_the_Ante', 'survivor', 'Up the Ante', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a3/IconPerks_upTheAnte.png/revision/latest?cb=20161210091356', 'All will be well in the end; you just know it.<br>Your confidence strengthens the feeling of hope for those around you.
<p>For every Survivor still in the Trial, <i>Up the Ante</i> is granted <b><span class="luaClr clr clr2" style="color: #e8c252;">+1 Token</span></b>:
</p><ul><li><b>Increases</b> the Odds of every Survivor succeeding a <i>Self-Unhook</i> attempt by a stack-able <b><span class="luaClr clr clr2" style="color: #e8c252;">1</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">2</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">3</span></b> <b>%</b> per Token, up to a maximum of <b><span class="luaClr clr clr2" style="color: #e8c252;">3</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">6</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">9</span></b> <b>%</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"What can I say? I''m just a very lucky guy... I''m sure some of it will rub off on you." — Ace Visconti</span></i>
', 'All will be well in the end; you just know it. Your confidence strengthens the feeling of hope for those around you.
For every Survivor still in the Trial, Up the Ante is granted +1 Token :
Increases the Odds of every Survivor succeeding a Self-Unhook attempt by a stack-able 1 / 2 / 3 % per Token, up to a maximum of 3 / 6 / 9 %.

"What can I say? I''m just a very lucky guy... I''m sure some of it will rub off on you." — Ace Visconti', 'Ace_Visconti');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Urban_Evasion', 'survivor', 'Urban Evasion', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c7/IconPerks_urbanEvasion.png/revision/latest?cb=20160821134257', 'Years of evading the cops taught you a thing or two about stealth.
<ul><li><b>Increases</b> your Crouching Movement speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">90</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">95</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">100</span></b> <b>%</b>.</li></ul>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"The paint is still fresh but I am long gone." — Nea Karlsson</span></i>
</p>', 'Years of evading the cops taught you a thing or two about stealth.
Increases your Crouching Movement speed by 90 / 95 / 100 %.
"The paint is still fresh but I am long gone." — Nea Karlsson', 'Nea_Karlsson');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Vigil', 'survivor', 'Vigil', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/4/46/IconPerks_vigil.png/revision/latest?cb=20171026230511', 'You look over your friends even in dire situations.
<ul><li><b>Increases</b> the Recovery rate from the following <b>Status Effects</b> by <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">25</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">30</span></b> <b>%</b>:
<ul><li>The <i><b><a href="https://deadbydaylight.fandom.com/wiki/Blindness" class="mw-redirect" title="Blindness">Blindness</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest?cb=20170620153742" class="mw-file-description image"><img alt="IconStatusEffects vision" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects vision.png" data-image-key="IconStatusEffects_vision.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/a/a9/IconStatusEffects_vision.png/revision/latest/scale-to-width-down/96?cb=20170620153742"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span>, <i><b><a href="https://deadbydaylight.fandom.com/wiki/Broken" class="mw-redirect" title="Broken">Broken</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest?cb=20180829073317" class="mw-file-description image"><img alt="IconStatusEffects broken" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects broken.png" data-image-key="IconStatusEffects_broken.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/14/IconStatusEffects_broken.png/revision/latest/scale-to-width-down/96?cb=20180829073317"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span>, <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exhausted" class="mw-redirect" title="Exhausted">Exhausted</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest?cb=20170620155334" class="mw-file-description image"><img alt="IconStatusEffects exhausted" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exhausted.png" data-image-key="IconStatusEffects_exhausted.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/e/ef/IconStatusEffects_exhausted.png/revision/latest/scale-to-width-down/96?cb=20170620155334"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span>, <i><b><a href="https://deadbydaylight.fandom.com/wiki/Exposed" class="mw-redirect" title="Exposed">Exposed</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest?cb=20170620155518" class="mw-file-description image"><img alt="IconStatusEffects exposed" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects exposed.png" data-image-key="IconStatusEffects_exposed.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/9e/IconStatusEffects_exposed.png/revision/latest/scale-to-width-down/96?cb=20170620155518"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span>, <i><b><a href="https://deadbydaylight.fandom.com/wiki/Haemorrhage" class="mw-redirect" title="Haemorrhage">Haemorrhage</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest?cb=20170620160528" class="mw-file-description image"><img alt="IconStatusEffects bleeding" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects bleeding.png" data-image-key="IconStatusEffects_bleeding.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/24/IconStatusEffects_bleeding.png/revision/latest/scale-to-width-down/96?cb=20170620160528"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span>, <i><b><a href="https://deadbydaylight.fandom.com/wiki/Hindered" class="mw-redirect" title="Hindered">Hindered</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest?cb=20201201161431" class="mw-file-description image"><img alt="IconStatusEffects hindered" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects hindered.png" data-image-key="IconStatusEffects_hindered.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/3/37/IconStatusEffects_hindered.png/revision/latest/scale-to-width-down/96?cb=20201201161431"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span>, <i><b><a href="https://deadbydaylight.fandom.com/wiki/Mangled" class="mw-redirect" title="Mangled">Mangled</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7f/IconStatusEffects_mangled.png/revision/latest?cb=20170620162001" class="mw-file-description image"><img alt="IconStatusEffects mangled" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects mangled.png" data-image-key="IconStatusEffects_mangled.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7f/IconStatusEffects_mangled.png/revision/latest/scale-to-width-down/96?cb=20170620162001"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span>,  and <i><b><a href="https://deadbydaylight.fandom.com/wiki/Oblivious" class="mw-redirect" title="Oblivious">Oblivious</a></b></i><span class="iconLink debuff effect-wrapper" style="--status-effect-main-size: 48px;"><span class="effect-tier effect-tier-1"></span><span class="effect-icon" style="scale: 0.57;"><span class="getIconShrinker" style="--imageShrinkerSize: 48px"><span typeof="mw:File"><a href="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest?cb=20190903170245" class="mw-file-description image"><img alt="IconStatusEffects oblivious" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects oblivious.png" data-image-key="IconStatusEffects_oblivious.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f7/IconStatusEffects_oblivious.png/revision/latest/scale-to-width-down/96?cb=20190903170245"></a></span></span></span><span class="effect-foreground-wrapper" style="display: none"><span class="effect-foreground"></span></span><span class="effect-background"></span></span> <b>Status Effects</b>.</li></ul></li></ul>
<p><i>Vigil</i> extends its effect to all Survivors within <b><span class="luaClr clr clr2" style="color: #e8c252;">8 metres</span></b> of your location and lingers for <b><span class="luaClr clr clr6" style="color: #ff8800;">15 seconds</span></b>.
</p>
<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"I am gonna be here when you wake up. You are gonna make it." — Quentin Smith</span></i>
</p>', 'You look over your friends even in dire situations.
Increases the Recovery rate from the following Status Effects by 20 / 25 / 30 % :
The Blindness , Broken , Exhausted , Exposed , Haemorrhage , Hindered , Mangled ,  and Oblivious Status Effects.
Vigil extends its effect to all Survivors within 8 metres of your location and lingers for 15 seconds .

"I am gonna be here when you wake up. You are gonna make it." — Quentin Smith', 'Quentin_Smith');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Visionary', 'survivor', 'Visionary', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/7c/IconPerks_visionary.png/revision/latest?cb=20200819113857', 'You are remarkably focused on your means of escape.
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> are revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">32 metres</span></b>.</li>
<li>Each time a Generator is completed, <i>Visionary</i> is deactivated for <b><span class="luaClr clr clr2" style="color: #e8c252;">20</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">18</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">16</span></b> <b>seconds</b>.</li></ul>
', 'You are remarkably focused on your means of escape.
The Auras of Generators are revealed to you within 32 metres .
Each time a Generator is completed, Visionary is deactivated for 20 / 18 / 16 seconds.', 'Felix_Richter');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Wake_Up!', 'survivor', 'Wake Up!', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/fd/IconPerks_wakeUp.png/revision/latest?cb=20171026230520', 'Unlocks potential in your Aura-reading ability.
<p>Once all <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> are completed, <i>Wake Up!</i> activates:
</p><ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" class="mw-redirect" title="Exit Gate Switch">Exit Gate Switches</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" title="Exit Gate Switch"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" title="Exit Gate Switch"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate_Switch" title="Exit Gate Switch"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span> are revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">128 metres</span></b>.</li>
<li>Your Aura is revealed to all other Survivors within <b><span class="luaClr clr clr6" style="color: #ff8800;">128 metres</span></b> of your location while opening an <a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" class="mw-redirect" title="Exit Gate">Exit Gate</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/64?cb=20170907140953"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/96?cb=20170907140953"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Exit_Gate" title="Exit Gate"><img alt="IconHelp exitGates" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp exitGates.png" data-image-key="IconHelp_exitGates.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/f/f0/IconHelp_exitGates.png/revision/latest/scale-to-width-down/32?cb=20170907140953"></a></span></span></span>.</li>
<li><b>Increases</b> your Gate-Opening speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">15</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">20</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">25</span></b> <b>%</b>.</li></ul>


<p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Ok, look. If we survive the next 24 hours, then I''ll take you out on a real date." — Quentin Smith</span></i>
</p>', 'Unlocks potential in your Aura-reading ability.
Once all Generators are completed, Wake Up! activates:
The Auras of the Exit Gate Switches are revealed to you within 128 metres .
Your Aura is revealed to all other Survivors within 128 metres of your location while opening an Exit Gate .
Increases your Gate-Opening speed by 15 / 20 / 25 %.

"Ok, look. If we survive the next 24 hours, then I''ll take you out on a real date." — Quentin Smith', 'Quentin_Smith');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('We%27ll_Make_It', 'survivor', 'We''ll Make It', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/8a/IconPerks_wellMakeIt.png/revision/latest?cb=20160605205228', 'Helping others heightens your morale.
<p>After unhooking another Survivor, <i>We''ll Make It</i> activates:
</p><ul><li><b>Increases</b> your Altruistic Healing speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">+100&nbsp;%</span></b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">30</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">60</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">90</span></b> <b>seconds</b>.</li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I am confident we can all escape in one piece if we help each other."</span></i>
', 'Helping others heightens your morale.
After unhooking another Survivor, We''ll Make It activates:
Increases your Altruistic Healing speed by +100 % for 30 / 60 / 90 seconds.

"I am confident we can all escape in one piece if we help each other."', NULL);
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('We%27re_Gonna_Live_Forever', 'survivor', 'We''re Gonna Live Forever', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/b/b8/IconPerks_wereGonnaLiveForever.png/revision/latest?cb=20170727160948', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.3.2</div><div class="dynamicContent ptb">Your few friends deserve the best protection.
<p>You benefit from the following effect when healing a dying Survivor:
</p><ul><li><b>Increases</b> your Healing speed by <b><span class="luaClr clr clr2" style="color: #e8c252;">+100&nbsp;%</span></b>.</li></ul>

Any dying Survivor you heal back to the Injured State benefits from the following effect:
<ul><li>Grants the <i><b><a href="https://deadbydaylight.fandom.com/wiki/Endurance" class="mw-redirect" title="Endurance">Endurance</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/64?cb=20170620154928"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/96?cb=20170620154928"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Endurance" title="Endurance"><img alt="IconStatusEffects enduranceSurvivor" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconStatusEffects enduranceSurvivor.png" data-image-key="IconStatusEffects_enduranceSurvivor.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/6/69/IconStatusEffects_enduranceSurvivor.png/revision/latest/scale-to-width-down/32?cb=20170620154928"></a></span></span></span></b></i> <b>Status Effect</b> for <b><span class="luaClr clr clr2" style="color: #e8c252;">6</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">8</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">10</span></b> <b>seconds</b>.
<ul><li>This effect can only be triggered once every <b><span class="luaClr clr clr6" style="color: #ff8800;">30 seconds</span></b>.</li></ul></li></ul>

<i><span class="luaClr clr clr9" style="color: #e7cda2;">"Come on then, let''s ave'' it! I don''t give a shit pal." — David King</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.3.2 Your few friends deserve the best protection.
You benefit from the following effect when healing a dying Survivor:
Increases your Healing speed by +100 % .

Any dying Survivor you heal back to the Injured State benefits from the following effect:
Grants the Endurance Status Effect for 6 / 8 / 10 seconds.
This effect can only be triggered once every 30 seconds .

"Come on then, let''s ave'' it! I don''t give a shit pal." — David King', 'David_King');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Wicked', 'survivor', 'Wicked', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/8/8f/IconPerks_wicked.png/revision/latest?cb=20240220182530', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 7.6.0</div><div class="dynamicContent ptb">They can try to hurt you.<br>But you''re not going down so easily.
<ul><li>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Aura</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of the Killer is revealed to you for <b><span class="luaClr clr clr2" style="color: #e8c252;">16</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">18</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">20</span></b> <b>seconds</b> after unhooking yourself or being unhooked.</li>
<li>Grants the ability to perform a successful <i>Self-Unhook</i> at any point during the first <i>Hook Stage</i>, if you are hooked in the <a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement">Basement</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/64?cb=20170907141327"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/96?cb=20170907141327"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Basement" title="Basement"><img alt="IconHelp basement" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp basement.png" data-image-key="IconHelp_basement.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/7/78/IconHelp_basement.png/revision/latest/scale-to-width-down/32?cb=20170907141327"></a></span></span></span>.
<ul><li>This effect cannot be triggered during the second <i>Hook Stage</i> or if you are hooked as the <b><span class="luaClr clr clr2" style="color: #e8c252;">Last Survivor Standing</span></b>.</li></ul></li></ul>
<i><span class="luaClr clr clr9" style="color: #e7cda2;">"I haven''t let anyone get in my way before. You think I''m gonna start now?" — Sable</span></i></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 7.6.0 They can try to hurt you. But you''re not going down so easily.
The Aura of the Killer is revealed to you for 16 / 18 / 20 seconds after unhooking yourself or being unhooked.
Grants the ability to perform a successful Self-Unhook at any point during the first Hook Stage, if you are hooked in the Basement .
This effect cannot be triggered during the second Hook Stage or if you are hooked as the Last Survivor Standing .
"I haven''t let anyone get in my way before. You think I''m gonna start now?" — Sable', 'Sable_Ward');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Windows_of_Opportunity', 'survivor', 'Windows of Opportunity', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/1/17/IconPerks_windowsOfOpportunity.png/revision/latest?cb=20180529195008', 'Unlocks potential in your Aura-reading ability.
<p>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" class="mw-redirect" title="Breakable Wall">Breakable Walls</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/64?cb=20220910215339"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/96?cb=20220910215339"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Breakable_Wall" title="Breakable Wall"><img alt="IconHelp breakableWall" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp breakableWall.png" data-image-key="IconHelp_breakableWall.png" data-relevant="1" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/9/95/IconHelp_breakableWall.png/revision/latest/scale-to-width-down/32?cb=20220910215339"></a></span></span></span>, <a href="https://deadbydaylight.fandom.com/wiki/Pallet" class="mw-redirect" title="Pallet">Pallets</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="49" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/64?cb=20170907174500"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="74" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/96?cb=20170907174500"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Pallet" title="Pallet"><img alt="IconHelp pullDown" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="25" class="mw-file-element lazyload" data-image-name="IconHelp pullDown.png" data-image-key="IconHelp_pullDown.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/d/d8/IconHelp_pullDown.png/revision/latest/scale-to-width-down/32?cb=20170907174500"></a></span></span></span>, and <a href="https://deadbydaylight.fandom.com/wiki/Window" class="mw-redirect" title="Window">Windows</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="57" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/64?cb=20170921093258"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="85" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/96?cb=20170921093258"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Window" title="Window"><img alt="IconHelp window" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="28" class="mw-file-element lazyload" data-image-name="IconHelp window.png" data-image-key="IconHelp_window.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/5/5a/IconHelp_window.png/revision/latest/scale-to-width-down/32?cb=20170921093258"></a></span></span></span> are revealed to you within <b><span class="luaClr clr clr2" style="color: #e8c252;">24</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">28</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">32</span></b> <b>metres</b>.
</p><p><i><span class="luaClr clr clr9" style="color: #e7cda2;">"Rise and shine, work hard, carve out your name,<br>Take aim, pull the trigger, hit the bulls eye for fame,<br>Know the value of faith, an'' family, and don''t you complain,<br>Open wide, your windows of opportunity" — Kate Denson''s "Windows of Opportunity"</span></i>
</p>', 'Unlocks potential in your Aura-reading ability.
The Auras of Breakable Walls , Pallets , and Windows are revealed to you within 24 / 28 / 32 metres.
"Rise and shine, work hard, carve out your name, Take aim, pull the trigger, hit the bulls eye for fame, Know the value of faith, an'' family, and don''t you complain, Open wide, your windows of opportunity" — Kate Denson''s "Windows of Opportunity"', 'Kate_Denson');
INSERT INTO Perks (id, type, name, icon_url, content_html, content_text, character_id) VALUES ('Wiretap', 'survivor', 'Wiretap', 'https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/2/23/IconPerks_wiretap.png/revision/latest?cb=20220815051906', '<div class="dynamicBox ptb"><div class="dynamicTitle ptb">This description is based on the changes announced for or featured in the upcoming Patch 8.2.0</div><div class="dynamicContent ptb">You know that the best way to stay one step ahead is to keep tabs on the competition.
<p>After repairing <a href="https://deadbydaylight.fandom.com/wiki/Generator" class="mw-redirect" title="Generator">Generators</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/64?cb=20170625095337"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/96?cb=20170625095337"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Generator" title="Generator"><img alt="IconHelpLoading generators" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelpLoading generators.png" data-image-key="IconHelpLoading_generators.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/c/c4/IconHelpLoading_generators.png/revision/latest/scale-to-width-down/32?cb=20170625095337"></a></span></span></span> for a total of <b><span class="luaClr clr clr2" style="color: #e8c252;">40&nbsp;%</span></b>, <i>Wiretap</i> activates:
</p><ul><li>Press the <i>Active Ability button</i> while near a partially progressed <b>Generator</b> to install a <i>Trap</i>, which stays active for <b><span class="luaClr clr clr2" style="color: #e8c252;">100</span></b>/<b><span class="luaClr clr clr3" style="color: #199b1e;">110</span></b>/<b><span class="luaClr clr clr4" style="color: #ac3ee3;">120</span></b> <b>seconds</b>.</li>
<li>Whenever the Killer comes within <b><span class="luaClr clr clr6" style="color: #ff8800;">14 metres</span></b> of the <i>Trapped Generator</i> their Aura is revealed to all Survivors.</li></ul>

<i>Wiretap</i> deactivates after the <b>Generator</b> is damaged or once the timer runs out.
<p>The <a href="https://deadbydaylight.fandom.com/wiki/Aura" class="mw-redirect" title="Aura">Auras</a><span class="iconLink" style="vertical-align: middle; padding: 0 0 0 0"><span style="width:32px;max-height: 32px" class="pcView pcIconLink"><span class="tooltip linkIncluded borderless"><span class="tooltipBaseText iconless"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="64" height="64" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/64?cb=20170907143115"></a></span></span><span class="tooltiptext flex flexCenter" style="width: 240px;"><span class="tooltipTextWrapper"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="96" height="96" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/96?cb=20170907143115"></a></span></span></span></span></span><span class="mobileView mobileIconLink"><span typeof="mw:File"><a href="https://deadbydaylight.fandom.com/wiki/Aura" title="Aura"><img alt="IconHelp auras" src="data:image/gif;base64,R0lGODlhAQABAIABAAAAAP///yH5BAEAAAEALAAAAAABAAEAQAICTAEAOw%3D%3D" decoding="async" loading="lazy" width="32" height="32" class="mw-file-element lazyload" data-image-name="IconHelp auras.png" data-image-key="IconHelp_auras.png" data-relevant="0" data-src="https://static.wikia.nocookie.net/deadbydaylight_gamepedia_en/images/0/03/IconHelp_auras.png/revision/latest/scale-to-width-down/32?cb=20170907143115"></a></span></span></span> of <i>Trapped Generators</i> are revealed to all Survivors in <b><span class="luaClr clr clr2" style="color: #e8c252;">yellow</span></b>.</p></div></div>
', 'This description is based on the changes announced for or featured in the upcoming Patch 8.2.0 You know that the best way to stay one step ahead is to keep tabs on the competition.
After repairing Generators for a total of 40 % , Wiretap activates:
Press the Active Ability button while near a partially progressed Generator to install a Trap, which stays active for 100 / 110 / 120 seconds.
Whenever the Killer comes within 14 metres of the Trapped Generator their Aura is revealed to all Survivors.

Wiretap deactivates after the Generator is damaged or once the timer runs out.
The Auras of Trapped Generators are revealed to all Survivors in yellow .', 'Ada_Wong');
